let leaflet = null;
let leafletPromise = null;
async function loadLeaflet() {
  if (!leafletPromise) {
    leafletPromise = Promise.all([
      import('leaflet'),
      import('leaflet/dist/leaflet.css'),
    ]).then(([module]) => {
      leaflet = module.default || module;
      return leaflet;
    });
  }
  return leafletPromise;
}

