const app = document.getElementById('app');
let supabaseClientCache = null;
let addressSuggestionRequestSeq = 0;
let pipeDrag = null;
let locationPickerMap = null;
let locationPickerMarker = null;
// init() is invoked at the very end of this module (see bottom of file) so that
// all top-level const declarations (e.g. WB_WS_ICONS/WB_PALETTE used by the
// workspace builder during startup data seeding) are initialized first.

// --- @mention typeahead for the feed composer ---------------------------------
// When the user types "@" in the composer, suggest workspace members (injected in
// the ROM embed via __ROM_WS_MEMBERS__). Selecting one inserts "@Full Name " and
// wbFeedText() highlights it on the posted card. Self-contained: document-level
// listeners + a floating popover, so it survives the app's frequent re-renders.
const MENTION_SEL = '[data-wb-compose-text]';
let mentionPop = null;
let mentionState = null; // { textarea, at, items, index }

function mentionMemberList() {
  try { const list = wbMembers(activeCompanyId()); if (Array.isArray(list) && list.length) return list; } catch { /* ignore */ }
  const rom = window.__ROM_WS_MEMBERS__;
  return Array.isArray(rom) ? rom.map((m) => ({ id: m.id, name: m.name || m.email || 'Member', color: m.color, avatar_url: m.avatar_url })) : [];
}
function closeMentionPop() {
  if (mentionPop) { mentionPop.remove(); mentionPop = null; }
  mentionState = null;
}
function mentionTokenAt(textarea) {
  const caret = textarea.selectionStart;
  if (caret == null || caret !== textarea.selectionEnd) return null;
  const m = textarea.value.slice(0, caret).match(/(?:^|\s)@([^@\n]{0,30})$/);
  return m ? { query: m[1], at: caret - m[1].length - 1 } : null;
}
function drawMentionPop() {
  if (!mentionPop || !mentionState) return;
  mentionPop.innerHTML = mentionState.items.map((m, i) => {
    const color = m.color || wbColorFor(m.id || m.name || '');
    const av = m.avatar_url
      ? `<span class="wb-mention-av has-image"><img src="${h(m.avatar_url)}" alt=""></span>`
      : `<span class="wb-mention-av" style="background:${h(color)}">${h(wbInitials(m.name || ''))}</span>`;
    return `<button type="button" class="wb-mention-item ${i === mentionState.index ? 'active' : ''}" data-mention-index="${i}">${av}<span class="wb-mention-name">${h(m.name)}</span></button>`;
  }).join('');
}
function positionMentionPop(textarea) {
  if (!mentionPop) return;
  const r = textarea.getBoundingClientRect();
  mentionPop.style.position = 'fixed';
  mentionPop.style.left = `${Math.max(8, r.left)}px`;
  mentionPop.style.top = `${Math.min(r.bottom + 4, window.innerHeight - 8)}px`;
  mentionPop.style.minWidth = `${Math.min(280, Math.max(200, r.width))}px`;
  mentionPop.style.zIndex = '9999';
}
function showMentionPop(textarea, token) {
  const q = token.query.trim().toLowerCase();
  const items = (q ? mentionMemberList().filter((m) => (m.name || '').toLowerCase().includes(q)) : mentionMemberList()).slice(0, 6);
  if (!items.length) { closeMentionPop(); return; }
  if (!mentionPop) { mentionPop = document.createElement('div'); mentionPop.className = 'wb-mention-pop'; document.body.appendChild(mentionPop); }
  mentionState = { textarea, at: token.at, items, index: 0 };
  drawMentionPop();
  positionMentionPop(textarea);
}
function applyMention(i) {
  if (!mentionState) return;
  const { textarea, at, items } = mentionState;
  const pick = items[i]; if (!pick) return;
  const caret = textarea.selectionStart;
  const insert = `@${pick.name} `;
  textarea.value = textarea.value.slice(0, at) + insert + textarea.value.slice(caret);
  const pos = at + insert.length;
  textarea.focus();
  textarea.setSelectionRange(pos, pos);
  closeMentionPop();
}
function onMentionInput(e) {
  const t = e.target;
  if (!t || !t.matches || !t.matches(MENTION_SEL)) return;
  const token = mentionTokenAt(t);
  if (!token) { closeMentionPop(); return; }
  showMentionPop(t, token);
}
function onMentionKeydown(e) {
  if (!mentionState || e.target !== mentionState.textarea) return;
  const n = mentionState.items.length;
  if (e.key === 'ArrowDown') { e.preventDefault(); mentionState.index = (mentionState.index + 1) % n; drawMentionPop(); }
  else if (e.key === 'ArrowUp') { e.preventDefault(); mentionState.index = (mentionState.index - 1 + n) % n; drawMentionPop(); }
  else if (e.key === 'Enter' || e.key === 'Tab') { e.preventDefault(); e.stopPropagation(); applyMention(mentionState.index); }
  else if (e.key === 'Escape') { e.preventDefault(); e.stopPropagation(); closeMentionPop(); }
}
function onMentionMousedown(e) {
  if (!mentionPop) return;
  const btn = e.target.closest && e.target.closest('.wb-mention-item');
  if (btn) { e.preventDefault(); applyMention(Number(btn.dataset.mentionIndex)); return; }
  if (!mentionPop.contains(e.target) && e.target !== (mentionState && mentionState.textarea)) closeMentionPop();
}

// A professional confirm dialog for the module (replaces window.confirm). Returns
// a Promise<boolean>. Self-contained overlay appended to <body>.
function wbConfirmModal({ title = 'Are you sure?', message = '', confirmLabel = 'Confirm', cancelLabel = 'Cancel', danger = false } = {}) {
  return new Promise((resolve) => {
    let settled = false;
    const done = (v) => { if (settled) return; settled = true; document.removeEventListener('keydown', onKey, true); overlay.remove(); resolve(v); };
    const overlay = document.createElement('div');
    overlay.className = 'wb-confirm-overlay';
    overlay.innerHTML = `
      <div class="wb-confirm-card" role="dialog" aria-modal="true">
        <div class="wb-confirm-title">${h(title)}</div>
        ${message ? `<div class="wb-confirm-msg">${h(message)}</div>` : ''}
        <div class="wb-confirm-acts">
          <button type="button" class="btn btn-sm" data-wb-confirm-cancel>${h(cancelLabel)}</button>
          <button type="button" class="btn btn-sm ${danger ? 'wb-confirm-danger' : 'btn-primary'}" data-wb-confirm-ok>${h(confirmLabel)}</button>
        </div>
      </div>`;
    overlay.addEventListener('mousedown', (e) => { if (e.target === overlay) done(false); });
    overlay.querySelector('[data-wb-confirm-cancel]').addEventListener('click', () => done(false));
    overlay.querySelector('[data-wb-confirm-ok]').addEventListener('click', () => done(true));
    function onKey(e) { if (e.key === 'Escape') { e.stopPropagation(); done(false); } else if (e.key === 'Enter') { e.stopPropagation(); done(true); } }
    document.addEventListener('keydown', onKey, true);
    document.body.appendChild(overlay);
    const ok = overlay.querySelector('[data-wb-confirm-ok]'); if (ok) ok.focus();
  });
}

// Open a ROM user profile from inside the embed by asking the parent to navigate.
function wbOpenUserProfile(uid) {
  if (!uid) return;
  try { window.parent.postMessage({ type: 'rom-open-user', uid }, window.location.origin); } catch { /* ignore */ }
}
function onMentionClick(e) {
  const m = e.target.closest && e.target.closest('.wb-mention[data-uid]');
  if (m) { e.preventDefault(); wbOpenUserProfile(m.dataset.uid); }
}

function init() {
  normalizeLegacyLocation();
  applyTheme();
  window.matchMedia('(prefers-color-scheme: dark)').addEventListener('change', () => {
    if (getThemeMode() === 'system') applyTheme();
  });
  window.addEventListener('popstate', () => {
    rememberSidebarScroll();
    render();
  });
  document.addEventListener('click', onDocumentClick);
  // ROM: the bridge pushes fresh workspace events/checklists via this event.
  window.addEventListener('rom-ws-data', () => { try { render(); } catch { /* ignore */ } });
  document.addEventListener('keydown', onDocumentKeydown);
  document.addEventListener('submit', onDocumentSubmit);
  document.addEventListener('input', onDocumentInput);
  document.addEventListener('change', onDocumentChange);
  // @mention typeahead (keydown in capture phase so it can intercept Enter/Tab/↑↓
  // before the app's own keydown handler).
  document.addEventListener('input', onMentionInput);
  document.addEventListener('keydown', onMentionKeydown, true);
  document.addEventListener('mousedown', onMentionMousedown);
  document.addEventListener('click', onMentionClick);
  // Widget tiles: a shared 1-second clock ticker + delegated calculator clicks.
  if (!state.wbClockTimer) { state.wbClockTimer = setInterval(wbTickClocks, 1000); }
  document.addEventListener('click', onWbCalcClick);
  window.addEventListener('scroll', () => { if (mentionState) positionMentionPop(mentionState.textarea); }, true);
  document.addEventListener('dragstart', onPipeDragStart);
  document.addEventListener('dragend', onPipeDragEnd);
  document.addEventListener('dragover', onPipeDragOver);
  document.addEventListener('drop', onPipeDrop);
  initializeAuth();
  render();
}

function getThemeMode() {
  const saved = localStorage.getItem(THEME_KEY);
  return ['light', 'dark', 'system'].includes(saved) ? saved : 'light';
}

function resolveThemeMode(mode = getThemeMode()) {
  if (mode === 'system') {
    return window.matchMedia('(prefers-color-scheme: dark)').matches ? 'dark' : 'light';
  }
  return mode === 'dark' ? 'dark' : 'light';
}

function getTheme() {
  return resolveThemeMode();
}

function getAccent() {
  const saved = localStorage.getItem(ACCENT_KEY);
  return ACCENT_OPTIONS.some(([id]) => id === saved) ? saved : 'ROM';
}

function applyTheme(theme = getTheme(), accent = getAccent()) {
  const mode = arguments.length === 0 ? getThemeMode() : theme;
  document.documentElement.dataset.themeMode = mode;
  document.documentElement.dataset.theme = resolveThemeMode(mode);
  document.documentElement.dataset.accent = accent;
}

function setTheme(theme) {
  const next = ['light', 'dark', 'system'].includes(theme) ? theme : 'light';
  localStorage.setItem(THEME_KEY, next);
  applyTheme(next);
  render();
}

function setAccent(accent) {
  const next = ACCENT_OPTIONS.some(([id]) => id === accent) ? accent : 'ROM';
  localStorage.setItem(ACCENT_KEY, next);
  applyTheme(getThemeMode(), next);
  render();
}

async function initializeAuth() {
  // Standalone local build: no Supabase, no login. Always run as a writable
  // local-basic session backed entirely by localStorage.
  if (state.session?.auth !== 'local-basic') {
    state.session = buildLocalSession();
    writeJson(SESSION_KEY, state.session);
  }
  resetDemoWorkspaceData();
  state.authReady = true;
}

async function setSupabaseSession(session) {
  if (!CONFIG.authEnabled) return;
  if (!session?.user) {
    state.session = null;
    resetLiveWorkspaceData();
    state.dataLoaded = false;
    localStorage.removeItem(SESSION_KEY);
    return;
  }
  const profile = await fetchSupabaseProfile(session.user);
  const nextSession = buildSupabaseSession(session, profile);
  const shouldReloadWorkspace = shouldReloadWorkspaceForSession(state.session, nextSession);
  state.session = nextSession;
  if (shouldReloadWorkspace) {
    resetLiveWorkspaceData();
    state.dataLoaded = false;
  }
  writeJson(SESSION_KEY, state.session);
}

function shouldReloadWorkspaceForSession(previousSession, nextSession) {
  if (!previousSession || previousSession.auth !== 'supabase') return true;
  if (!nextSession || nextSession.auth !== 'supabase') return true;
  if (previousSession?.user?.id !== nextSession?.user?.id) return true;
  if (previousSession?.profile?.member_id !== nextSession?.profile?.member_id) return true;
  if (previousSession?.profile?.role !== nextSession?.profile?.role) return true;
  if (previousSession?.profile?.approved !== nextSession?.profile?.approved) return true;
  return JSON.stringify(previousSession?.profile?.company_ids || []) !== JSON.stringify(nextSession?.profile?.company_ids || []);
}

async function fetchSupabaseProfile(user) {
  const fallback = {
    id: user.id,
    email: user.email || '',
    full_name: user.user_metadata?.full_name || user.email || 'ROM user',
    role: 'member',
    role_label: 'Member',
    member_id: '',
    company_ids: [],
    avatar_url: '',
    approved: false,
    email_verified: !!user.email_confirmed_at,
  };
  const client = createSupabaseClient();
  if (!client) return fallback;
  const result = await client.from('profiles').select('*').eq('id', user.id).maybeSingle();
  if (result.error || !result.data) return fallback;
  return normalizeProfile(result.data, fallback);
}

function render() {
  state.route = getRoute();

  if (CONFIG.authEnabled && !state.authReady) {
    renderAuthLoading();
    return;
  }

  if (state.route.name === 'home' || state.route.name === 'login') {
    // Standalone build: skip the marketing/login landing, go straight to the
    // Workspace App Builder for the active local company.
    navigate(companyPath('workspaces', {}, activeCompanyId()), { replace: true });
    return;
  }

  if (state.route.name === 'client-portal') {
    document.title = 'Client portal | ROM';
    try {
      app.innerHTML = renderClientPortalPublicPage(state.route);
    } catch (error) {
      console.error('Client portal render failed', error);
      app.innerHTML = `<main class="client-portal-public"><section class="client-portal-gate"><div class="client-portal-brand"><span class="side-mark logo-image-mark">${romLogoImage('ROM Client Portal')}</span><span><strong>ROM Client Portal</strong><small>Plan review</small></span></div><h1>Something went wrong</h1><div class="form-message error">${h(error.message || String(error))}</div></section></main>`;
      return;
    }
    queueMicrotask(() => {
      if (shouldAutoOpenClientPortal(state.route.token)) {
        ensureClientPortalPublicOpen(state.route.token).catch((error) => {
          state.clientPortalPublic = { token: state.route.token || '', error: error.message || 'Could not open portal.' };
          render();
        });
      }
      mountClientPortalAnnotate().catch((error) => console.warn('Client portal viewer failed', error));
    });
    return;
  }

  if (state.route.name === 'proposal-public') {
    document.title = 'Proposal | ROM';
    app.innerHTML = renderProposalPublicPage(state.route);
    queueMicrotask(() => {
      ensureProposalPublicOpen(state.route.token).catch((error) => {
        state.proposalPublic = { token: state.route.token || '', error: error.message || 'Could not open proposal.' };
        render();
      });
    });
    return;
  }

  if (state.route.name === 'form-public') {
    document.title = 'Form | ROM';
    app.innerHTML = renderPublicFormPage(state.route);
    queueMicrotask(() => {
      ensurePublicFormOpen(state.route.token).catch((error) => {
        state.publicForm = { formId: state.route.token || '', error: error.message || 'Could not open form.' };
        render();
      });
    });
    return;
  }

  if (needsLocalLogin(state.route)) {
    navigate('/login?return_url=' + encodeURIComponent(currentAppUrl()), { replace: true });
    return;
  }

  ensureDataLoad();
  if (shouldHoldCompanyRouteForLiveData(state.route)) {
    renderWorkspaceLoading(state.route);
    return;
  }
  if (state.session?.auth === 'supabase' && state.dataLoaded && !allowedCompanyIds().length) {
    renderNoCompanyAccess();
    return;
  }
  const redirect = routeRedirect(state.route);
  if (redirect) {
    navigate(redirect, { replace: true });
    return;
  }

  reconcileCompany(state.route);
  reconcileSelection(state.route);
  if (state.route.params.get('account') === 'profile') state.modal = 'profile';
  if (state.route.name === 'company'
      && state.route.section === 'client-portals'
      && state.route.params.get('annotate') === '1'
      && state.route.params.get('fs') === '1'
      && state.route.params.get('portal_id')
      && clientPortalById(state.route.params.get('portal_id'))) {
    const portalId = state.route.params.get('portal_id');
    ensureClientPortalAnnotateState('owner', portalId, state.route.params.get('document_id') || '');
    document.title = `Plan review | ${companyName(activeCompanyId())} | ROM`;
    app.innerHTML = `<div class="cp-fullscreen">${renderClientPortalAnnotate('owner')}</div>`;
    queueMicrotask(() => mountClientPortalAnnotate().catch((error) => console.warn('Annotate mount failed', error)));
    return;
  }
  document.title = `${routeTitle(state.route)} | ${companyName(activeCompanyId())} | ROM`;
  app.innerHTML = shellTemplate(state.route, renderWorkspace(state.route));
  queueMicrotask(restoreSidebarScroll);
  queueMicrotask(bindTimePickerInputs);
  queueMicrotask(bindGoogleAddressInputs);
  queueMicrotask(() => initContactAddressForm().catch((error) => console.warn('Contact map failed', error)));
  queueMicrotask(mountPriceBookVendorModal);
  queueMicrotask(mountPriceBookImport);
  queueMicrotask(() => mountLocationPicker().catch((error) => console.warn('Location picker map failed', error)));
  queueMicrotask(mountWorkspaceBuilder);
  queueMicrotask(mountFileViewer);
  queueMicrotask(mountDashboardWidgetDnD);
}

function openNativeTimePicker(input) {
  if (typeof input.showPicker !== 'function') return;
  try {
    input.showPicker();
  } catch (error) {
    // Browsers can reject showPicker outside trusted user activation.
  }
}

function bindTimePickerInputs() {
  document.querySelectorAll('input[type="time"]:not([data-time-picker-bound])').forEach((input) => {
    input.dataset.timePickerBound = 'true';
    input.addEventListener('pointerdown', () => openNativeTimePicker(input));
    input.addEventListener('focus', () => openNativeTimePicker(input));
  });
}

function parseJobTypeOptions(input) {
  try {
    const parsed = JSON.parse(input.dataset.jobTypeOptions || '[]');
    return Array.isArray(parsed) ? parsed : [];
  } catch (error) {
    return [];
  }
}

function jobTypeMenu(input) {
  const host = input.closest('.job-type-combobox');
  if (!host) return null;
  let menu = host.querySelector('[data-job-type-menu]');
  if (!menu) {
    menu = document.createElement('div');
    menu.className = 'job-type-suggestions-menu';
    menu.setAttribute('data-job-type-menu', '');
    menu.hidden = true;
    host.appendChild(menu);
  }
  if (!menu.dataset.jobTypeBound) {
    menu.dataset.jobTypeBound = 'true';
    menu.addEventListener('pointerdown', (event) => {
      if (event.target.closest('[data-job-type-option]')) event.preventDefault();
    });
  }
  return menu;
}

function jobTypeMatches(input) {
  const query = input.value.trim().toLowerCase();
  const options = parseJobTypeOptions(input);
  const filtered = query
    ? options.filter((item) => item.toLowerCase().includes(query))
    : options;
  return filtered.slice(0, 12);
}

function renderJobTypeSuggestions(input, force = false) {
  const menu = jobTypeMenu(input);
  if (!menu) return;
  const query = input.value.trim();
  const matches = jobTypeMatches(input);
  const exact = matches.some((item) => item.toLowerCase() === query.toLowerCase());
  const custom = query && !exact ? [`<button type="button" class="job-type-suggestion-option custom" data-job-type-option="${h(query)}"><i class="ti ti-plus"></i><span>Use "${h(query)}"</span></button>`] : [];
  if (!force && !query && !matches.length) {
    menu.hidden = true;
    menu.innerHTML = '';
    return;
  }
  menu.innerHTML = `${custom.join('')}${matches.map((item) => `<button type="button" class="job-type-suggestion-option" data-job-type-option="${h(item)}"><span>${h(item)}</span></button>`).join('')}`;
  menu.hidden = !menu.innerHTML;
}

function closeJobTypeMenus(exceptInput = null) {
  document.querySelectorAll('[data-job-type-menu]').forEach((menu) => {
    if (exceptInput && menu.closest('.job-type-combobox')?.contains(exceptInput)) return;
    menu.hidden = true;
  });
}

function wireJobTypeAutocomplete(input, options = null) {
  if (options) input.dataset.jobTypeOptions = JSON.stringify(options);
  input.setAttribute('autocomplete', 'off');
  input.setAttribute('data-job-type-input', '');
  jobTypeMenu(input);
  renderJobTypeSuggestions(input, true);
}

function addressLookupContainer(input) {
  return input.closest('.address-lookup-control, .sf-inline-address-editor');
}

function addressLookupField(input) {
  return input.closest('.address-lookup-field, .sf-inline-address-editor');
}

function closeAddressSuggestionMenus(exceptInput = null) {
  document.querySelectorAll('.address-suggestions-menu').forEach((menu) => {
    if (exceptInput && menu.dataset.addressInputId === exceptInput.dataset.addressInputId) return;
    menu.hidden = true;
    menu.innerHTML = '';
  });
}

function parseAddressOptionDataset(input) {
  try {
    const parsed = JSON.parse(input.dataset.addressOptions || '[]');
    return Array.isArray(parsed) ? parsed : [];
  } catch (error) {
    return [];
  }
}

function localAddressSuggestions(input, query) {
  const needle = String(query || '').toLowerCase();
  if (!needle) return [];
  return parseAddressOptionDataset(input)
    .filter((address) => String(address || '').toLowerCase().includes(needle))
    .map((address) => ({ label: String(address), value: String(address), source: 'saved' }));
}

function mergeAddressSuggestions(...groups) {
  const merged = new Map();
  groups.flat().forEach((item) => {
    const value = String(item?.value || item?.label || '').trim();
    if (!value) return;
    const key = value.toLowerCase();
    if (!merged.has(key)) merged.set(key, { label: String(item.label || value), value, source: item.source || 'address' });
  });
  return [...merged.values()].slice(0, 8);
}

function addressSuggestionMenu(input) {
  if (!input.dataset.addressInputId) input.dataset.addressInputId = `address-${crypto.randomUUID()}`;
  const host = addressLookupContainer(input) || addressLookupField(input);
  if (!host) return null;
  let menu = host.querySelector(`.address-suggestions-menu[data-address-input-id="${input.dataset.addressInputId}"]`);
  if (!menu) {
    menu = document.createElement('div');
    menu.className = 'address-suggestions-menu';
    menu.dataset.addressInputId = input.dataset.addressInputId;
    menu.setAttribute('role', 'listbox');
    menu.hidden = true;
    host.appendChild(menu);
  }
  return menu;
}

function renderAddressSuggestionMenu(input, suggestions, status = '') {
  const menu = addressSuggestionMenu(input);
  if (!menu) return;
  if (!suggestions.length && !status) {
    menu.hidden = true;
    menu.innerHTML = '';
    return;
  }
  const rows = suggestions.map((item) => `
    <button type="button" class="address-suggestion-option" data-address-suggestion="${h(item.value)}" role="option">
      <i class="ti ti-map-pin"></i>
      <span>${h(item.label)}</span>
    </button>
  `).join('');
  menu.innerHTML = `${status ? `<div class="address-suggestion-status">${h(status)}</div>` : ''}${rows}`;
  menu.hidden = false;
  menu.querySelectorAll('[data-address-suggestion]').forEach((button) => {
    button.addEventListener('pointerdown', (ev) => ev.preventDefault());
    button.addEventListener('click', () => {
      input.value = button.dataset.addressSuggestion || '';
      input.dispatchEvent(new Event('input', { bubbles: true }));
      input.dispatchEvent(new Event('change', { bubbles: true }));
      closeAddressSuggestionMenus();
      input.focus();
    });
  });
}

async function refreshAddressSuggestions(input) {
  const query = String(input.value || '').trim();
  const local = localAddressSuggestions(input, query);
  if (query.length < 3) {
    renderAddressSuggestionMenu(input, mergeAddressSuggestions(local));
    return;
  }
  const requestId = String(++addressSuggestionRequestSeq);
  input.dataset.addressSuggestRequest = requestId;
  renderAddressSuggestionMenu(input, mergeAddressSuggestions(local), 'Searching addresses...');
  const response = await fetch(`/api/address-suggestions?q=${encodeURIComponent(query)}`).catch(() => null);
  if (input.dataset.addressSuggestRequest !== requestId) return;
  const payload = response?.ok ? await response.json().catch(() => ({})) : {};
  const remote = Array.isArray(payload.suggestions) ? payload.suggestions : [];
  renderAddressSuggestionMenu(input, mergeAddressSuggestions(remote, local));
}

function scheduleAddressSuggestions(input) {
  window.clearTimeout(Number(input.dataset.addressSuggestTimer || 0));
  const timer = window.setTimeout(() => {
    refreshAddressSuggestions(input).catch(() => renderAddressSuggestionMenu(input, localAddressSuggestions(input, input.value)));
  }, 250);
  input.dataset.addressSuggestTimer = String(timer);
}

function bindGoogleAddressInputs() {
  document.querySelectorAll('[data-address-lookup-input]:not([data-address-lookup-bound])').forEach((input) => {
    input.dataset.addressLookupBound = 'true';
    const field = addressLookupField(input);
    const link = field?.querySelector('[data-address-map-link]');
    const updatePinLink = () => {
      const address = String(input.value || '').trim();
      if (!link) return;
      link.href = address ? googleMapsPlaceSearchUrl(address) : '#';
      link.classList.toggle('is-disabled', !address);
      link.setAttribute('aria-disabled', address ? 'false' : 'true');
    };
    input.addEventListener('input', () => {
      updatePinLink();
      scheduleAddressSuggestions(input);
    });
    input.addEventListener('focus', () => scheduleAddressSuggestions(input));
    input.addEventListener('keydown', (ev) => {
      if (ev.key === 'Escape') closeAddressSuggestionMenus();
    });
    link?.addEventListener('pointerdown', (ev) => {
      if (link.getAttribute('aria-disabled') !== 'true') ev.preventDefault();
    });
    link?.addEventListener('click', (ev) => {
      updatePinLink();
      if (link.getAttribute('aria-disabled') === 'true') ev.preventDefault();
    });
    updatePinLink();
  });
  const places = window.google?.maps?.places;
  if (!places?.Autocomplete) return;
  document.querySelectorAll('[data-google-address-input]:not([data-google-bound])').forEach((input) => {
    input.dataset.googleBound = 'true';
    const autocomplete = new places.Autocomplete(input, { fields: ['formatted_address', 'geometry', 'name'], types: ['address'] });
    autocomplete.addListener('place_changed', () => {
      const place = autocomplete.getPlace();
      if (place?.formatted_address) {
        input.value = place.formatted_address;
        input.dispatchEvent(new Event('input', { bubbles: true }));
      }
    });
  });
}

function shouldHoldCompanyRouteForLiveData(route) {
  // Only show the full "Loading workspace data…" screen on the very first load.
  // Once data has loaded once, later re-fetches (a save, or a realtime update)
  // refresh in place using the data already on screen — no blocking loader.
  return !!route && route.name !== 'home' && route.name !== 'login' && route.name !== 'client-portal' && route.name !== 'proposal-public' && route.name !== 'form-public' && state.session?.auth === 'supabase' && !state.dataLoaded && !state.everLoaded;
}

function renderWorkspaceLoading(route) {
  document.title = `${routeTitle(route)} | ROM`;
  app.innerHTML = `
    <main class="login-shell">
      <section class="login-panel">
        <div class="login-brand">
          <span class="side-mark logo-image-mark">${romLogoImage()}</span>
          <span><strong>ROM</strong><small>Secure workspace</small></span>
        </div>
        ${emptyState('Loading workspace data...')}
      </section>
    </main>
  `;
}

function workspacePresetSelect(selected = 'generic') {
  return `
    <label>Company type
      <select name="preset_code">
        ${Object.keys(WORKSPACE_PLUGIN_PRESETS).map((presetCode) => `
          <option value="${h(presetCode)}" ${presetCode === selected ? 'selected' : ''}>${h(WORKSPACE_PLUGIN_PRESET_LABELS[presetCode] || titleCase(presetCode))}</option>
        `).join('')}
      </select>
    </label>
  `;
}

function workspaceIconSelect(selected = 'home') {
  const activeIcon = workspaceIconOption(selected).key;
  return `
    <label>Workspace icon
      <select name="icon_key">
        ${WORKSPACE_ICON_OPTIONS.map((item) => `<option value="${h(item.key)}" ${item.key === activeIcon ? 'selected' : ''}>${h(item.label)}</option>`).join('')}
      </select>
    </label>
  `;
}

function renderNoCompanyAccess() {
  const busy = /creating|joining|opening/i.test(state.authMessage || '');
  const canCreate = canCreateAnotherWorkspace();
  document.title = 'Company access pending | ROM';
  app.innerHTML = `
    <main class="login-shell">
      <section class="login-panel">
        <div class="login-brand">
          <span class="side-mark logo-image-mark">${romLogoImage()}</span>
          <span><strong>ROM</strong><small>Access pending</small></span>
        </div>
        <div>
          <div class="eyebrow">Tenant security</div>
          <h1>No active company access</h1>
          <p>Your account exists, but you are not an active member of a company workspace yet. Business owners can create a workspace. Workers need an invite code from their company admin.</p>
        </div>
        <section class="login-lanes no-access-lanes">
          <article class="login-lane-card">
            <div>
              <strong>Business owner</strong>
              <span>Create a company workspace for ROM approval.</span>
            </div>
            <form data-company-create-form>
              <label>Company workspace<input name="company_name" placeholder="Example Roofing LLC" required /></label>
              ${workspacePresetSelect()}
              ${workspaceIconSelect()}
              <button class="btn btn-primary full" type="submit" ${busy || !canCreate ? 'disabled' : ''}>${busy ? 'Creating workspace...' : 'Create business workspace'}</button>
              ${state.loginError ? `<div class="form-message error">${h(state.loginError)}</div>` : `<div class="form-message">${h(state.authMessage || `${workspaceLimitMessage()} You become Owner, then ROM approves access before live modules open.`)}</div>`}
            </form>
          </article>
          <article class="login-lane-card">
            <div>
              <strong>Invited worker</strong>
              <span>Join only with a code from your Owner/Admin.</span>
            </div>
            <form data-existing-invite-code-form>
              <label>Invite code<input name="invite_code" autocomplete="one-time-code" required placeholder="Paste invite code" /></label>
              <button class="btn full" type="submit">Join workspace</button>
              <div class="form-message">Worker registration is blocked without an invite.</div>
            </form>
          </article>
        </section>
        <button class="btn full" type="button" data-action="sign-out">Sign out</button>
      </section>
    </main>
  `;
}

function needsLocalLogin(route) {
  if (!CONFIG.authEnabled && !CONFIG.localLoginEnabled) return false;
  if (route.name === 'login' || route.name === 'home' || route.name === 'proposal-public' || route.name === 'form-public') return false;
  return !state.session;
}

function renderAuthLoading() {
  document.title = 'Loading | ROM';
  app.innerHTML = `
    <main class="login-shell">
      <section class="login-panel">
        <div class="login-brand">
          <span class="side-mark logo-image-mark">${romLogoImage()}</span>
          <span><strong>ROM</strong><small>Secure workspace</small></span>
        </div>
        ${emptyState('Checking secure session...')}
      </section>
    </main>
  `;
}

function ensureDataLoad() {
  if (state.dataLoaded || state.dataLoading) return;
  state.dataLoading = true;
  loadSupabaseData()
    .catch(async (error) => {
      console.warn('Workspace data load failed', error);
      if (state.session?.auth === 'supabase') {
        await loadSupabaseBootstrapData().catch((bootstrapError) => console.warn('Workspace bootstrap load failed', bootstrapError));
      }
      if (state.sync.mode === 'loading') state.sync = { label: 'Local fallback', mode: 'local' };
    })
    .finally(async () => {
      state.dataLoaded = true;
      state.everLoaded = true;
      state.dataLoading = false;
      await maybeRunAutomaticBackups().catch((error) => console.warn('Automatic backup failed', error));
      persistAll();
      if (state.session?.auth === 'supabase') { try { subscribeToGlobalRealtime(); } catch (err) { console.warn('Realtime subscribe failed', err); } }
      render();
    });
}

async function loadSupabaseData() {
  if (state.session?.auth === 'local-basic' || state.session?.auth === 'demo-readonly') {
    state.sync = { label: isReadOnlyDemo() ? 'Read-only demo' : 'Demo mode', mode: 'local' };
    return;
  }
  const client = createSupabaseClient();
  if (!client) {
    state.sync = { label: 'Supabase unavailable', mode: 'local' };
    return;
  }

  const [
    companiesResult,
    jobsResult,
    tasksResult,
    filesResult,
    teamResult,
    membershipsResult,
    profilesResult,
    subscriptionsResult,
    rolesResult,
    rolePermissionsResult,
    roleAssignmentsResult,
    resourceAclResult,
    fieldPermissionsResult,
    invitesResult,
    joinRequestsResult,
    auditEventsResult,
    messageConversationsResult,
    messageAccessResult,
    messagesResult,
    messageAttachmentsResult,
    messageReadsResult,
    calendarEventsResult,
    notificationsResult,
    formsResult,
    formResponsesResult,
    financeInvoicesResult,
    financePaymentsResult,
    financeExpensesResult,
    financeVendorsResult,
    contactsResult,
    pipelineStagesResult,
    accountsResult,
    dealsResult,
    sitesResult,
    proposalsResult,
    activitiesResult,
    companyPluginsResult,
    clientPortalsResult,
    clientPortalDocumentsResult,
    clientPortalAnnotationsResult,
    clientPortalEventsResult,
    pricebookVendorsResult,
    pricebookMaterialsResult,
    pricebookPricesResult,
    workspaceBackupsResult,
    recycleBinResult,
    workspaceBuilderResult,
    platformAdminResult,
  ] = await Promise.all([
    client.from('companies').select('*').order('name', { ascending: true }),
    client.from('jobs').select('*').order('updated_at', { ascending: false }),
    client.from('tasks').select('*').order('updated_at', { ascending: false }),
    client.from('job_files').select('*').is('deleted_at', null).order('created_at', { ascending: false }),
    client.from('team_members').select('*').order('name', { ascending: true }),
    client.from('company_memberships').select('*'),
    client.from('profiles').select('*'),
    client.from('company_subscriptions').select('*'),
    client.from('roles').select('*').order('priority', { ascending: false }),
    client.from('role_permissions').select('*'),
    client.from('user_role_assignments').select('*'),
    client.from('resource_acl').select('*'),
    client.from('field_permissions').select('*'),
    client.from('company_invites').select('*').order('created_at', { ascending: false }),
    client.from('company_join_requests').select('*').order('created_at', { ascending: false }),
    client.from('audit_events').select('*').order('created_at', { ascending: false }).limit(100),
    client.from('message_conversations').select('*').order('last_message_at', { ascending: false }),
    client.from('message_conversation_access').select('*'),
    client.from('messages').select('*').order('created_at', { ascending: true }).limit(500),
    client.from('message_attachments').select('*').order('created_at', { ascending: true }).limit(500),
    client.from('message_reads').select('*'),
    client.from('calendar_events').select('*').order('starts_at', { ascending: true }),
    client.from('notifications').select('*').order('created_at', { ascending: false }).limit(200),
    client.from('forms').select('*').order('updated_at', { ascending: false }),
    client.from('form_responses').select('*').order('created_at', { ascending: false }).limit(500),
    client.from('finance_invoices').select('*').order('updated_at', { ascending: false }),
    client.from('finance_payments').select('*').order('received_at', { ascending: false }),
    client.from('finance_expenses').select('*').order('spent_at', { ascending: false }),
    client.from('finance_vendors').select('*').order('name', { ascending: true }),
    client.from('contacts').select('*').order('updated_at', { ascending: false }),
    client.from('pipeline_stages').select('*').order('position', { ascending: true }),
    client.from('accounts').select('*').order('name', { ascending: true }),
    client.from('deals').select('*').order('updated_at', { ascending: false }),
    safeSupabaseQuery(client.from('crm_sites').select('*').order('updated_at', { ascending: false })),
    safeSupabaseQuery(client.from('proposal_documents').select('*').order('updated_at', { ascending: false })),
    client.from('activities').select('*').order('created_at', { ascending: false }).limit(500),
    safeSupabaseQuery(client.from('company_plugins').select('*')),
    safeSupabaseQuery(client.from('client_portals').select('*').order('updated_at', { ascending: false })),
    safeSupabaseQuery(client.from('client_portal_documents').select('*').order('created_at', { ascending: false })),
    safeSupabaseQuery(client.from('client_portal_annotations').select('*').order('created_at', { ascending: true })),
    safeSupabaseQuery(client.from('client_portal_events').select('*').order('created_at', { ascending: false }).limit(500)),
    safeSupabaseQuery(client.from('pricebook_vendors').select('*').order('name', { ascending: true })),
    safeSupabaseQuery(client.from('pricebook_materials').select('*').order('name', { ascending: true })),
    safeSupabaseQuery(client.from('pricebook_vendor_prices').select('*').order('updated_at', { ascending: false })),
    safeSupabaseQuery(client.from('workspace_backups').select('*').order('created_at', { ascending: false })),
    safeSupabaseQuery(client.from('recycle_bin_items').select('*').order('deleted_at', { ascending: false })),
    safeSupabaseQuery(client.from('workspace_builder_state').select('*')),
    safeSupabaseQuery(client.rpc('is_platform_admin')),
  ]);

  let liveTables = 0;
  if (!companiesResult.error) {
    state.companies = (companiesResult.data || []).map(normalizeCompany);
    liveTables += 1;
  }
  if (!jobsResult.error) {
    state.jobs = activeRows(jobsResult.data || []).map(normalizeJob);
    liveTables += 1;
  }
  if (!tasksResult.error) {
    state.tasks = activeRows(tasksResult.data || []).map(normalizeTask);
    liveTables += 1;
  }
  if (!filesResult.error) {
    state.files = (filesResult.data || []).map(normalizeFile);
    wbReconstructAppDriveFolders();
    liveTables += 1;
  }
  if (!teamResult.error) {
    state.teamMembers = (teamResult.data || []).map(normalizeTeamMember);
    liveTables += 1;
  }
  if (!membershipsResult.error) {
    state.memberships = (membershipsResult.data || []).map(normalizeMembership);
    liveTables += 1;
  }
  if (!profilesResult.error) {
    state.profiles = (profilesResult.data || []).map((profile) => normalizeProfile(profile));
    liveTables += 1;
  }
  if (!subscriptionsResult.error) {
    state.subscriptions = (subscriptionsResult.data || []).map(normalizeSubscription);
    liveTables += 1;
  }
  if (!rolesResult.error) {
    state.roles = (rolesResult.data || []).map(normalizeRole);
    liveTables += 1;
  }
  if (!rolePermissionsResult.error) state.rolePermissions = (rolePermissionsResult.data || []).map(normalizeRolePermission);
  if (!roleAssignmentsResult.error) state.roleAssignments = (roleAssignmentsResult.data || []).map(normalizeRoleAssignment);
  if (!resourceAclResult.error) state.resourceAcl = (resourceAclResult.data || []).map(normalizeResourceAcl);
  if (!fieldPermissionsResult.error) state.fieldPermissions = (fieldPermissionsResult.data || []).map(normalizeFieldPermission);
  if (!invitesResult.error) state.companyInvites = (invitesResult.data || []).map(normalizeCompanyInvite);
  if (!joinRequestsResult.error) state.joinRequests = (joinRequestsResult.data || []).map(normalizeJoinRequest);
  if (!auditEventsResult.error) state.auditEvents = auditEventsResult.data || [];
  if (!messageConversationsResult.error) state.messageConversations = (messageConversationsResult.data || []).map(normalizeMessageConversation);
  if (!messageAccessResult.error) state.messageAccess = (messageAccessResult.data || []).map(normalizeMessageAccess);
  if (!messagesResult.error) state.messages = (messagesResult.data || []).map(normalizeMessage);
  if (!messageAttachmentsResult.error) state.messageAttachments = (messageAttachmentsResult.data || []).map(normalizeMessageAttachment);
  if (!messageReadsResult.error) state.messageReads = (messageReadsResult.data || []).map(normalizeMessageRead);
  if (!calendarEventsResult.error) state.calendarEvents = activeRows(calendarEventsResult.data || []).map(normalizeCalendarEvent);
  if (!notificationsResult.error) state.notifications = (notificationsResult.data || []).map(normalizeNotification);
  if (!formsResult.error) {
    state.forms = activeRows(formsResult.data || []).map(normalizeForm);
    liveTables += 1;
  }
  if (!formResponsesResult.error) state.formResponses = activeRows(formResponsesResult.data || []).map(normalizeFormResponse);
  if (!financeInvoicesResult.error) {
    state.financeInvoices = activeRows(financeInvoicesResult.data || []).map(normalizeFinanceInvoice);
    liveTables += 1;
  }
  if (!financePaymentsResult.error) state.financePayments = activeRows(financePaymentsResult.data || []).map(normalizeFinancePayment);
  if (!financeExpensesResult.error) state.financeExpenses = activeRows(financeExpensesResult.data || []).map(normalizeFinanceExpense);
  if (!financeVendorsResult.error) state.financeVendors = activeRows(financeVendorsResult.data || []).map(normalizeFinanceVendor);
  if (!contactsResult.error) {
    state.contacts = activeRows(contactsResult.data || []).map(normalizeContact);
    liveTables += 1;
  }
  if (!pipelineStagesResult.error) {
    state.pipelineStages = pipelineStagesResult.data || [];
    applyPipelineStagesForCompany(activeCompanyId());
  }
  if (!accountsResult.error) {
    state.accounts = activeRows(accountsResult.data || []).map(normalizeAccount);
    liveTables += 1;
  }
  if (!dealsResult.error) {
    state.deals = activeRows(dealsResult.data || []).map(normalizeDeal);
    liveTables += 1;
  }
  if (!sitesResult.error) {
    state.sites = (sitesResult.data || []).map(normalizeCrmSite);
  }
  if (!proposalsResult.error) {
    state.proposals = activeRows(proposalsResult.data || []).map(normalizeProposal);
  }
  if (!activitiesResult.error) {
    state.activities = activeRows(activitiesResult.data || []).map(normalizeActivity);
  }
  if (!companyPluginsResult.error) {
    state.companyPlugins = (companyPluginsResult.data || []).map(normalizeCompanyPlugin);
    state.pluginLoadFailed = false;
  } else {
    state.pluginLoadFailed = true;
  }
  if (!clientPortalsResult.error) state.clientPortals = activeRows(clientPortalsResult.data || []).map(normalizeClientPortal);
  if (!clientPortalDocumentsResult.error) state.clientPortalDocuments = activeRows(clientPortalDocumentsResult.data || []).map(normalizeClientPortalDocument);
  if (!clientPortalAnnotationsResult.error) state.clientPortalAnnotations = (clientPortalAnnotationsResult.data || []).map(normalizeClientPortalAnnotation);
  if (!clientPortalEventsResult.error) state.clientPortalEvents = (clientPortalEventsResult.data || []).map(normalizeClientPortalEvent);
  if (!pricebookVendorsResult.error) state.pricebookVendors = activeRows(pricebookVendorsResult.data || []).map(normalizePricebookVendor);
  if (!pricebookMaterialsResult.error) state.pricebookMaterials = activeRows(pricebookMaterialsResult.data || []).map(normalizePricebookMaterial);
  if (!pricebookPricesResult.error) state.pricebookPrices = activeRows(pricebookPricesResult.data || []).map(normalizePricebookPrice);
  if (!workspaceBackupsResult.error) state.workspaceBackups = (workspaceBackupsResult.data || []).map(normalizeWorkspaceBackup);
  if (!recycleBinResult.error) state.recycleBinItems = (recycleBinResult.data || []).map(normalizeRecycleBinItem);
  if (!workspaceBuilderResult.error) {
    // Don't let a background refresh clobber optimistic edits whose save is still
    // in flight (or landed in the last few seconds) — keep the local doc for those.
    const holdLocalWb = (state.wbPendingSaves || 0) > 0 || (Date.now() - (state.wbLastLocalEditAt || 0) < 4000);
    const prevDocs = state.workspaceBuilderDocs || {};
    state.workspaceBuilderDocs = {};
    state.workspaceBuilderLive = {};
    (workspaceBuilderResult.data || []).forEach((row) => {
      const companyId = canonicalCompanyId(row.company_id);
      state.workspaceBuilderDocs[companyId] = holdLocalWb && prevDocs[companyId] ? prevDocs[companyId] : normalizeWorkspaceBuilderDoc(row.doc);
      state.workspaceBuilderLive[companyId] = true;
    });
    // Preserve any local-only docs (unsaved companies) that the server didn't return.
    if (holdLocalWb) Object.keys(prevDocs).forEach((cid) => { if (!state.workspaceBuilderDocs[cid]) state.workspaceBuilderDocs[cid] = prevDocs[cid]; });
  }
  state.platformAdmin = !platformAdminResult.error && platformAdminResult.data === true;

  if (state.platformAdmin) {
    const [platformCompaniesResult, platformMembersResult, platformBackupCopiesResult] = await Promise.all([
      safeSupabaseQuery(client.rpc('list_platform_companies')),
      safeSupabaseQuery(client.rpc('list_platform_company_members', { target_company_id: null })),
      safeSupabaseQuery(client.rpc('list_platform_backup_copies', { filter_company_id: null, filter_status: null, filter_kind: null })),
    ]);
    if (!platformCompaniesResult.error) {
      state.platformCompanies = (platformCompaniesResult.data || []).map(normalizePlatformCompany);
      state.workspaceReviews = state.platformCompanies.map(normalizeWorkspaceReview);
      state.companies = mergeCompanies(state.companies.concat(state.platformCompanies.map((company) => normalizeCompany({
        id: company.company_id,
        name: company.company_name,
        short_name: company.short_name || company.company_name,
        color: company.color,
        label: company.label,
        pill: company.pill,
        icon_key: company.icon_key,
      }))));
      state.subscriptions = mergeSubscriptions(state.subscriptions.concat(state.platformCompanies.map(normalizeSubscription)));
    }
    if (!platformMembersResult.error) {
      state.platformCompanyMembers = (platformMembersResult.data || []).map(normalizePlatformCompanyMember);
    }
    if (!platformBackupCopiesResult.error) {
      state.platformBackupCopies = (platformBackupCopiesResult.data || []).map(normalizePlatformBackupCopy);
    }
  }

  if (isQuestDeveloper() && !state.platformCompanies.length) {
    const reviewsResult = await safeSupabaseQuery(client.rpc('list_workspace_reviews'));
    if (!reviewsResult.error) {
      state.workspaceReviews = (reviewsResult.data || []).map(normalizeWorkspaceReview);
      const reviewCompanies = state.workspaceReviews.map((review) => normalizeCompany({
        id: review.company_id,
        name: review.company_name,
        short_name: review.company_name,
      }));
      const reviewSubscriptions = state.workspaceReviews.map((review) => normalizeSubscription({
        company_id: review.company_id,
        status: review.status,
        plan_code: review.plan_code,
        amount_cents: review.amount_cents,
        currency: review.currency,
        trial_ends_at: review.trial_ends_at,
        current_period_end: review.current_period_end,
        grace_ends_at: review.grace_ends_at,
      }));
      state.companies = mergeCompanies(state.companies.concat(reviewCompanies));
      state.subscriptions = mergeSubscriptions(state.subscriptions.concat(reviewSubscriptions));
    }
  }

  state.sync = liveTables ? { label: 'ROM Supabase live', mode: 'live' } : { label: 'Local fallback', mode: 'local' };
}

async function loadSupabaseBootstrapData() {
  if (state.session?.auth !== 'supabase') return;
  const client = createSupabaseClient();
  if (!client) return;
  const profile = activeSession().profile;
  const [membershipsResult, profileResult, platformAdminResult] = await Promise.all([
    safeSupabaseQuery(client.from('company_memberships').select('*').eq('profile_id', profile.id)),
    safeSupabaseQuery(client.from('profiles').select('*').eq('id', profile.id).maybeSingle()),
    safeSupabaseQuery(client.rpc('is_platform_admin')),
  ]);
  if (!profileResult.error && profileResult.data) {
    const nextProfile = normalizeProfile(profileResult.data, profile);
    state.session = { ...activeSession(), profile: nextProfile };
    writeJson(SESSION_KEY, state.session);
  }
  if (!membershipsResult.error) {
    const ownMemberships = (membershipsResult.data || []).map(normalizeMembership);
    state.memberships = ownMemberships.concat(state.memberships.filter((item) => item.profile_id !== profile.id));
  }
  state.platformAdmin = !platformAdminResult.error && platformAdminResult.data === true;
  const companyIds = compactUnique(state.memberships
    .filter((item) => item.profile_id === activeSession().profile.id && item.status === 'active')
    .map((item) => item.company_id)
    .concat(activeSession().profile.company_ids || []));
  if (companyIds.length) {
    const [companiesResult, subscriptionsResult, rolesResult, rolePermissionsResult, roleAssignmentsResult, companyPluginsResult] = await Promise.all([
      safeSupabaseQuery(client.from('companies').select('*').in('id', companyIds)),
      safeSupabaseQuery(client.from('company_subscriptions').select('*').in('company_id', companyIds)),
      safeSupabaseQuery(client.from('roles').select('*').in('company_id', companyIds)),
      safeSupabaseQuery(client.from('role_permissions').select('*')),
      safeSupabaseQuery(client.from('user_role_assignments').select('*').in('company_id', companyIds)),
      safeSupabaseQuery(client.from('company_plugins').select('*').in('company_id', companyIds)),
    ]);
    if (!companiesResult.error) state.companies = mergeCompanies(state.companies.concat((companiesResult.data || []).map(normalizeCompany)));
    if (!subscriptionsResult.error) state.subscriptions = mergeSubscriptions(state.subscriptions.concat((subscriptionsResult.data || []).map(normalizeSubscription)));
    if (!rolesResult.error) state.roles = mergeRoles(state.roles.concat((rolesResult.data || []).map(normalizeRole)));
    if (!rolePermissionsResult.error) state.rolePermissions = (rolePermissionsResult.data || []).map(normalizeRolePermission);
    if (!roleAssignmentsResult.error) state.roleAssignments = (roleAssignmentsResult.data || []).map(normalizeRoleAssignment);
    if (!companyPluginsResult.error) {
      state.companyPlugins = mergeCompanyPlugins(state.companyPlugins.concat((companyPluginsResult.data || []).map(normalizeCompanyPlugin)));
      state.pluginLoadFailed = false;
    } else {
      state.pluginLoadFailed = true;
    }
  }
  if (state.platformAdmin) {
    const [platformCompaniesResult, platformMembersResult] = await Promise.all([
      safeSupabaseQuery(client.rpc('list_platform_companies')),
      safeSupabaseQuery(client.rpc('list_platform_company_members', { target_company_id: null })),
    ]);
    if (!platformCompaniesResult.error) {
      state.platformCompanies = (platformCompaniesResult.data || []).map(normalizePlatformCompany);
      state.companies = mergeCompanies(state.companies.concat(state.platformCompanies.map((company) => normalizeCompany({
        id: company.company_id,
        name: company.company_name,
        short_name: company.short_name || company.company_name,
        color: company.color,
        label: company.label,
        pill: company.pill,
      }))));
      state.subscriptions = mergeSubscriptions(state.subscriptions.concat(state.platformCompanies.map(normalizeSubscription)));
    }
    if (!platformMembersResult.error) state.platformCompanyMembers = (platformMembersResult.data || []).map(normalizePlatformCompanyMember);
  }
  state.sync = { label: 'ROM Supabase limited', mode: 'live' };
}

function createSupabaseClient() {
  if (isReadOnlyDemo()) return null;
  if (!CONFIG.supabaseUrl || !CONFIG.supabaseKey) return null;
  if (!supabaseClientCache) {
    supabaseClientCache = createSupabaseJsClient(CONFIG.supabaseUrl, CONFIG.supabaseKey);
  }
  return supabaseClientCache;
}

function safeSupabaseQuery(query) {
  return Promise.resolve(query).catch((error) => ({ error }));
}

