  state.forms = activeRows(readDemoList(FORM_CACHE_KEY, formsFallback)).map(normalizeForm);
  state.formResponses = activeRows(readDemoList(FORM_RESPONSE_CACHE_KEY, formResponsesFallback)).map(normalizeFormResponse);
