function estimateDraftFromForm(form) {
  const data = new FormData(form);
  const toLines = (prefix) => {
    const names = data.getAll(`${prefix}_name`);
    const quantities = data.getAll(`${prefix}_quantity`);
    const prices = data.getAll(`${prefix}_unit_price`);
    return names.map((name, index) => ({
      name: String(name || '').trim(),
      quantity: number(quantities[index]),
      unitPrice: number(prices[index]),
    })).filter((item) => item.name || item.quantity || item.unitPrice);
  };
  return {
    name: String(data.get('name') || '').trim(),
    primary: estimateSystemKey(data.get('primary')),
    projectType: String(data.get('project_type') || 'rr'),
    squares: number(data.get('squares')),
    commissionRate: number(data.get('commission_rate')),
    targetMargin: number(data.get('target_margin')),
    quote: number(data.get('quote')),
    labor: toLines('labor'),
    materials: toLines('material'),
    notes: String(data.get('notes') || '').trim(),
  };
}

function updateEstimateBuilderPreview(form) {
  if (!form) return;
  const preview = form.querySelector('[data-estimate-preview]');
  if (!preview) return;
  const draft = estimateDraftFromForm(form);
  preview.innerHTML = estimateMetricGrid(draft, calculateEstimateTotals(draft));
}

function estimateActivityBody(draft, totals) {
  const system = ROOF_ESTIMATE_SYSTEMS[draft.primary]?.label || titleCase(draft.primary);
  const projectType = draft.projectType === 'new' ? 'New construction' : 'R&R';
  const nonZeroLines = draft.labor.concat(draft.materials).filter((line) => number(line.quantity) || number(line.unitPrice));
  const lineSummary = nonZeroLines.slice(0, 8).map((line) => `${line.name}: ${line.quantity} x ${money(line.unitPrice)}`).join('\n');
  return [
    `${system} ${projectType} estimate`,
    `Squares: ${draft.squares || 0}`,
    `Quote: ${money(draft.quote || 0)}`,
    `Hard cost: ${money(totals.hardCost)} (labor ${money(totals.laborTotal)}, materials ${money(totals.materialTotal)})`,
    `Net profit: ${money(totals.netProfit)} / ${totals.netMargin.toFixed(1)}%`,
    `Payments: deposit ${money(totals.deposit)}, material drop ${money(totals.materialDrop)}, completion ${money(totals.completion)}`,
    draft.notes ? `Notes: ${draft.notes}` : '',
    lineSummary ? `Lines:\n${lineSummary}${nonZeroLines.length > 8 ? '\n...' : ''}` : '',
  ].filter(Boolean).join('\n');
}

async function saveBuiltEstimate(form) {
  const data = new FormData(form);
  const type = String(data.get('related_type') || '');
  const id = String(data.get('related_id') || '');
  const ctx = estimateContext(type, id);
  if (!ctx) throw new Error('Estimate record was not found.');
  if (!requirePermission(type === 'job' ? 'jobs.manage' : 'crm.view', ctx.company_id, 'Your role cannot save estimates here.', 'Estimate')) return;
  const draft = estimateDraftFromForm(form);
  const initialTotals = calculateEstimateTotals(draft);
  if (!draft.quote && initialTotals.targetQuote > 0) draft.quote = Math.round(initialTotals.targetQuote);
  const totals = calculateEstimateTotals(draft);
  const quoteTotal = roundCurrency(draft.quote || 0);
  const body = estimateActivityBody(draft, totals);
  if (type === 'contact') {
    const contact = contactById(id);
    if (!await persistContact({ ...contact, value: quoteTotal, roof_system: ROOF_ESTIMATE_SYSTEMS[draft.primary]?.label || draft.primary })) return false;
    await logContactActivity(id, 'system', `Estimate saved - ${money(quoteTotal)}`, body);
  } else if (type === 'deal') {
    const deal = dealById(id);
    const estimateStage = dealStageNames().find((stage) => /estimate|proposal/i.test(stage));
    if (!await persistDeal({ ...deal, value: quoteTotal, stage: estimateStage || deal.stage }, 'Estimate saved to quote.')) return false;
    await logDealActivity(id, 'system', `Estimate saved - ${money(quoteTotal)}`, body);
  } else if (type === 'job') {
    const job = jobById(id);
    if (!await persistJob({ ...job, estimate_total: quoteTotal }, 'Estimate saved to job.')) return false;
    await logJobActivity(id, 'system', `Estimate saved - ${money(quoteTotal)}`, body);
  }
  state.modal = '';
  state.estimateContext = null;
  showToast(`Estimate saved at ${money(quoteTotal)}.`, 'live', 'Estimate');
  render();
}

function openEstimateBuilder(type, id) {
  const ctx = estimateContext(type, id);
  if (!ctx) return;
  state.estimateContext = { type, id };
  state.modal = 'estimate-builder';
  render();
}

function proposalTemplateById(id) {
  return PROPOSAL_TEMPLATES.find((template) => template.id === id) || PROPOSAL_TEMPLATES[0];
}

function normalizeProposal(input = {}) {
  const status = PROPOSAL_STATUS_OPTIONS.includes(input.status) ? input.status : 'Draft';
  const draft = input.draft && typeof input.draft === 'object' ? input.draft : {};
  const client = input.client && typeof input.client === 'object' ? input.client : draft.client || {};
  return {
    id: String(input.id || ''),
    company_id: canonicalCompanyId(input.company_id || defaultCompanyId()),
    proposal_no: String(input.proposal_no || draft.proposalNo || '').trim(),
    title: String(input.title || draft.jobTitle || 'Proposal').trim(),
    status,
    related_type: ['contact', 'deal', 'job'].includes(input.related_type) ? input.related_type : 'deal',
    related_id: input.related_id ? String(input.related_id) : '',
    contact_id: input.contact_id ? String(input.contact_id) : '',
    deal_id: input.deal_id ? String(input.deal_id) : '',
    job_id: input.job_id ? String(input.job_id) : '',
    client: {
      name: String(client.name || '').trim(),
      email: String(client.email || '').trim(),
      phone: String(client.phone || '').trim(),
      address: String(client.address || '').trim(),
    },
    draft: { ...draft },
    total: number(input.total ?? draft.total),
    public_token: String(input.public_token || ''),
    accepted_by: String(input.accepted_by || '').trim(),
    accepted_email: String(input.accepted_email || '').trim(),
    accepted_at: input.accepted_at || null,
    declined_at: input.declined_at || null,
    viewed_at: input.viewed_at || null,
    sent_at: input.sent_at || null,
    created_by: String(input.created_by || ''),
    created_by_label: String(input.created_by_label || '').trim(),
    created_at: input.created_at || new Date().toISOString(),
    updated_at: input.updated_at || new Date().toISOString(),
  };
}

function proposalById(id) {
  return id ? state.proposals.find((proposal) => proposal.id === id) || null : null;
}

function companyProposals(companyId = activeCompanyId()) {
  return state.proposals
    .filter((proposal) => proposal.company_id === companyId)
    .sort((a, b) => Date.parse(b.updated_at || 0) - Date.parse(a.updated_at || 0));
}

function proposalsFor(relatedType, relatedId) {
  if (!relatedId) return [];
  return state.proposals
    .filter((proposal) => proposal.related_type === relatedType && proposal.related_id === relatedId)
    .sort((a, b) => Date.parse(b.updated_at || 0) - Date.parse(a.updated_at || 0));
}

function proposalPublicUrl(proposal) {
  return proposal?.public_token ? `${window.location.origin}${appHref(`/proposal/${encodeURIComponent(proposal.public_token)}`)}` : '';
}

function proposalToken() {
  return `prop_${crypto.randomUUID().replace(/-/g, '')}`;
}

function proposalContext(type, id) {
  if (type === 'contact') {
    const contact = contactById(id);
    if (!contact) return null;
    return {
      type,
      id,
      company_id: contact.company_id,
      label: 'Contact',
      title: contact.name,
      client: { name: contact.name, email: contact.email, phone: contact.phone, address: contact.location },
      total: contact.value || 0,
      jobTitle: contact.title || 'Roofing Proposal',
      account_id: contact.account_id,
    };
  }
  if (type === 'deal') {
    const deal = dealById(id);
    if (!deal) return null;
    const contact = contactById(deal.primary_contact_id);
    const account = accountById(deal.account_id);
    return {
      type,
      id,
      company_id: deal.company_id,
      label: 'Quote',
      title: deal.name,
      client: {
        name: contact?.name || account?.name || deal.name,
        email: contact?.email || account?.email || '',
        phone: contact?.phone || account?.phone || '',
        address: account?.address || contact?.location || '',
      },
      total: deal.value || 0,
      jobTitle: deal.name,
      account_id: deal.account_id,
    };
  }
  if (type === 'job') {
    const job = jobById(id);
    if (!job) return null;
    return {
      type,
      id,
      company_id: job.company_id,
      label: 'Job',
      title: job.name,
      client: { name: job.client_name || job.contact_name, email: '', phone: '', address: job.site_address },
      total: job.estimate_total || 0,
      jobTitle: job.name,
      account_id: job.account_id,
    };
  }
  return null;
}

function currentProposalContext() {
  const ctx = state.proposalContext || {};
  if (ctx.proposalId) {
    const proposal = proposalById(ctx.proposalId);
    if (proposal) {
      const base = proposalContext(proposal.related_type, proposal.related_id) || {
        type: proposal.related_type,
        id: proposal.related_id,
        company_id: proposal.company_id,
        label: 'Proposal',
        title: proposal.title,
        client: proposal.client,
        total: proposal.total,
        jobTitle: proposal.title,
        account_id: '',
      };
      return {
        ...base,
        templateId: proposal.draft?.templateId || ctx.template || PROPOSAL_TEMPLATES[0].id,
        proposalId: proposal.id,
      };
    }
  }
  const base = proposalContext(ctx.type, ctx.id);
  if (!base) return null;
  return { ...base, templateId: ctx.template || PROPOSAL_TEMPLATES[0].id };
}

function proposalDraftForContext(ctx) {
  if (ctx.proposalId) {
    const proposal = proposalById(ctx.proposalId);
    if (proposal?.draft) return { ...proposal.draft, client: { ...(proposal.draft.client || proposal.client) } };
  }
  const template = proposalTemplateById(ctx.templateId);
  return {
    ...DEFAULT_PROPOSAL_PREMIUM,
    style: 'premium',
    templateId: template.id,
    templateName: template.name,
    issued: isoDate(0),
    valid: isoDate(14),
    proposalNo: `QR-${String(new Date().getFullYear()).slice(2)}-${String(ctx.id || '').slice(-5).toUpperCase() || 'NEW'}`,
    client: ctx.client,
    jobTitle: ctx.jobTitle || template.jobTitle,
    includes: 'Includes - Labor & Materials',
    total: ctx.total || 0,
    items: template.items.map(([service, description, star]) => ({ service, description, star })),
  };
}

function proposalDraftFromForm(form) {
  const data = new FormData(form);
  const services = data.getAll('scope_service');
  const descriptions = data.getAll('scope_description');
  return {
    style: String(data.get('style') || 'premium'),
    templateId: String(data.get('template_id') || PROPOSAL_TEMPLATES[0].id),
    proposalNo: String(data.get('proposal_no') || '').trim(),
    issued: String(data.get('issued') || isoDate(0)),
    valid: String(data.get('valid') || isoDate(14)),
    client: {
      name: String(data.get('client_name') || '').trim(),
      email: String(data.get('client_email') || '').trim(),
      phone: String(data.get('client_phone') || '').trim(),
      address: String(data.get('client_address') || '').trim(),
    },
    jobTitle: String(data.get('job_title') || '').trim(),
    includes: String(data.get('includes') || '').trim() || 'Includes - Labor & Materials',
    total: number(data.get('total')),
    monthly: String(data.get('monthly') || '').trim(),
    deposit: number(data.get('deposit')),
    warranty: String(data.get('warranty') || '').trim(),
    manufacturerWarranty: String(data.get('manufacturer_warranty') || '').trim(),
    materials: String(data.get('materials') || '').trim(),
    terms: String(data.get('terms') || '').trim(),
    items: services.map((service, index) => ({
      service: String(service || '').trim(),
      description: String(descriptions[index] || '').trim(),
      star: data.get(`scope_star_${index}`) === 'on',
    })).filter((item) => item.service || item.description),
  };
}

function proposalRecordFromDraft(ctx, draft, existing = null) {
  const now = new Date().toISOString();
  const relatedType = ctx.type || existing?.related_type || 'deal';
  const relatedId = ctx.id || existing?.related_id || '';
  const record = normalizeProposal({
    ...(existing || {}),
    id: existing?.id || `proposal-${crypto.randomUUID()}`,
    company_id: ctx.company_id || existing?.company_id || activeCompanyId(),
    proposal_no: draft.proposalNo,
    title: draft.jobTitle || existing?.title || 'Proposal',
    status: existing?.status || 'Draft',
    related_type: relatedType,
    related_id: relatedId,
    contact_id: relatedType === 'contact' ? relatedId : existing?.contact_id || (relatedType === 'deal' ? dealById(relatedId)?.primary_contact_id : ''),
    deal_id: relatedType === 'deal' ? relatedId : existing?.deal_id || (relatedType === 'job' ? jobById(relatedId)?.deal_id : ''),
    job_id: relatedType === 'job' ? relatedId : existing?.job_id || (relatedType === 'deal' ? dealById(relatedId)?.job_id : ''),
    client: draft.client,
    draft,
    total: draft.total || 0,
    public_token: existing?.public_token || proposalToken(),
    created_by: existing?.created_by || activeSession().profile.id || '',
    created_by_label: existing?.created_by_label || activeSession().profile.full_name || '',
    created_at: existing?.created_at || now,
    updated_at: now,
  });
  return record;
}

function proposalDraftFromRecord(proposal) {
  return {
    ...DEFAULT_PROPOSAL_PREMIUM,
    ...(proposal?.draft || {}),
    client: { ...(proposal?.client || {}), ...(proposal?.draft?.client || {}) },
    total: number(proposal?.total ?? proposal?.draft?.total),
    proposalNo: proposal?.proposal_no || proposal?.draft?.proposalNo || '',
    jobTitle: proposal?.title || proposal?.draft?.jobTitle || 'Proposal',
  };
}

function renderProposalScopeRows(items) {
  return items.map((item, index) => `
    <div class="proposal-scope-row">
      <label class="proposal-star"><input data-proposal-field type="checkbox" name="scope_star_${index}" ${item.star ? 'checked' : ''} /><span>*</span></label>
      <input data-proposal-field name="scope_service" value="${h(item.service)}" aria-label="Scope service ${index + 1}" />
      <input data-proposal-field name="scope_description" value="${h(item.description)}" aria-label="Scope description ${index + 1}" />
    </div>
  `).join('');
}

function renderProposalPreview(draft) {
  const valid = draft.valid || isoDate(14);
  const depositAmount = roundCurrency((draft.total || 0) * (number(draft.deposit) / 100));
  const scope = draft.items.map((item) => `<li>${item.star ? '<b>*</b> ' : ''}${h(item.service)}${item.description ? `<span>${h(item.description)}</span>` : ''}</li>`).join('');
  const materials = String(draft.materials || '').split('\n').map((line) => line.trim()).filter(Boolean)
    .map((line) => {
      const [name, ...rest] = line.split(' - ');
      return `<div><b>${h(name)}</b><span>${h(rest.join(' - '))}</span></div>`;
    }).join('');
  return `
    <article class="proposal-preview-sheet ${draft.style === 'simple' ? 'simple' : 'premium'}">
      <header>
        <div><strong>ROM Roofing</strong><span>Proposal - ${h(draft.proposalNo || 'Draft')}</span></div>
        <b>${h(money(draft.total || 0))}</b>
      </header>
      <section class="proposal-hero">
        <div>
          <small>${draft.style === 'premium' ? 'On a ROM to serve you better' : 'Prepared proposal'}</small>
          <h3>${h(draft.jobTitle || 'Proposal')}</h3>
          <p>Prepared for ${h(draft.client.name || 'Client')} ${draft.client.address ? `at ${h(draft.client.address)}` : ''}</p>
        </div>
        <div class="proposal-investment">
          <span>Your investment</span>
          <strong>${h(money(draft.total || 0))}</strong>
          ${draft.monthly ? `<em>or as low as $${h(String(draft.monthly).replace(/^\$/, ''))}/mo with financing</em>` : ''}
        </div>
      </section>
      <section>
        <h4>Scope of work</h4>
        <ul class="proposal-scope-preview">${scope || '<li>Scope lines will appear here.</li>'}</ul>
      </section>
      ${draft.style === 'premium' ? `<section class="proposal-materials"><h4>Built to last</h4><div>${materials}</div></section>` : ''}
      <section class="proposal-warranty">
        <div><b>${h(draft.warranty || DEFAULT_PROPOSAL_PREMIUM.warranty)}</b><span>ROM craftsmanship warranty</span></div>
        <div><b>${h(draft.manufacturerWarranty || DEFAULT_PROPOSAL_PREMIUM.manufacturerWarranty)}</b><span>Material protection</span></div>
      </section>
      <section class="proposal-accept">
        <h4>Ready to move forward?</h4>
        <p>Sign to lock in your price and schedule.${draft.deposit ? ` A ${draft.deposit}% deposit reserves your install date (${money(depositAmount)}).` : ''}</p>
        <div><span>Customer signature & date</span><span>Valid through ${h(formatDate(valid))}</span></div>
      </section>
    </article>
  `;
}

function updateProposalBuilderPreview(form) {
  if (!form) return;
  const preview = form.querySelector('[data-proposal-preview]');
  if (preview) preview.innerHTML = renderProposalPreview(proposalDraftFromForm(form));
}

function renderProposalBuilderModal(companyId) {
  const ctx = currentProposalContext();
  if (!ctx || ctx.company_id !== companyId) return renderModalShell('Job Center', 'Proposal', emptyState('Choose a contact, quote, or job before creating a proposal.'));
  const draft = proposalDraftForContext(ctx);
  const addressOptions = contactAddressOptions(companyId);
  const saved = proposalsFor(ctx.type, ctx.id);
  const activeProposal = ctx.proposalId ? proposalById(ctx.proposalId) : null;
  const savedPanel = saved.length ? `
    <section class="proposal-history">
      <div><strong>Saved proposals</strong><small>Reuse, edit, or export past versions.</small></div>
      ${saved.slice(0, 5).map((proposal) => `
        <button class="${proposal.id === ctx.proposalId ? 'active' : ''}" type="button" data-action="edit-proposal" data-proposal-id="${h(proposal.id)}">
          <span>${h(proposal.proposal_no || proposal.title)}</span>
          <em>${h(proposal.status)} - ${h(money(proposal.total))}</em>
        </button>
      `).join('')}
    </section>
  ` : '';
  return renderModalShell('Job Center', `${ctx.label} proposal`, `
    <form id="proposal-builder-form" class="proposal-builder" data-proposal-builder-form>
      <input type="hidden" name="proposal_id" value="${h(ctx.proposalId || '')}" />
      <input type="hidden" name="related_type" value="${h(ctx.type)}" />
      <input type="hidden" name="related_id" value="${h(ctx.id)}" />
      <section class="proposal-builder-rail">
        ${savedPanel}
        <label><span>Template</span><select data-proposal-template name="template_id">${PROPOSAL_TEMPLATES.map((template) => `<option value="${h(template.id)}" ${template.id === draft.templateId ? 'selected' : ''}>${h(template.name)}</option>`).join('')}</select></label>
        <label><span>Style</span><select data-proposal-field name="style"><option value="premium" ${draft.style !== 'simple' ? 'selected' : ''}>Premium</option><option value="simple" ${draft.style === 'simple' ? 'selected' : ''}>Simple</option></select></label>
        <label><span>Proposal #</span><input data-proposal-field name="proposal_no" value="${h(draft.proposalNo)}" /></label>
        <div class="proposal-two"><label><span>Issued</span><input data-proposal-field name="issued" type="date" value="${h(draft.issued)}" /></label><label><span>Valid through</span><input data-proposal-field name="valid" type="date" value="${h(draft.valid)}" /></label></div>
        <label><span>Client name</span><input data-proposal-field name="client_name" value="${h(draft.client.name)}" /></label>
        <label><span>Client email</span><input data-proposal-field name="client_email" value="${h(draft.client.email)}" /></label>
        <label><span>Client phone</span><input data-proposal-field name="client_phone" value="${h(draft.client.phone)}" /></label>
        ${renderAddressLookupField('Client address', 'client_address', draft.client.address, addressOptions, '', 'proposal-client-address-options', 'data-proposal-field')}
        <label><span>Job title</span><input data-proposal-field name="job_title" value="${h(draft.jobTitle)}" /></label>
        <label><span>Total</span><input data-proposal-field name="total" type="number" step="0.01" value="${h(String(draft.total || ''))}" /></label>
        <div class="proposal-two"><label><span>Monthly</span><input data-proposal-field name="monthly" value="${h(draft.monthly)}" /></label><label><span>Deposit %</span><input data-proposal-field name="deposit" type="number" step="1" value="${h(String(draft.deposit))}" /></label></div>
        <label><span>Includes row</span><input data-proposal-field name="includes" value="${h(draft.includes)}" /></label>
        <label><span>Warranty</span><input data-proposal-field name="warranty" value="${h(draft.warranty)}" /></label>
        <label><span>Manufacturer warranty</span><input data-proposal-field name="manufacturer_warranty" value="${h(draft.manufacturerWarranty)}" /></label>
        <label><span>Materials</span><textarea data-proposal-field name="materials">${h(draft.materials)}</textarea></label>
        <label><span>Terms</span><textarea data-proposal-field name="terms">${h(draft.terms)}</textarea></label>
        <section class="proposal-scope-editor"><div><strong>Scope lines</strong><small>Asterisk marks featured items.</small></div>${renderProposalScopeRows(draft.items)}</section>
      </section>
      <section class="proposal-builder-preview" data-proposal-preview>${renderProposalPreview(draft)}</section>
    </form>
  `, 'proposal-modal', `
    ${activeProposal ? `<button class="btn" type="button" data-action="export-proposal" data-proposal-id="${h(activeProposal.id)}"><i class="ti ti-download"></i>Export</button>` : ''}
    <button class="btn btn-primary" type="submit" form="proposal-builder-form"><i class="ti ti-file-text"></i>${activeProposal ? 'Update proposal' : 'Save proposal'}</button>
  `);
}

function proposalActivityBody(draft) {
  const scope = draft.items.slice(0, 12).map((item) => `${item.star ? '* ' : ''}${item.service}${item.description ? ' - ' + item.description : ''}`).join('\n');
  return [
    `Proposal: ${draft.jobTitle || 'Proposal'}`,
    `Total: ${money(draft.total || 0)}`,
    draft.monthly ? `Financing: ${draft.monthly}/mo` : '',
    draft.deposit ? `Deposit: ${draft.deposit}% (${money((draft.total || 0) * draft.deposit / 100)})` : '',
    `Valid through: ${formatDate(draft.valid)}`,
    draft.warranty ? `Warranty: ${draft.warranty}` : '',
    scope ? `Scope:\n${scope}` : '',
  ].filter(Boolean).join('\n');
}

async function saveBuiltProposal(form) {
  const data = new FormData(form);
  const type = String(data.get('related_type') || '');
  const id = String(data.get('related_id') || '');
  const proposalId = String(data.get('proposal_id') || '');
  const ctx = proposalContext(type, id);
  if (!ctx) throw new Error('Proposal record was not found.');
  if (!requirePermission(type === 'job' ? 'jobs.manage' : 'crm.view', ctx.company_id, 'Your role cannot save proposals here.', 'Proposal')) return;
  const draft = proposalDraftFromForm(form);
  const total = roundCurrency(draft.total || 0);
  const body = proposalActivityBody(draft);
  const existing = proposalId ? proposalById(proposalId) : null;
  const savedProposal = await persistProposal(proposalRecordFromDraft(ctx, draft, existing), existing ? 'Proposal updated.' : 'Proposal saved.');
  if (!savedProposal) return false;
  if (type === 'contact') {
    const contact = contactById(id);
    if (!await persistContact({ ...contact, value: total })) return false;
    await logContactActivity(id, 'email', `${existing ? 'Proposal updated' : 'Proposal prepared'} - ${money(total)}`, `${body}\n\nProposal ID: ${savedProposal.id}`);
  } else if (type === 'deal') {
    const deal = dealById(id);
    const proposalStage = dealStageNames().find((stage) => /estimate|proposal/i.test(stage));
    if (!await persistDeal({ ...deal, value: total, stage: proposalStage || deal.stage }, 'Proposal saved to quote.')) return false;
    await logDealActivity(id, 'email', `${existing ? 'Proposal updated' : 'Proposal prepared'} - ${money(total)}`, `${body}\n\nProposal ID: ${savedProposal.id}`);
  } else if (type === 'job') {
    const job = jobById(id);
    if (!await persistJob({ ...job, estimate_total: total }, 'Proposal saved to job.')) return false;
    await logJobActivity(id, 'email', `${existing ? 'Proposal updated' : 'Proposal prepared'} - ${money(total)}`, `${body}\n\nProposal ID: ${savedProposal.id}`);
  }
  state.modal = '';
  state.proposalContext = null;
  state.selectedProposalId = savedProposal.id;
  navigate(companyPath('proposals', { proposal_id: savedProposal.id }, ctx.company_id));
}

function openProposalBuilder(type, id, proposalId = '') {
  const ctx = proposalContext(type, id);
  if (!ctx) return;
  state.proposalContext = { type, id, proposalId };
  state.modal = 'proposal-builder';
  render();
}

function openProposalEdit(proposalId) {
  const proposal = proposalById(proposalId);
  if (!proposal) return showToast('Proposal not found.', 'local', 'Proposals');
  openProposalBuilder(proposal.related_type, proposal.related_id, proposal.id);
}

async function duplicateProposal(proposalId) {
  const source = proposalById(proposalId);
  if (!source) return showToast('Choose a proposal to reuse first.', 'local', 'Proposals');
  if (!requirePermission(source.related_type === 'job' ? 'jobs.manage' : 'crm.view', source.company_id, 'Your role cannot duplicate proposals here.', 'Proposal')) return;
  const draft = proposalDraftFromRecord(source);
  const copy = normalizeProposal({
    ...source,
    id: `proposal-${crypto.randomUUID()}`,
    proposal_no: `${source.proposal_no || 'QR'}-COPY`,
    title: `${source.title} copy`,
    status: 'Draft',
    public_token: proposalToken(),
    accepted_by: '',
    accepted_email: '',
    accepted_at: null,
    declined_at: null,
    viewed_at: null,
    sent_at: null,
    draft: { ...draft, proposalNo: `${source.proposal_no || 'QR'}-COPY` },
    created_at: new Date().toISOString(),
    updated_at: new Date().toISOString(),
  });
  const saved = await persistProposal(copy, 'Proposal duplicated.');
  if (!saved) return false;
  await logActivity({ type: 'system', subject: 'Proposal reused', body: `Copied from ${source.proposal_no || source.id}`, related_type: saved.related_type, related_id: saved.related_id });
  state.selectedProposalId = saved.id;
  navigate(companyPath('proposals', { proposal_id: saved.id }, saved.company_id));
}

async function setProposalStatus(proposalId, status, label = 'Proposal status saved.') {
  const proposal = proposalById(proposalId);
  if (!proposal || !PROPOSAL_STATUS_OPTIONS.includes(status)) return;
  if (!requirePermission(proposal.related_type === 'job' ? 'jobs.manage' : 'crm.view', proposal.company_id, 'Your role cannot update proposal status.', 'Proposal')) return;
  const now = new Date().toISOString();
  const updates = { status };
  if (status === 'Sent' && !proposal.sent_at) updates.sent_at = now;
  if (status === 'Viewed' && !proposal.viewed_at) updates.viewed_at = now;
  if (status === 'Accepted' && !proposal.accepted_at) updates.accepted_at = now;
  if (status === 'Declined' && !proposal.declined_at) updates.declined_at = now;
  const saved = await persistProposal({ ...proposal, ...updates }, label);
  if (!saved) return false;
  await logActivity({ type: 'system', subject: `Proposal ${status}`, body: `${saved.proposal_no || saved.title} is now ${status}.`, related_type: saved.related_type, related_id: saved.related_id });
  state.selectedProposalId = saved.id;
  render();
}

function copyProposalApprovalLink(proposalId) {
  const proposal = proposalById(proposalId);
  const url = proposalPublicUrl(proposal);
  if (!url) return showToast('This proposal does not have an approval link.', 'local', 'Proposals');
  navigator.clipboard?.writeText(url).then(
    () => showToast('Approval link copied.', 'live', 'Proposals'),
    () => showToast(url, 'local', 'Approval link')
  );
  if (proposal.status === 'Draft') setProposalStatus(proposal.id, 'Sent', 'Proposal marked sent.');
}

async function exportProposalPdf(proposalId) {
  const proposal = proposalById(proposalId) || state.proposalPublic?.proposal;
  if (!proposal) throw new Error('Proposal not found.');
  const draft = proposalDraftFromRecord(proposal);
  await loadExternalScript('https://cdnjs.cloudflare.com/ajax/libs/jspdf/2.5.1/jspdf.umd.min.js', 'jspdf');
  const pdf = new window.jspdf.jsPDF({ unit: 'pt', format: 'letter' });
  const pageWidth = 612;
  const margin = 42;
  let y = 54;
  pdf.setFillColor(26, 43, 74);
  pdf.rect(0, 0, pageWidth, 102, 'F');
  pdf.setTextColor(255, 255, 255);
  pdf.setFont('helvetica', 'bold');
  pdf.setFontSize(24);
  pdf.text('ROM Roofing', margin, y);
  pdf.setFontSize(10);
  pdf.text(`Proposal - ${draft.proposalNo || proposal.proposal_no || proposal.id}`, margin, y + 20);
  pdf.setFontSize(26);
  pdf.text(money(draft.total || 0), pageWidth - margin, y, { align: 'right' });
  y = 138;
  pdf.setTextColor(232, 97, 26);
  pdf.setFontSize(11);
  pdf.text(String(draft.tagline || 'On a ROM to serve you better').toUpperCase(), margin, y);
  pdf.setTextColor(20, 28, 45);
  pdf.setFontSize(18);
  pdf.text(draft.jobTitle || proposal.title || 'Proposal', margin, y + 22);
  pdf.setFont('helvetica', 'normal');
  pdf.setFontSize(11);
  const prepared = `Prepared for ${draft.client?.name || 'Client'}${draft.client?.address ? ` at ${draft.client.address}` : ''}`;
  pdf.text(pdf.splitTextToSize(prepared, pageWidth - margin * 2), margin, y + 42);
  y += 84;
  pdf.setFont('helvetica', 'bold');
  pdf.setFontSize(14);
  pdf.text('Scope of work', margin, y);
  y += 22;
  pdf.setFont('helvetica', 'normal');
  pdf.setFontSize(10);
  (draft.items || []).forEach((item) => {
    const line = `${item.star ? '* ' : ''}${item.service}${item.description ? ` - ${item.description}` : ''}`;
    const lines = pdf.splitTextToSize(line, pageWidth - margin * 2 - 18);
    if (y + lines.length * 13 > 742) {
      pdf.addPage();
      y = 54;
    }
    pdf.text('- ', margin, y);
    pdf.text(lines, margin + 16, y);
    y += lines.length * 13 + 4;
  });
  y += 12;
  if (y > 660) {
    pdf.addPage();
    y = 54;
  }
  pdf.setFont('helvetica', 'bold');
  pdf.setFontSize(13);
  pdf.text('Warranty and terms', margin, y);
  y += 18;
  pdf.setFont('helvetica', 'normal');
  pdf.setFontSize(10);
  const terms = [
    draft.warranty || DEFAULT_PROPOSAL_PREMIUM.warranty,
    draft.manufacturerWarranty || DEFAULT_PROPOSAL_PREMIUM.manufacturerWarranty,
    draft.terms || DEFAULT_PROPOSAL_PREMIUM.terms,
    draft.deposit ? `Deposit due at approval: ${draft.deposit}% (${money((draft.total || 0) * draft.deposit / 100)}).` : '',
    `Valid through ${formatDate(draft.valid)}.`,
  ].filter(Boolean).join('\n');
  pdf.text(pdf.splitTextToSize(terms, pageWidth - margin * 2), margin, y);
  pdf.save(`ROMIO-Proposal-${slugify(proposal.proposal_no || proposal.id)}.pdf`);
}

function renderTaskRouteModal(route, companyId) {
  const job = route.jobId ? jobById(route.jobId) : null;
  const taskId = route.params.get('task_id') || '';
  const task = taskId ? taskById(taskId) : null;
  if (route.params.get('new') === '1') {
    return renderModalShell('Tasks', 'New task', renderTaskForm(companyId, job, null), 'task-modal');
  }
  if (route.params.get('edit') === '1' && task) {
    return renderModalShell('Tasks', 'Edit task', renderTaskForm(companyId, job, task), 'task-modal');
  }
  if (task) {
    return renderDrawerShell('Task detail', task.title, renderTaskDetail(companyId, task));
  }
  return '';
}

function renderCalendarEventDetailModal(companyId) {
  const item = calendarEventByKey(state.selectedCalendarEventId, companyId);
  if (!item) return '';
  const manual = item.source === 'manual' ? manualCalendarEventById(item.sourceId) : null;
  const actions = [
    item.href ? `<a class="btn btn-primary" href="${appHref(item.href)}" data-router><i class="ti ti-arrow-right"></i>Open source</a>` : '',
    manual && item.editable ? `<button class="btn" type="button" data-action="edit-calendar-event" data-event-id="${h(manual.id)}"><i class="ti ti-pencil"></i>Edit</button>` : '',
    manual && item.editable ? `<button class="btn danger" type="button" data-action="delete-calendar-event" data-event-id="${h(manual.id)}"><i class="ti ti-trash"></i>Delete</button>` : '',
  ].filter(Boolean).join('');
  return renderModalShell('Calendar', item.title, `
    <div class="calendar-detail">
      ${contractRows([
        ['Type', item.type],
        ['When', item.allDay ? formatDate(item.dateKey) : `${formatDateTime(item.startsAt)}${item.endsAt && item.endsAt !== item.startsAt ? ` - ${formatDateTime(item.endsAt)}` : ''}`],
        ['Assigned', item.owner || 'Unassigned'],
        ['Source', item.source === 'manual' ? 'Manual event' : titleCase(item.source)],
        ['Linked', item.linkLabel || 'None'],
      ])}
      ${item.description ? `<p>${h(item.description)}</p>` : ''}
      <div class="modal-actions">${actions || '<span class="small-note">This derived item opens from its source module.</span>'}</div>
    </div>
  `, 'calendar-modal');
}

