function syncJobInvoiceTotal(jobId) {
  if (!jobId) return;
  const job = jobById(jobId);
  if (!job) return;
  job.invoice_total = sum(companyFinanceInvoices(job.company_id).filter((invoice) => invoice.job_id === jobId), 'total');
  job.updated_at = new Date().toISOString();
  upsertJob(job);
}

function updateWorkspaceOnly() {
  const workspace = document.getElementById('workspace');
  if (!workspace) return;
  reconcileSelection(state.route);
  workspace.innerHTML = renderWorkspace(state.route);
}

function rememberSidebarScroll() {
  const scrollTop = document.querySelector('.deck-scroll')?.scrollTop || 0;
  sessionStorage.setItem(SIDEBAR_SCROLL_KEY, String(scrollTop));
}

function restoreSidebarScroll() {
  const deckScroll = document.querySelector('.deck-scroll');
  if (!deckScroll) return;
  const scrollTop = Number(sessionStorage.getItem(SIDEBAR_SCROLL_KEY) || 0);
  if (Number.isFinite(scrollTop) && scrollTop > 0) deckScroll.scrollTop = scrollTop;
}

function getRoute() {
  const path = appPathname();
  const params = new URLSearchParams(window.location.search);
  if (path.startsWith('/portal/')) return { name: 'client-portal', path, params, section: 'client-portal', companyId: '', token: decodeURIComponent(path.replace(/^\/portal\//, '')), jobId: '' };
  if (path.startsWith('/proposal/')) return { name: 'proposal-public', path, params, section: 'proposal-public', companyId: '', token: decodeURIComponent(path.replace(/^\/proposal\//, '')), jobId: '' };
  if (path.startsWith('/form/')) return { name: 'form-public', path, params, section: 'form-public', companyId: '', token: decodeURIComponent(path.replace(/^\/form\//, '')), jobId: '' };
  if (path === '/login') return { name: 'login', path, params, section: '', companyId: '', jobId: '' };
  if (path === '/') return { name: 'home', path, params, section: '', companyId: '', jobId: '' };
  if (path === '/command') return { name: 'command', path, params, section: 'dashboard', companyId: activeCompanyId(), jobId: params.get('job_id') || '' };
  const companyMatch = path.match(/^\/company\/([^/]+)(?:\/([^/]+))?\/?$/);
  if (companyMatch) {
    const section = companyMatch[2] || 'dashboard';
    return {
      name: 'company',
      path,
      params,
      companyId: decodeURIComponent(companyMatch[1]),
      section,
      jobId: params.get('job_id') || '',
    };
  }
  return { name: path.replace(/^\//, '') || 'command', path, params, section: '', companyId: activeCompanyId(), jobId: params.get('job_id') || '' };
}

function normalizeLegacyLocation() {
  const path = appPathname();
  const params = new URLSearchParams(window.location.search);
  const companyId = params.get('company_id') || params.get('company') || companyIdForJob(params.get('job_id') || params.get('project_id')) || localStorage.getItem(COMPANY_KEY) || defaultCompanyId();
  const map = Object.fromEntries(Object.entries(LEGACY_ROUTE_SECTIONS).map(([legacyPath, section]) => [legacyPath, companyPath(section, {}, companyId)]));
  Object.assign(map, {
    '/index.html': '/',
    '/command.html': companyPath('dashboard', {}, companyId),
    '/login.html': '/login',
  });

  let target = map[path];
  if (path === '/jobs') {
    const tab = params.get('tab');
    if (tab === 'tasks') target = companyPath('tasks', copyParams(params, ['job_id', 'task_id', 'new', 'edit']), companyId);
    else if (tab === 'files') target = companyPath('files', copyParams(params, ['job_id', 'folder']), companyId);
    else if (tab === 'forms') target = companyPath('forms', copyParams(params, ['job_id']), companyId);
    else if (tab === 'analytics') target = companyPath('analytics', copyParams(params, ['job_id']), companyId);
    else target = companyPath('jobs', copyParams(params, ['job_id', 'tab']), companyId);
  }
  if (path === '/files') target = companyPath('files', copyParams(params, ['job_id', 'folder']), companyId);
  if (path === '/forms') target = companyPath('forms', copyParams(params, ['job_id']), companyId);
  if (path === '/analytics') target = companyPath('analytics', copyParams(params, ['job_id']), companyId);
  if (path === '/crm') target = companyPath('crm', copyParams(params, ['account']), companyId);
  if (path === '/underwriter') target = companyPath('underwriter', copyParams(params, ['stage']), companyId);
  if (path === '/finance') target = companyPath('finance', copyParams(params, ['invoice', 'expense', 'vendor', 'report']), companyId);
  if (path === '/messages') target = companyPath('messages', copyParams(params, ['conversation']), companyId);
  if (path === '/calendar') target = companyPath('calendar', {}, companyId);
  if (path === '/admin') target = companyPath('settings', {}, companyId);
  if (path === '/time') target = companyPath('time', {}, companyId);
  if (path === '/team') target = companyPath('team-chart', {}, companyId);
  if (path === '/team-chart') target = companyPath('team-chart', {}, companyId);
  if (path === '/approvals') target = companyPath('approvals', {}, companyId);
  if (path === '/clock') target = companyPath('clock', {}, companyId);
  if (path === '/task-management.html') {
    const jobId = params.get('project_id') || params.get('job_id') || '';
    target = companyPath('tasks', jobId ? { job_id: jobId } : {}, companyIdForJob(jobId) || companyId);
  }
  const jobTaskMatch = path.match(/^\/jobs\/([^/]+)\/tasks\/?$/);
  if (jobTaskMatch) {
    const jobId = decodeURIComponent(jobTaskMatch[1]);
    target = companyPath('tasks', { job_id: jobId }, companyIdForJob(jobId) || companyId);
  }

  if (!target) return;
  window.history.replaceState({}, '', appHref(target));
}

function routeRedirect(route) {
  if (route.name !== 'company') return '';
  // Standalone build: default every landing to the Workspace App Builder.
  if (route.section === 'home' || route.section === 'dashboard') {
    return companyPath('workspaces', Object.fromEntries(route.params.entries()), route.companyId);
  }
  const allowed = allowedCompanyIds();
  if (state.session?.auth === 'supabase' && !allowed.length) return null;
  if (!allowed.includes(route.companyId)) {
    if (state.session?.auth === 'supabase') return '';
    return companyPath(route.section || 'workspaces', Object.fromEntries(route.params.entries()), allowed[0] || defaultCompanyId());
  }
  const validSections = MODULE_REGISTRY.map((module) => module.id);
  if (!validSections.includes(route.section)) return companyPath('workspaces', {}, route.companyId);
  const jobCompanyId = route.jobId ? companyIdForJob(route.jobId) : '';
  if (jobCompanyId && jobCompanyId !== route.companyId && allowed.includes(jobCompanyId)) {
    return companyPath(route.section, Object.fromEntries(route.params.entries()), jobCompanyId);
  }
  return '';
}

function appPathname() {
  let path = window.location.pathname || '/';
  if (BASE_PATH && path.startsWith(BASE_PATH)) path = path.slice(BASE_PATH.length) || '/';
  if (!path.startsWith('/')) path = '/' + path;
  return path.replace(/\/+$/, '') || '/';
}

function appHref(path) {
  if (/^https?:\/\//i.test(path)) return path;
  const [rawPath, rawSearch = ''] = String(path || '/').split('?');
  const normalized = rawPath.startsWith('/') ? rawPath : '/' + rawPath;
  return `${BASE_PATH}${normalized}${rawSearch ? `?${rawSearch}` : ''}` || '/';
}

function navigate(path, options = {}) {
  rememberSidebarScroll();
  const href = /^https?:\/\//i.test(path) || path.startsWith(BASE_PATH + '/') || (BASE_PATH === '' && path.startsWith('/')) ? path : appHref(path);
  if (options.replace) window.history.replaceState({}, '', href);
  else window.history.pushState({}, '', href);
  render();
}

function currentAppUrl() {
  return `${appPathname()}${window.location.search}`;
}

function safeReturnUrl(value) {
  try {
    const url = new URL(value, window.location.origin);
    if (url.origin !== window.location.origin) return appHref(companyPath('jobs', {}, defaultCompanyId()));
    return `${url.pathname}${url.search}`;
  } catch {
    return appHref(companyPath('jobs', {}, defaultCompanyId()));
  }
}

function companyPath(section = 'jobs', params = {}, companyId = activeCompanyId()) {
  const search = new URLSearchParams(params);
  for (const [key, value] of [...search.entries()]) {
    if (value === undefined || value === null || value === '') search.delete(key);
  }
  return `/company/${encodeURIComponent(canonicalCompanyId(companyId || defaultCompanyId()))}/${section}${search.toString() ? `?${search.toString()}` : ''}`;
}

function routeTitle(route) {
  if (route.name === 'home') return 'ROM';
  if (route.name === 'company') return titleCase(route.section);
  if (route.name === 'command') return 'Company Dashboard';
  if (route.name === 'login') return 'Sign in';
  return titleCase(route.name || 'Workspace');
}

function isActiveNav(route, path) {
  const [targetPath] = path.split('?');
  const target = targetPath.match(/^\/company\/([^/]+)\/([^/]+)/);
  if (!target || route.name !== 'company') return false;
  return route.companyId === decodeURIComponent(target[1]) && route.section === target[2];
}

function normalizeJobTab(value) {
  return JOB_TABS.includes(value) ? value : 'pipeline';
}

function labelForTab(tab) {
  return {
    pipeline: 'Pipeline',
    list: 'List',
    profile: 'Profile',
  }[tab] || tab;
}

function reconcileCompany(route) {
  const target = route.companyId || state.activeCompanyId || defaultCompanyId();
  const allowed = allowedCompanyIds();
  state.activeCompanyId = allowed.includes(target) ? target : allowed[0] || defaultCompanyId();
  localStorage.setItem(COMPANY_KEY, state.activeCompanyId);
  applyPipelineStagesForCompany(state.activeCompanyId);
}

function reconcileSelection(route) {
  const companyId = activeCompanyId();
  if (route.jobId && companyJobs(companyId).some((job) => job.id === route.jobId)) state.selectedJobId = route.jobId;
  if (!state.selectedJobId || !companyJobs(companyId).some((job) => job.id === state.selectedJobId)) {
    state.selectedJobId = companyJobs(companyId)[0]?.id || '';
  }
  const taskId = route.params.get('task_id');
  if (taskId && companyTasks(companyId).some((task) => task.id === taskId)) state.selectedTaskId = taskId;
  if (route.section !== 'tasks') state.selectedTaskId = '';
  state.driveFolder = route.params.get('folder') || 'home';
}

function setActiveCompany(companyId) {
  const allowed = allowedCompanyIds();
  const target = canonicalCompanyId(companyId);
  const next = allowed.includes(target) ? target : allowed[0] || defaultCompanyId();
  state.activeCompanyId = next;
  localStorage.setItem(COMPANY_KEY, next);
  applyPipelineStagesForCompany(next);
  resetScopedUiState();
  const route = state.route || getRoute();
  const section = route.name === 'company' ? route.section : 'jobs';
  navigate(companyPath(section, {}, next));
}

function resetScopedUiState() {
  state.modal = '';
  state.selectedJobId = '';
  state.selectedTaskId = '';
  state.selectedFileId = '';
  state.selectedFormId = '';
  state.selectedQuestionId = '';
  state.selectedFinanceInvoiceId = '';
  state.selectedFinanceExpenseId = '';
  state.selectedFinanceVendorId = '';
  state.selectedCalendarEventId = '';
  state.query = '';
  state.fileQuery = '';
  state.formQuery = '';
  state.crmQuery = '';
  state.contactQuery = '';
  state.contactFilters = { ...CONTACT_FILTER_DEFAULTS };
  state.selectedContactId = '';
  state.contactStageFilter = 'all';
  state.dealQuery = '';
  state.selectedDealId = '';
  state.stageFilterDeals = 'all';
  state.proposalQuery = '';
  state.proposalStatusFilter = 'all';
  state.selectedProposalId = '';
  state.accountQuery = '';
  state.selectedAccountId = '';
  state.accountTypeFilter = 'all';
  state.accountTab = 'overview';
  state.stageFilter = 'all';
  state.crmStageFilter = 'all';
  state.crmOwnerFilter = 'all';
  state.taskStatusFilter = 'all';
  state.taskPriorityFilter = 'all';
  state.calendarQuery = '';
  state.calendarTypeFilter = 'all';
  state.calendarScope = 'company';
  state.fileCategoryFilter = 'All categories';
  state.formTypeFilter = 'all';
  state.formsTab = 'library';
  state.driveFolder = 'home';
}

function setSelectedJob(id) {
  const job = jobById(id);
  if (!job) return;
  state.selectedJobId = id;
  navigate(companyPath('jobs', { tab: 'profile', job_id: id }, job.company_id));
}

function setSelectedTask(id) {
  const task = taskById(id);
  if (!task) return;
  state.selectedTaskId = id;
  navigate(companyPath('tasks', { ...(task.project_id ? { job_id: task.project_id } : {}), task_id: id }, task.company_id));
}

function selectedJob() {
  return jobById(state.selectedJobId) || companyJobs(activeCompanyId())[0] || null;
}

function jobById(id) {
  return state.jobs.find((job) => job.id === id) || null;
}

function taskById(id) {
  return state.tasks.find((task) => task.id === id) || null;
}

function companyJobs(companyId = activeCompanyId()) {
  return state.jobs.filter((job) => job.company_id === companyId);
}

function companyTasks(companyId = activeCompanyId()) {
  return state.tasks.filter((task) => task.company_id === companyId);
}

function companyNotifications(companyId = activeCompanyId()) {
  const profileId = activeSession().profile.id;
  return state.notifications
    .filter((item) => item.company_id === companyId && item.recipient_profile_id === profileId)
    .sort((a, b) => Date.parse(b.created_at || 0) - Date.parse(a.created_at || 0));
}

function companyMessageConversations(companyId = activeCompanyId()) {
  const query = state.messageQuery.trim().toLowerCase();
  const filter = state.messageFilter || 'all';
  return state.messageConversations
    .filter((conversation) => conversation.company_id === companyId && canAccessConversation(conversation))
    .filter((conversation) => filter === 'all' || conversation.type === filter || (filter === 'groups' && conversation.type !== 'direct') || (filter === 'unread' && conversationUnreadCount(conversation.id) > 0))
    .filter((conversation) => {
      if (!query) return true;
      const messageMatch = conversationMessages(conversation.id).some((message) => message.body.toLowerCase().includes(query));
      return conversation.title.toLowerCase().includes(query) || messageMatch;
    })
    .sort((a, b) => Date.parse(b.last_message_at || b.updated_at || b.created_at || 0) - Date.parse(a.last_message_at || a.updated_at || a.created_at || 0));
}

function companyMessageUnreadCount(companyId = activeCompanyId()) {
  return companyMessageConversations(companyId).reduce((sum, conversation) => sum + conversationUnreadCount(conversation.id), 0);
}

function selectedConversation(companyId = activeCompanyId()) {
  const visible = companyMessageConversations(companyId);
  const routeId = state.route?.params?.get('conversation') || '';
  const candidate = routeId || state.selectedConversationId;
  return visible.find((conversation) => conversation.id === candidate) || visible[0] || null;
}

function conversationMessages(conversationId) {
  return state.messages
    .filter((message) => message.conversation_id === conversationId && !message.deleted_at)
    .sort((a, b) => Date.parse(a.created_at || 0) - Date.parse(b.created_at || 0));
}

function conversationAttachments(conversationId) {
  return state.messageAttachments.filter((attachment) => attachment.conversation_id === conversationId);
}

function messageAttachments(messageId) {
  return state.messageAttachments.filter((attachment) => attachment.message_id === messageId);
}

function conversationAccessRows(conversationId) {
  return state.messageAccess.filter((access) => access.conversation_id === conversationId);
}

function conversationRead(conversationId, profileId = activeSession().profile.id) {
  return state.messageReads.find((read) => read.conversation_id === conversationId && read.profile_id === profileId) || null;
}

function conversationUnreadCount(conversationId, profileId = activeSession().profile.id) {
  const readAt = Date.parse(conversationRead(conversationId, profileId)?.last_read_at || 0);
  return conversationMessages(conversationId).filter((message) => message.sender_profile_id !== profileId && Date.parse(message.created_at || 0) > readAt).length;
}

function canAccessConversation(conversation) {
  if (!conversation || !can('messages.view', conversation.company_id)) return false;
  const profile = activeSession().profile;
  const rows = conversationAccessRows(conversation.id);
  if (conversation.type === 'company' || rows.some((row) => row.target_type === 'all_company')) return true;
  const profileKeys = new Set([profile.id, profile.member_id, profile.email].filter(Boolean).map(String));
  if (rows.some((row) => row.target_type === 'profile' && profileKeys.has(row.target_id))) return true;
  const roleIds = [roleIdForName(conversation.company_id, roleForCompany(conversation.company_id)), ...state.roleAssignments.filter((item) => item.company_id === conversation.company_id && item.profile_id === profile.id).map((item) => item.role_id)];
  return rows.some((row) => row.target_type === 'role' && roleIds.includes(row.target_id));
}

function calendarItems(companyId = activeCompanyId()) {
  const manual = state.calendarEvents
    .filter((event) => event.company_id === companyId && canAccessCalendarEvent(event))
    .map(calendarManualItem);
  const tasks = companyTasks(companyId)
    .filter((task) => task.due && task.status !== 'done')
    .filter((task) => can('calendar.view_team', companyId) || taskAssignedToMe(task.assignee_id) || task.creator_id === activeSession().profile.member_id)
    .map(calendarTaskItem);
  const finance = can('finance.view', companyId)
    ? companyFinanceInvoices(companyId)
      .filter((invoice) => invoice.due_date && invoiceBalance(invoice.id) > 0)
      .map(calendarInvoiceItem)
    : [];
  const approvals = approvalItems(companyId)
    .filter((item) => item.type !== 'Access request' || can('users.manage', companyId))
    .map((item) => calendarApprovalItem(item, companyId));
  const timer = activeTimerForCompany(companyId);
  const time = timer && (can('calendar.view_team', companyId) || calendarPersonMatchesMe(timer.user_id)) ? [calendarTimerItem(timer)] : [];
  return manual.concat(tasks, finance, approvals, time).sort((a, b) => Date.parse(a.startsAt || 0) - Date.parse(b.startsAt || 0));
}

function filteredCalendarItems(companyId = activeCompanyId()) {
  const query = state.calendarQuery.trim().toLowerCase();
  return calendarItems(companyId)
    .filter((item) => state.calendarScope === 'company' || item.mine)
    .filter((item) => state.calendarTypeFilter === 'all' || item.type === state.calendarTypeFilter)
    .filter((item) => {
      if (!query) return true;
      return [item.title, item.description, item.type, item.owner, item.linkLabel]
        .some((value) => String(value || '').toLowerCase().includes(query));
    })
    .filter((item) => state.calendarView === 'list' || calendarItemInVisibleRange(item));
}

function calendarUpcomingItems(companyId = activeCompanyId()) {
  const now = Date.now();
  return calendarItems(companyId)
    .filter((item) => Date.parse(item.endsAt || item.startsAt || 0) >= now)
    .slice(0, 9);
}

function calendarManualItem(event) {
  const job = event.linked_type === 'job' ? jobById(event.linked_id) : null;
  return {
    id: `manual:${event.id}`,
    source: 'manual',
    sourceId: event.id,
    companyId: event.company_id,
    title: event.title,
    description: event.description,
    type: event.event_type,
    startsAt: event.starts_at,
    endsAt: event.ends_at || event.starts_at,
    allDay: event.all_day,
    dateKey: calendarDateKey(event.starts_at),
    owner: calendarPersonName(event.assigned_profile_id || event.created_by),
    mine: calendarPersonMatchesMe(event.assigned_profile_id) || event.created_by === activeSession().profile.id,
    href: calendarLinkedHref(event),
    linkLabel: job?.name || '',
    editable: canEditCalendarEvent(event),
  };
}

function calendarTaskItem(task) {
  const startsAt = task.due_time ? `${task.due}T${task.due_time}:00` : `${task.due}T12:00:00`;
  return {
    id: `task:${task.id}`,
    source: 'task',
    sourceId: task.id,
    companyId: task.company_id,
    title: task.title,
    description: task.description || taskTypeLabel(task.type),
    type: 'Task due',
    startsAt,
    endsAt: startsAt,
    allDay: !task.due_time,
    dateKey: task.due,
    owner: memberName(task.assignee_id),
    mine: taskAssignedToMe(task.assignee_id),
    href: companyPath('tasks', { ...(task.project_id ? { job_id: task.project_id } : {}), task_id: task.id }, task.company_id),
    linkLabel: jobById(task.project_id)?.name || 'Company task',
    editable: false,
  };
}

function calendarInvoiceItem(invoice) {
  return {
    id: `invoice:${invoice.id}`,
    source: 'invoice',
    sourceId: invoice.id,
    companyId: invoice.company_id,
    title: `${invoice.invoice_number} due`,
    description: `${money(invoiceBalance(invoice.id))} outstanding for ${invoice.client_name || 'client'}.`,
    type: 'Invoice due',
    startsAt: `${invoice.due_date}T12:00:00`,
    endsAt: `${invoice.due_date}T12:00:00`,
    allDay: true,
    dateKey: invoice.due_date,
    owner: invoice.client_name || 'Finance',
    mine: can('finance.view', invoice.company_id),
    href: companyPath('finance', { invoice: invoice.id }, invoice.company_id),
    linkLabel: invoice.client_name || 'Finance',
    editable: false,
  };
}

function calendarApprovalItem(item, companyId = activeCompanyId()) {
  const dateKey = String(item.updatedAt || isoDate(0)).slice(0, 10);
  return {
    id: `approval:${item.id}`,
    source: 'approval',
    sourceId: item.id,
    companyId,
    title: item.title,
    description: item.meta,
    type: 'Approval',
    startsAt: `${dateKey}T12:00:00`,
    endsAt: `${dateKey}T12:00:00`,
    allDay: true,
    dateKey,
    owner: item.owner,
    mine: true,
    href: item.href,
    linkLabel: item.status,
    editable: false,
  };
}

function calendarTimerItem(timer) {
  const dateKey = calendarDateKey(timer.started_at);
  return {
    id: `timer:${timer.id}`,
    source: 'timer',
    sourceId: timer.id,
    companyId: timer.company_id,
    title: timer.task_title || 'Active timer',
    description: 'Current clock session.',
    type: 'Time',
    startsAt: timer.started_at,
    endsAt: new Date().toISOString(),
    allDay: false,
    dateKey,
    owner: memberName(timer.user_id),
    mine: calendarPersonMatchesMe(timer.user_id),
    href: companyPath('time', {}, timer.company_id),
    linkLabel: 'My time',
    editable: false,
  };
}

function canAccessCalendarEvent(event) {
  if (!event || !can('calendar.view', event.company_id)) return false;
  if (event.visibility !== 'private') return true;
  return can('calendar.view_team', event.company_id) || canEditCalendarEvent(event) || calendarPersonMatchesMe(event.assigned_profile_id);
}

function canEditCalendarEvent(event) {
  if (!event) return false;
  return can('calendar.manage', event.company_id) || event.created_by === activeSession().profile.id;
}

function calendarLinkedHref(event) {
  if (event.linked_type === 'job' && event.linked_id && can('jobs.view', event.company_id)) return companyPath('jobs', { tab: 'profile', job_id: event.linked_id }, event.company_id);
  if (event.linked_type === 'task' && event.linked_id && can('tasks.view', event.company_id)) return companyPath('tasks', { task_id: event.linked_id }, event.company_id);
  if (event.linked_type === 'form' && event.linked_id && can('forms.view', event.company_id)) return companyPath('forms', { form_id: event.linked_id }, event.company_id);
  if (event.linked_type === 'invoice' && event.linked_id && can('finance.view', event.company_id)) return companyPath('finance', { invoice: event.linked_id }, event.company_id);
  return '';
}

function calendarEventByKey(key, companyId = activeCompanyId()) {
  return calendarItems(companyId).find((item) => item.id === key) || null;
}

function manualCalendarEventById(id) {
  return state.calendarEvents.find((event) => event.id === id) || null;
}

function taskAssignedToMe(assigneeId) {
  return String(assigneeId || '') === String(activeSession().profile.member_id || activeSession().profile.id || '');
}

function calendarPersonMatchesMe(value) {
  const profile = activeSession().profile;
  return [profile.id, profile.member_id, profile.email].filter(Boolean).map(String).includes(String(value || ''));
}

function calendarPersonName(value) {
  if (!value) return 'Unassigned';
  return profileById(value)?.full_name || memberName(value) || String(value);
}

function calendarDateKey(value) {
  if (!value) return isoDate(0);
  const date = new Date(value);
  if (Number.isNaN(date.getTime())) return String(value).slice(0, 10);
  return date.toISOString().slice(0, 10);
}

function calendarItemsForDate(items, dateKey) {
  return items.filter((item) => item.dateKey === dateKey).sort((a, b) => Date.parse(a.startsAt || 0) - Date.parse(b.startsAt || 0));
}

function calendarItemsThisWeek(items) {
  const start = startOfWeekDate(new Date());
  const end = new Date(start);
  end.setDate(start.getDate() + 7);
  return items.filter((item) => {
    const time = Date.parse(item.startsAt || item.dateKey || 0);
    return time >= start.getTime() && time < end.getTime();
  });
}

function calendarItemInVisibleRange(item) {
  const date = new Date(`${item.dateKey}T00:00:00`);
  if (state.calendarView === 'month') {
    const cursor = new Date(`${state.calendarCursorDate}T00:00:00`);
    return date.getFullYear() === cursor.getFullYear() && date.getMonth() === cursor.getMonth();
  }
  const start = startOfWeekDate(new Date(`${state.calendarCursorDate}T00:00:00`));
  const end = new Date(start);
  end.setDate(start.getDate() + 7);
  return date >= start && date < end;
}

function calendarMonthDays(value) {
  const cursor = new Date(`${value}T00:00:00`);
  const first = new Date(cursor.getFullYear(), cursor.getMonth(), 1);
  const start = new Date(first);
  start.setDate(first.getDate() - first.getDay());
  return Array.from({ length: 42 }, (_, index) => {
    const date = new Date(start);
    date.setDate(start.getDate() + index);
    return { key: localDateKey(date), label: String(date.getDate()), month: date.getMonth() };
  });
}

function calendarWeekDays(value) {
  const start = startOfWeekDate(new Date(`${value}T00:00:00`));
  return Array.from({ length: 7 }, (_, index) => {
    const date = new Date(start);
    date.setDate(start.getDate() + index);
    return {
      key: localDateKey(date),
      name: new Intl.DateTimeFormat('en-US', { weekday: 'short' }).format(date),
      shortDate: new Intl.DateTimeFormat('en-US', { month: 'short', day: 'numeric' }).format(date),
    };
  });
}

function calendarRangeLabel() {
  const cursor = new Date(`${state.calendarCursorDate}T00:00:00`);
  if (state.calendarView === 'month') return new Intl.DateTimeFormat('en-US', { month: 'long', year: 'numeric' }).format(cursor);
  if (state.calendarView === 'week') {
    const days = calendarWeekDays(state.calendarCursorDate);
    return `${formatDate(days[0].key)} - ${formatDate(days[6].key)}`;
  }
  return 'Upcoming';
}

function startOfWeekDate(date) {
  const next = new Date(date);
  next.setHours(0, 0, 0, 0);
  next.setDate(next.getDate() - next.getDay());
  return next;
}

function localDateKey(date) {
  const y = date.getFullYear();
  const m = String(date.getMonth() + 1).padStart(2, '0');
  const d = String(date.getDate()).padStart(2, '0');
  return `${y}-${m}-${d}`;
}

function moveCalendarCursor(direction) {
  const date = new Date(`${state.calendarCursorDate}T00:00:00`);
  if (state.calendarView === 'month') date.setMonth(date.getMonth() + direction);
  else date.setDate(date.getDate() + direction * 7);
  state.calendarCursorDate = localDateKey(date);
}

function groupByDate(items) {
  return items.reduce((groups, item) => {
    groups[item.dateKey] = groups[item.dateKey] || [];
    groups[item.dateKey].push(item);
    return groups;
  }, {});
}

function calendarTimeLabel(item) {
  if (item.allDay) return 'All day';
  const start = new Date(item.startsAt);
  if (Number.isNaN(start.getTime())) return 'Timed';
  return new Intl.DateTimeFormat('en-US', { hour: 'numeric', minute: '2-digit' }).format(start);
}

function calendarTypeClass(type) {
  return `calendar-type-${slugify(type || 'event')}`;
}

function calendarTypeIcon(type) {
  if (type === 'Task due') return 'ti-list-check';
  if (type === 'Invoice due') return 'ti-file-dollar';
  if (type === 'Approval') return 'ti-user-check';
  if (type === 'Time') return 'ti-clock';
  if (type.includes('Install')) return 'ti-hammer';
  if (type.includes('Estimate')) return 'ti-calendar-dollar';
  if (type.includes('Personal')) return 'ti-user';
  return 'ti-calendar-event';
}

function companyFiles(companyId = activeCompanyId()) {
  return state.files.filter((file) => file.company_id === companyId);
}

function companyDriveFolders(companyId = activeCompanyId()) {
  return state.driveFolders.filter((folder) => folder.company_id === companyId);
}

function companyMembers(companyId = activeCompanyId()) {
  if (state.session?.auth === 'supabase') {
    return state.memberships
      .filter((membership) => membership.company_id === companyId && membership.status === 'active')
      .map((membership) => {
        const profile = profileById(membership.profile_id);
        const member = membership.member_id ? state.teamMembers.find((item) => item.id === membership.member_id) : null;
        const id = membership.profile_id || membership.member_id;
        return normalizeTeamMember({
          id,
          name: profile?.full_name || member?.name || profile?.email || id,
          full_name: profile?.full_name || member?.full_name || profile?.email || id,
          email: profile?.email || member?.email || '',
          avatar_url: profile?.avatar_url || member?.avatar_url || '',
          active: membership.status === 'active',
          company_ids: [companyId],
        });
      })
      .filter((member) => member.id);
  }
  return state.teamMembers.filter((member) => Array.isArray(member.company_ids) && member.company_ids.includes(companyId));
}

function companyAccessUsers(companyId = activeCompanyId()) {
  const byId = new Map();
  if (state.session?.auth !== 'supabase') {
    companyMembers(companyId).forEach((member) => {
      byId.set(member.id, {
        profile_id: '',
        member_id: member.id,
        name: member.full_name || member.name,
        email: member.email,
        avatar_url: member.avatar_url,
        role: roleForMember(companyId, member.id).toLowerCase(),
        role_label: roleForMember(companyId, member.id),
        role_id: '',
        status: member.active ? 'active' : 'disabled',
      });
    });
  }
  state.memberships
    .filter((membership) => membership.company_id === companyId)
    .forEach((membership) => {
      const profile = profileById(membership.profile_id);
      const member = membership.member_id ? state.teamMembers.find((item) => item.id === membership.member_id) : null;
      const assignment = state.roleAssignments.find((item) => item.company_id === companyId && item.profile_id === membership.profile_id);
      const role = assignment ? roleById(companyId, assignment.role_id) : null;
      const id = membership.profile_id || membership.member_id;
      byId.set(id, {
        profile_id: membership.profile_id,
        member_id: membership.member_id,
        name: profile?.full_name || member?.full_name || profile?.email || member?.name || id || 'User',
        email: profile?.email || member?.email || '',
        avatar_url: profile?.avatar_url || member?.avatar_url || '',
        role: membership.role,
        role_label: role?.name || titleCase(membership.role),
        role_id: assignment?.role_id || roleIdForName(companyId, membership.role),
        status: membership.status || 'active',
      });
    });
  const sessionProfile = activeSession().profile;
  if (state.session?.auth === 'supabase' && sessionProfile?.id && !byId.has(sessionProfile.id)) {
    const membership = membershipForProfile(companyId, sessionProfile.id);
    if (membership) {
      byId.set(sessionProfile.id, {
        profile_id: sessionProfile.id,
        member_id: sessionProfile.member_id || '',
        name: sessionProfile.full_name || sessionProfile.email,
        email: sessionProfile.email,
        avatar_url: sessionProfile.avatar_url,
        role: membership.role,
        role_label: titleCase(membership.role),
        role_id: roleIdForName(companyId, membership.role),
        status: membership.status || 'active',
      });
    }
  }
  return [...byId.values()].sort((a, b) => (a.status === 'active' ? 0 : 1) - (b.status === 'active' ? 0 : 1) || a.name.localeCompare(b.name));
}

function companyInvites(companyId = activeCompanyId()) {
  return state.companyInvites
    .filter((invite) => invite.company_id === companyId && invite.status === 'pending')
    .sort((a, b) => Date.parse(b.created_at || 0) - Date.parse(a.created_at || 0));
}

function companyAuditEvents(companyId = activeCompanyId()) {
  return state.auditEvents
    .filter((event) => event.company_id === companyId)
    .sort((a, b) => Date.parse(b.created_at || 0) - Date.parse(a.created_at || 0));
}

function renderAuditEventRow(event) {
  const profile = profileById(event.actor_profile_id);
  const actor = profile?.full_name || profile?.email || shortUserId(event.actor_profile_id || 'system');
  return `
    <article class="access-audit-row">
      ${renderAvatar({ full_name: actor, email: profile?.email || '' }, 'avatar small')}
      <span>
        <strong>${h(titleCase(String(event.event_type || 'access.event').replace(/[._-]+/g, ' ')))}</strong>
        <small>${h(actor)} / ${formatDate(event.created_at)}</small>
      </span>
    </article>
  `;
}

function companyRoles(companyId = activeCompanyId()) {
  const custom = state.roles.filter((role) => role.company_id === companyId);
  if (custom.length) return custom.sort((a, b) => b.priority - a.priority || a.name.localeCompare(b.name));
  return [
    normalizeRole({ id: `owner-${companyId}`, company_id: companyId, name: 'Owner', color: '#f0b23b', priority: 1000, is_system: true }),
    normalizeRole({ id: `admin-${companyId}`, company_id: companyId, name: 'Admin', color: '#60a5fa', priority: 800, is_system: true }),
    normalizeRole({ id: `staff-${companyId}`, company_id: companyId, name: 'Staff', color: '#15803d', priority: 100, is_system: true }),
  ];
}

function roleById(companyId, roleId) {
  return companyRoles(companyId).find((role) => role.id === roleId) || null;
}

function rolePreviewForCompany(companyId = activeCompanyId()) {
  if (!state.rolePreview || state.rolePreview.company_id !== companyId) return null;
  return roleById(companyId, state.rolePreview.role_id);
}

function roleAllowsPermission(role, permission) {
  if (!permission) return true;
  const normalizedName = String(role?.name || '').toLowerCase();
  if (['owner', 'admin', 'developer'].includes(normalizedName)) return true;
  const variants = permissionVariants(permission);
  const explicit = state.rolePermissions.filter((item) => item.role_id === role?.id);
  if (explicit.some((item) => (variants.includes(item.permission_key) || item.permission_key === '*') && item.effect === 'deny')) return false;
  if (explicit.some((item) => (variants.includes(item.permission_key) || item.permission_key === '*') && item.effect === 'allow')) return true;
  if (explicit.length) return false;
  const fallbackRole = membershipRoleForRole(role);
  const fallbackPermissions = ROLE_PERMISSIONS[fallbackRole] || ROLE_PERMISSIONS.member;
  return fallbackPermissions.includes('*') || variants.some((variant) => fallbackPermissions.includes(variant));
}

function permissionVariants(permission) {
  return compactUnique([permission, ...(PERMISSION_ALIASES[permission] || [])]);
}

function roleIdForName(companyId, roleName) {
  const normalized = String(roleName || '').toLowerCase();
  return companyRoles(companyId).find((role) => role.name.toLowerCase() === normalized || role.id.toLowerCase() === normalized)?.id || '';
}

function defaultInviteRoleId(companyId = activeCompanyId()) {
  const roles = companyRoles(companyId).filter((role) => role.name.toLowerCase() !== 'owner');
  return roles.find((role) => role.name.toLowerCase() === 'staff')?.id || roles.find((role) => role.name.toLowerCase() === 'member')?.id || roles[0]?.id || '';
}

function generateInviteCode() {
  const bytes = new Uint8Array(8);
  crypto.getRandomValues(bytes);
  return `QH-${Array.from(bytes, (byte) => byte.toString(36).padStart(2, '0')).join('').toUpperCase()}`;
}

function inviteLink(invite) {
  const url = new URL(appHref('/login'), window.location.origin);
  url.searchParams.set('invite', invite.token);
  return url.toString();
}

function membershipRoleForRole(role) {
  const normalized = String(role?.name || '').toLowerCase().replace(/\s+/g, '_');
  const allowed = ['owner', 'member', 'worker', 'sales', 'supervisor', 'admin', 'developer', 'construction_supervisor'];
  if (allowed.includes(normalized)) return normalized;
  if (normalized === 'staff') return 'member';
  return 'member';
}

function profileById(profileId) {
  return state.profiles.find((profile) => profile.id === profileId) || (activeSession().profile.id === profileId ? activeSession().profile : null);
}

function filteredJobs(companyId = activeCompanyId(), ignoreStage = false) {
  const q = state.query.trim().toLowerCase();
  return companyJobs(companyId).filter((job) => {
    if (!ignoreStage && state.stageFilter !== 'all' && resolvePipelineStage('jobs', job.stage, companyId) !== state.stageFilter) return false;
    if (!q) return true;
    return [job.name, job.client_name, job.contact_name, job.owner_name, job.site_address, job.job_type, companyName(job.company_id)]
      .some((value) => String(value || '').toLowerCase().includes(q));
  });
}

function companyContacts(companyId = activeCompanyId()) {
  return state.contacts.filter((contact) => contact.company_id === companyId);
}

function contactFilterJobType(contact) {
  return String(contact.job_type || contact.roof_system || '').trim();
}

function contactFilterPayType(contact) {
  return String(contact.pay_type || '').trim();
}

function cleanContactFilterOption(value, kind, companyId = activeCompanyId()) {
  const clean = String(value || '').trim();
  if (!clean) return '';
  if (kind === 'owner_name') return personOwnerDisplayName(clean, companyId);
  if (kind === 'job_type' || kind === 'pay_type') {
    if (clean.length < 2) return '';
    if (!/[a-z]/i.test(clean)) return '';
  }
  return clean;
}

function contactFilterOptions(companyId) {
  const contacts = companyContacts(companyId);
  return {
    temperature: compactUnique([...TEMPERATURES, ...contacts.map((contact) => contact.temperature)]),
    job_type: compactUnique([...CONTACT_JOB_TYPE_OPTIONS, ...contacts.map(contactFilterJobType).map((value) => cleanContactFilterOption(value, 'job_type', companyId))]),
    owner_name: compactUnique(contacts.map((contact) => cleanContactFilterOption(contact.owner_name, 'owner_name', companyId))).sort((a, b) => a.localeCompare(b)),
    pay_type: compactUnique([...CONTACT_PAY_TYPE_OPTIONS, ...contacts.map(contactFilterPayType).map((value) => cleanContactFilterOption(value, 'pay_type', companyId))]),
  };
}

function activeContactFilters() {
  const filters = { ...CONTACT_FILTER_DEFAULTS, ...(state.contactFilters || {}) };
  const labels = {
    temperature: 'Temperature',
    job_type: 'Job type',
    owner_name: 'Owner',
    pay_type: 'Pay type',
  };
  return Object.keys(CONTACT_FILTER_DEFAULTS)
    .filter((key) => filters[key] && filters[key] !== 'all')
    .map((key) => ({ key, label: labels[key], value: filters[key] }));
}

function filteredContacts(companyId = activeCompanyId(), ignoreStage = false) {
  const q = state.contactQuery.trim().toLowerCase();
  const filters = { ...CONTACT_FILTER_DEFAULTS, ...(state.contactFilters || {}) };
  return companyContacts(companyId).filter((contact) => {
    if (!ignoreStage && state.contactStageFilter !== 'all' && resolvePipelineStage('contacts', contact.stage, companyId) !== state.contactStageFilter) return false;
    if (filters.temperature !== 'all' && String(contact.temperature || '') !== filters.temperature) return false;
    if (filters.job_type !== 'all' && contactFilterJobType(contact) !== filters.job_type) return false;
    if (filters.owner_name !== 'all' && String(contact.owner_name || '') !== filters.owner_name) return false;
    if (filters.pay_type !== 'all' && contactFilterPayType(contact) !== filters.pay_type) return false;
    if (!q) return true;
    return [contact.name, contact.phone, contact.email, contact.location, contact.owner_name, contact.stage, contact.title, accountName(contact.account_id)]
      .some((value) => String(value || '').toLowerCase().includes(q));
  });
}

function sortedContacts(contacts) {
  const sort = CONTACT_SORT_OPTIONS.find((option) => option.id === state.contactSort) || CONTACT_SORT_OPTIONS[0];
  const direction = sort.dir === 'desc' ? -1 : 1;
  return [...contacts].sort((a, b) => {
    const av = sort.field === 'value' ? Number(a.value || 0) : String(a[sort.field] || '').toLowerCase();
    const bv = sort.field === 'value' ? Number(b.value || 0) : String(b[sort.field] || '').toLowerCase();
    if (av < bv) return -1 * direction;
    if (av > bv) return 1 * direction;
    return String(a.name || '').localeCompare(String(b.name || ''));
  });
}

function contactById(id) {
  return state.contacts.find((contact) => contact.id === id) || null;
}

function selectedContact() {
  return contactById(state.selectedContactId);
}

function persistContacts() {
  writeJson(CONTACT_CACHE_KEY, state.contacts);
}

function upsertContact(contact) {
  const index = state.contacts.findIndex((item) => item.id === contact.id);
  if (index >= 0) state.contacts[index] = contact;
  else state.contacts.push(contact);
  persistContacts();
}

function pipelineStageRouteParams(stage) {
  return stage && stage !== 'all' ? { stage } : {};
}

function isPipelineDetailRoute(route, kind) {
  if (!route || route.name !== 'company' || route.section !== kind) return false;
  if (kind === 'contacts') return route.params.has('contact_id');
  if (kind === 'deals') return route.params.has('deal_id');
  if (kind === 'jobs') return route.params.has('job_id');
  return false;
}

function setPipelineStage(kind, stage, forceNav) {
  if (!['contacts', 'jobs', 'deals'].includes(kind)) return;
  const nextStage = stage || 'all';
  if (kind === 'contacts') state.contactStageFilter = nextStage;
  else if (kind === 'deals') state.stageFilterDeals = nextStage;
  else state.stageFilter = nextStage;
  const nextPath = companyPath(kind, pipelineStageRouteParams(nextStage), activeCompanyId());
  navigate(nextPath, { replace: !forceNav && currentAppUrl() === nextPath });
}

// ---- CRM getters + CRUD: accounts / deals / activities --------------------
function companyAccounts(companyId = activeCompanyId()) {
  return state.accounts.filter((account) => account.company_id === companyId);
}
function accountById(id) {
  return id ? state.accounts.find((account) => account.id === id) || null : null;
}
function accountName(id) {
  return accountById(id)?.name || '';
}
function selectedAccount() {
  return accountById(state.selectedAccountId);
}
function companyCrmSites(companyId = activeCompanyId()) {
  return state.sites.filter((site) => site.company_id === companyId);
}
function crmSiteById(id) {
  return id ? state.sites.find((site) => site.id === id) || null : null;
}
function crmSitesForContact(contactId) {
  return state.sites.filter((site) => site.contact_id === contactId);
}
function filteredAccounts(companyId = activeCompanyId()) {
  const q = state.accountQuery.trim().toLowerCase();
  return companyAccounts(companyId).filter((account) => {
    if (state.accountTypeFilter !== 'all' && account.type !== state.accountTypeFilter) return false;
    if (!q) return true;
    return [account.name, account.industry, account.email, account.phone, account.owner_name, account.address]
      .some((value) => String(value || '').toLowerCase().includes(q));
  });
}

function companyDeals(companyId = activeCompanyId()) {
  return state.deals.filter((deal) => deal.company_id === companyId);
}
function dealById(id) {
  return id ? state.deals.find((deal) => deal.id === id) || null : null;
}
function selectedDeal() {
  return dealById(state.selectedDealId);
}
function filteredDeals(companyId = activeCompanyId(), ignoreStage = false) {
  const q = state.dealQuery.trim().toLowerCase();
  return companyDeals(companyId).filter((deal) => {
    if (!ignoreStage && state.stageFilterDeals !== 'all' && resolvePipelineStage('deals', deal.stage, companyId) !== state.stageFilterDeals) return false;
    if (!q) return true;
    return [deal.name, deal.owner_name, deal.source, deal.stage, accountName(deal.account_id), contactById(deal.primary_contact_id)?.name]
      .some((value) => String(value || '').toLowerCase().includes(q));
  });
}
function dealsForAccount(accountId) {
  return state.deals.filter((deal) => deal.account_id === accountId);
}
function contactsForAccount(accountId) {
  return state.contacts.filter((contact) => contact.account_id === accountId);
}
function jobsForAccount(accountId) {
  return state.jobs.filter((job) => job.account_id === accountId);
}

function companyActivities(companyId = activeCompanyId()) {
  return state.activities.filter((activity) => activity.company_id === companyId);
}
function relationThreadIds(relatedType, relatedId) {
  const ids = { account_id: '', contact_id: '', site_id: '', deal_id: '', job_id: '' };
  if (!relatedId) return ids;
  if (relatedType === 'account') ids.account_id = relatedId;
  if (relatedType === 'contact') {
    const contact = contactById(relatedId);
    ids.contact_id = relatedId;
    ids.account_id = contact?.account_id || '';
    ids.site_id = crmSitesForContact(relatedId)[0]?.id || '';
  }
  if (relatedType === 'deal') {
    const deal = dealById(relatedId);
    ids.deal_id = relatedId;
    ids.account_id = deal?.account_id || '';
    ids.contact_id = deal?.primary_contact_id || '';
    ids.site_id = deal?.site_id || '';
    ids.job_id = deal?.job_id || '';
  }
  if (relatedType === 'job') {
    const job = jobById(relatedId);
    const deal = dealById(job?.deal_id);
    ids.job_id = relatedId;
    ids.deal_id = job?.deal_id || '';
    ids.account_id = job?.account_id || deal?.account_id || '';
    ids.contact_id = job?.contact_id || deal?.primary_contact_id || '';
    ids.site_id = job?.site_id || deal?.site_id || '';
  }
  return ids;
}
function matchesActivityThread(activity, relatedType, relatedId) {
  if (!relatedId) return false;
  if (activity.related_type === relatedType && activity.related_id === relatedId) return true;
  const ids = relationThreadIds(relatedType, relatedId);
  return (!!ids.account_id && activity.account_id === ids.account_id && relatedType === 'account')
    || (!!ids.contact_id && activity.contact_id === ids.contact_id)
    || (!!ids.site_id && activity.site_id === ids.site_id)
    || (!!ids.deal_id && activity.deal_id === ids.deal_id)
    || (!!ids.job_id && activity.job_id === ids.job_id);
}
function activitiesFor(relatedType, relatedId) {
  if (!relatedId) return [];
  return state.activities
    .filter((activity) => matchesActivityThread(activity, relatedType, relatedId))
    .sort((a, b) => Date.parse(b.created_at || 0) - Date.parse(a.created_at || 0));
}
function activityFilterOption(filterId = state.activityFilter) {
  return ACTIVITY_FILTER_OPTIONS.find((filter) => filter.id === filterId) || ACTIVITY_FILTER_OPTIONS[0];
}
function filterActivities(items, filterId = state.activityFilter) {
  const filter = activityFilterOption(filterId);
  if (!filter.types.length) return items;
  return items.filter((item) => filter.types.includes(String(item.type || 'note')));
}
function filteredActivitiesFor(relatedType, relatedId) {
  return filterActivities(activitiesFor(relatedType, relatedId));
}

function normalizeActivityComposerKind(kind) {
  const value = String(kind || '').trim();
  const aliases = {
    Task: 'New Task',
    Meeting: 'New Event',
    Event: 'New Event',
    'Call Log': 'Log a Call',
    Call: 'Log a Call',
    'Add Note': 'Note',
  };
  const normalized = aliases[value] || value || 'Note';
  return ACTIVITY_COMPOSER_CONFIG[normalized] ? normalized : 'Note';
}

function activityRelatedRecord(relatedType, relatedId) {
  if (relatedType === 'contact') return contactById(relatedId);
  if (relatedType === 'job') return jobById(relatedId);
  if (relatedType === 'deal') return dealById(relatedId);
  return null;
}

function activityRelatedLabel(record) {
  return record?.name || record?.client_name || record?.title || 'Record';
}

function activityRelatedEmail(relatedType, record) {
  if (relatedType === 'contact') return record?.email || '';
  if (relatedType === 'deal') return contactById(record?.primary_contact_id)?.email || '';
  if (relatedType === 'job') return contactById(record?.contact_id)?.email || '';
  return '';
}

function activityComposerId(relatedType, relatedId, kind) {
  return `${relatedType}:${relatedId}:${normalizeActivityComposerKind(kind)}`;
}

function activityDockComposerClass(config) {
  if (config.type === 'email') return 'activity-dock-email';
  if (config.type === 'task') return 'activity-dock-task';
  if (config.type === 'meeting') return 'activity-dock-event';
  if (config.type === 'call') return 'activity-dock-call';
  return 'activity-dock-note';
}

function openDockedActivityComposer(relatedType, relatedId, kind) {
  const cleanType = String(relatedType || '').trim();
  const cleanId = String(relatedId || '').trim();
  const normalizedKind = normalizeActivityComposerKind(kind);
  if (!activityRelatedRecord(cleanType, cleanId)) return;
  const id = activityComposerId(cleanType, cleanId, normalizedKind);
  const existing = state.dockedActivityComposers.find((composer) => composer.id === id);
  if (existing) {
    existing.minimized = false;
    existing.updated_at = Date.now();
    render();
    return;
  }
  state.dockedActivityComposers = [
    ...state.dockedActivityComposers,
    {
      id,
      related_type: cleanType,
      related_id: cleanId,
      kind: normalizedKind,
      minimized: false,
      created_at: Date.now(),
      updated_at: Date.now(),
    },
  ].slice(-4);
  render();
}

function closeDockedActivityComposer(composerId) {
  state.dockedActivityComposers = state.dockedActivityComposers.filter((composer) => composer.id !== composerId);
  render();
}

function minimizeDockedActivityComposer(composerId) {
  const composer = state.dockedActivityComposers.find((item) => item.id === composerId);
  if (!composer) return;
  composer.minimized = !composer.minimized;
  render();
}

function renderDockedActivityComposers() {
  if (!state.dockedActivityComposers.length) return '';
  const items = state.dockedActivityComposers.map((composer) => {
    const record = activityRelatedRecord(composer.related_type, composer.related_id);
    if (!record) return '';
    const config = ACTIVITY_COMPOSER_CONFIG[composer.kind] || ACTIVITY_COMPOSER_CONFIG.Note;
    const label = activityRelatedLabel(record);
    const composerClass = activityDockComposerClass(config);
    return `
      <section class="activity-dock-window ${h(composerClass)} ${composer.minimized ? 'minimized' : ''}" aria-label="${h(composer.kind)} composer for ${h(label)}">
        <div class="activity-dock-head">
          <div>
            <span class="activity-dock-kind"><i class="ti ${h(config.icon)}"></i>${h(composer.kind)}</span>
            <strong>${h(label)}</strong>
          </div>
          <div class="activity-dock-controls">
            <button type="button" data-action="minimize-docked-activity" data-composer-id="${h(composer.id)}" aria-label="${composer.minimized ? 'Restore composer' : 'Minimize composer'}"><i class="ti ${composer.minimized ? 'ti-window-maximize' : 'ti-minus'}"></i></button>
            <button type="button" data-action="close-docked-activity" data-composer-id="${h(composer.id)}" aria-label="Close composer"><i class="ti ti-x"></i></button>
          </div>
        </div>
        ${composer.minimized ? '' : `
          <form class="activity-dock-body" data-docked-activity-form autocomplete="off">
            <input type="hidden" name="composer_id" value="${h(composer.id)}" />
            ${renderDockedActivityFields(composer, record, config)}
            <div class="activity-dock-foot">
              <button class="btn" type="button" data-action="close-docked-activity" data-composer-id="${h(composer.id)}">Cancel</button>
              <button class="btn-primary" type="submit">${h(config.action)}</button>
            </div>
          </form>
        `}
      </section>
    `;
  }).join('');
  return `<div class="activity-dock" aria-live="polite">${items}</div>`;
}

function renderDockedActivityFields(composer, record, config) {
  const label = activityRelatedLabel(record);
  const subject = `${config.subject}: ${label}`;
  if (config.type === 'email') {
    return `
      <label class="activity-dock-field">
        <span>To</span>
        <input name="email_to" value="${h(activityRelatedEmail(composer.related_type, record))}" placeholder="name@example.com" aria-label="Email to" />
      </label>
      <label class="activity-dock-field">
        <span>Subject</span>
        <input name="subject" value="${h(subject)}" aria-label="Subject" />
      </label>
      <label class="activity-dock-field">
        <span>Email body</span>
        <textarea name="email_body" rows="7" placeholder="Write the email message..." aria-label="Email body"></textarea>
      </label>
      <div class="activity-dock-toolbar" aria-label="Email tools">
        <button type="button" title="Attach file"><i class="ti ti-paperclip"></i></button>
        <button type="button" title="Insert template"><i class="ti ti-template"></i></button>
        <button type="button" title="Add merge field"><i class="ti ti-braces"></i></button>
      </div>
    `;
  }
  if (config.type === 'task') {
    return `
      <label class="activity-dock-field">
        <span>Subject</span>
        <input name="subject" value="${h(subject)}" aria-label="Subject" />
      </label>
      <div class="activity-dock-grid">
        <label class="activity-dock-field">
          <span>Due date</span>
          <input name="due_date" type="date" value="${h(isoDate(1))}" aria-label="Due date" />
        </label>
        <label class="activity-dock-field">
          <span>Due time</span>
          <input name="due_time" type="time" value="" aria-label="Due time" />
        </label>
        <label class="activity-dock-field">
          <span>Priority</span>
          <select name="priority" aria-label="Priority">
            <option>Normal</option>
            <option>High</option>
            <option>Low</option>
          </select>
        </label>
      </div>
      <label class="activity-dock-field">
        <span>Task details</span>
        <textarea name="task_notes" rows="5" placeholder="Add task details..." aria-label="Task details"></textarea>
      </label>
    `;
  }
  if (config.type === 'meeting') {
    return `
      <label class="activity-dock-field">
        <span>Subject</span>
        <input name="subject" value="${h(subject)}" aria-label="Subject" />
      </label>
      <div class="activity-dock-grid">
        <label class="activity-dock-field">
          <span>Date</span>
          <input name="event_date" type="date" value="${h(isoDate(1))}" aria-label="Event date" />
        </label>
        <label class="activity-dock-field">
          <span>Start</span>
          <input name="start_time" type="time" value="09:00" aria-label="Start time" />
        </label>
        <label class="activity-dock-field">
          <span>End</span>
          <input name="end_time" type="time" value="09:30" aria-label="End time" />
        </label>
      </div>
      <label class="activity-dock-field">
        <span>Location</span>
        <input name="event_location" value="${h(record.location || record.site_address || '')}" placeholder="Address or call link" aria-label="Event location" />
      </label>
      <label class="activity-dock-field">
        <span>Event notes</span>
        <textarea name="event_notes" rows="4" placeholder="Add meeting details..." aria-label="Event notes"></textarea>
      </label>
    `;
  }
  if (config.type === 'call') {
    return `
      <label class="activity-dock-field">
        <span>Subject</span>
        <input name="subject" value="${h(subject)}" aria-label="Subject" />
      </label>
      <div class="activity-dock-grid">
        <label class="activity-dock-field">
          <span>Outcome</span>
          <select name="call_outcome" aria-label="Call outcome">
            <option>Connected</option>
            <option>Left voicemail</option>
            <option>No answer</option>
            <option>Bad number</option>
          </select>
        </label>
        <label class="activity-dock-field">
          <span>Next step</span>
          <select name="follow_up" aria-label="Follow up">
            <option>None</option>
            <option>Follow up tomorrow</option>
            <option>Schedule meeting</option>
            <option>Send quote</option>
          </select>
        </label>
      </div>
      <label class="activity-dock-field">
        <span>Call notes</span>
        <textarea name="call_notes" rows="5" placeholder="Summarize the call..." aria-label="Call notes"></textarea>
      </label>
    `;
  }
  return `
    <label class="activity-dock-field">
      <span>Subject</span>
      <input name="subject" value="${h(subject)}" aria-label="Subject" />
    </label>
    <label class="activity-dock-field">
      <span>Note</span>
      <textarea name="body" rows="6" placeholder="${h(config.placeholder)}" aria-label="Note"></textarea>
    </label>
  `;
}

function serializeDockedActivityBody(composer, formData) {
  const config = ACTIVITY_COMPOSER_CONFIG[composer.kind] || ACTIVITY_COMPOSER_CONFIG.Note;
  const pairs = [];
  const push = (label, key) => {
    const value = String(formData[key] || '').trim();
    if (value) pairs.push(`${label}: ${value}`);
  };
  if (config.type === 'email') {
    push('To', 'email_to');
    push('Body', 'email_body');
  } else if (config.type === 'task') {
    push('Due', 'due_date');
    push('Priority', 'priority');
    push('Details', 'task_notes');
  } else if (config.type === 'meeting') {
    push('Date', 'event_date');
    push('Start', 'start_time');
    push('End', 'end_time');
    push('Location', 'event_location');
    push('Notes', 'event_notes');
  } else if (config.type === 'call') {
    push('Outcome', 'call_outcome');
    push('Follow-up', 'follow_up');
    push('Notes', 'call_notes');
  } else {
    push('Note', 'body');
  }
  return pairs.join('\n');
}

async function submitDockedActivityComposer(form) {
  const formData = Object.fromEntries(new FormData(form).entries());
  const composerId = String(formData.composer_id || '');
  const composer = state.dockedActivityComposers.find((item) => item.id === composerId);
  if (!composer) return;
  const config = ACTIVITY_COMPOSER_CONFIG[composer.kind] || ACTIVITY_COMPOSER_CONFIG.Note;
  const subject = String(formData.subject || config.subject).trim() || config.subject;
  const body = serializeDockedActivityBody(composer, formData);
  state.dockedActivityComposers = state.dockedActivityComposers.filter((item) => item.id !== composerId);

  if (config.type === 'task') {
    if (composer.related_type === 'contact') await createContactTask(composer.related_id, {
      title: subject,
      description: formData.task_notes,
      due: formData.due_date,
      due_time: formData.due_time,
      priority: formData.priority,
    });
    if (composer.related_type === 'job') await createJobTask(composer.related_id, subject);
    if (composer.related_type === 'deal') await createDealTask(composer.related_id, subject);
    return;
  }

  if (composer.related_type === 'contact') await logContactActivity(composer.related_id, config.type, subject, body);
  if (composer.related_type === 'job') await logJobActivity(composer.related_id, config.type, subject, body);
  if (composer.related_type === 'deal') await logDealActivity(composer.related_id, config.type, subject, body);
  if (['call', 'email', 'note'].includes(config.type)) openWorkdayNextStepPrompt({
    related_type: composer.related_type,
    related_id: composer.related_id,
    company_id: activeCompanyId(),
    activity_type: config.type,
    label: activityRelatedLabel(activityRelatedRecord(composer.related_type, composer.related_id)),
  });
}

function renderActivityFilterBar(totalCount, visibleCount) {
  const active = activityFilterOption();
  return `
    <div class="sf-filters" aria-label="Activity filters">
      <span class="sf-filter-label">Activity</span>
      ${ACTIVITY_FILTER_OPTIONS.map((filter) => `
        <button class="sf-filter-chip ${active.id === filter.id ? 'active' : ''}" type="button" data-action="set-activity-filter" data-filter="${h(filter.id)}">${h(filter.label)}</button>
      `).join('')}
      <span class="sf-filter-count">${h(String(visibleCount))}/${h(String(totalCount))}</span>
    </div>
  `;
}
function activitiesForAccount(accountId) {
  if (!accountId) return [];
  return state.activities
    .filter((activity) => activity.account_id === accountId || (activity.related_type === 'account' && activity.related_id === accountId))
    .sort((a, b) => Date.parse(b.created_at || 0) - Date.parse(a.created_at || 0));
}

function persistAccounts() { writeJson(ACCOUNT_CACHE_KEY, state.accounts); }
function persistDeals() { writeJson(DEAL_CACHE_KEY, state.deals); }
function persistSites() { writeJson(SITE_CACHE_KEY, state.sites); }
function persistProposalsLocal() { writeJson(PROPOSAL_CACHE_KEY, state.proposals); }
function persistActivities() { writeJson(ACTIVITY_CACHE_KEY, state.activities); }

function upsertAccount(account) {
  const index = state.accounts.findIndex((item) => item.id === account.id);
  if (index >= 0) state.accounts[index] = account;
  else state.accounts.push(account);
  persistAccounts();
}
function upsertDeal(deal) {
  const index = state.deals.findIndex((item) => item.id === deal.id);
  if (index >= 0) state.deals[index] = deal;
  else state.deals.push(deal);
  persistDeals();
}
function upsertCrmSite(site) {
  const index = state.sites.findIndex((item) => item.id === site.id);
  if (index >= 0) state.sites[index] = site;
  else state.sites.push(site);
  persistSites();
}
function upsertProposal(proposal) {
  const normalized = normalizeProposal(proposal);
  const index = state.proposals.findIndex((item) => item.id === normalized.id);
  if (index >= 0) state.proposals[index] = normalized;
  else state.proposals.unshift(normalized);
  persistProposalsLocal();
}
function upsertActivity(activity) {
  const index = state.activities.findIndex((item) => item.id === activity.id);
  if (index >= 0) state.activities[index] = activity;
  else state.activities.unshift(activity);
  persistActivities();
}

async function loadJsZip() {
  const module = await import('jszip');
  return module.default || module;
}

function workspaceBackupsForCompany(companyId = activeCompanyId()) {
  return (state.workspaceBackups || [])
    .filter((backup) => backup.company_id === companyId)
    .sort((a, b) => String(b.created_at || '').localeCompare(String(a.created_at || '')));
}

function workspaceBackupById(id) {
  return (state.workspaceBackups || []).find((backup) => backup.id === id) || null;
}

function backupSettingsForCompany(companyId = activeCompanyId()) {
  return { interval_key: 'manual', ...(state.backupSettings?.[companyId] || {}) };
}

function backupIntervalMs(intervalKey) {
  return {
    daily: 24 * 60 * 60 * 1000,
    weekly: 7 * 24 * 60 * 60 * 1000,
    monthly: 30 * 24 * 60 * 60 * 1000,
  }[intervalKey] || 0;
}

function latestWorkspaceBackupAt(companyId) {
  const latest = workspaceBackupsForCompany(companyId)
    .filter((backup) => backup.status === 'active')
    .map((backup) => Date.parse(backup.created_at || backup.updated_at || 0))
    .filter((time) => Number.isFinite(time))
    .sort((a, b) => b - a)[0];
  const settingsTime = Date.parse(backupSettingsForCompany(companyId).last_backup_at || 0);
  return Math.max(Number.isFinite(latest) ? latest : 0, Number.isFinite(settingsTime) ? settingsTime : 0);
}

function automaticBackupDue(companyId, now = Date.now()) {
  const intervalKey = backupSettingsForCompany(companyId).interval_key;
  const interval = backupIntervalMs(intervalKey);
  if (!interval) return false;
  const last = latestWorkspaceBackupAt(companyId);
  return !last || now - last >= interval;
}

async function maybeRunAutomaticBackups() {
  const companyIds = allowedCompanyIds().length ? allowedCompanyIds() : [activeCompanyId()].filter(Boolean);
  for (const companyId of companyIds) {
    const intervalKey = backupSettingsForCompany(companyId).interval_key;
    const runKey = `${companyId}:${intervalKey}:${new Date().toISOString().slice(0, 10)}`;
    if (state.backupAutoRunKeys.has(runKey) || !automaticBackupDue(companyId)) continue;
    state.backupAutoRunKeys.add(runKey);
    await createWorkspaceBackup(companyId, 'automatic');
  }
}

function backupPayloadRows(rows, companyId) {
  return (rows || []).filter((row) => row.company_id === companyId).map((row) => clone(row));
}

function buildWorkspaceBackupPayload(companyId) {
  const company = companyById(companyId);
  return {
    version: WORKSPACE_BACKUP_VERSION,
    exported_at: new Date().toISOString(),
    company_id: companyId,
    company: clone(company),
    data: {
      jobs: backupPayloadRows(state.jobs, companyId),
      pipelineStages: backupPayloadRows(state.pipelineStages, companyId),
      contacts: backupPayloadRows(state.contacts, companyId),
      accounts: backupPayloadRows(state.accounts, companyId),
      deals: backupPayloadRows(state.deals, companyId),
      sites: backupPayloadRows(state.sites, companyId),
      proposals: backupPayloadRows(state.proposals, companyId),
      activities: backupPayloadRows(state.activities, companyId),
      tasks: backupPayloadRows(state.tasks, companyId),
      files: backupPayloadRows(state.files, companyId),
      driveFolders: backupPayloadRows(state.driveFolders, companyId),
      forms: backupPayloadRows(state.forms, companyId),
      formResponses: backupPayloadRows(state.formResponses, companyId),
      financeInvoices: backupPayloadRows(state.financeInvoices, companyId),
      financePayments: backupPayloadRows(state.financePayments, companyId),
      financeExpenses: backupPayloadRows(state.financeExpenses, companyId),
      financeVendors: backupPayloadRows(state.financeVendors, companyId),
      pricebookVendors: backupPayloadRows(state.pricebookVendors, companyId),
      pricebookMaterials: backupPayloadRows(state.pricebookMaterials, companyId),
      pricebookPrices: backupPayloadRows(state.pricebookPrices, companyId),
      clientPortals: backupPayloadRows(state.clientPortals, companyId),
      clientPortalDocuments: backupPayloadRows(state.clientPortalDocuments, companyId),
      clientPortalAnnotations: backupPayloadRows(state.clientPortalAnnotations, companyId),
      clientPortalEvents: backupPayloadRows(state.clientPortalEvents, companyId),
      messageConversations: backupPayloadRows(state.messageConversations, companyId),
      messageAccess: backupPayloadRows(state.messageAccess, companyId),
      messages: backupPayloadRows(state.messages, companyId),
      messageReads: backupPayloadRows(state.messageReads, companyId),
      messageAttachments: backupPayloadRows(state.messageAttachments, companyId),
      calendarEvents: backupPayloadRows(state.calendarEvents, companyId),
      roles: backupPayloadRows(state.roles, companyId),
      rolePermissions: backupPayloadRows(state.rolePermissions, companyId),
      roleAssignments: backupPayloadRows(state.roleAssignments, companyId),
      resourceAcl: backupPayloadRows(state.resourceAcl, companyId),
      fieldPermissions: backupPayloadRows(state.fieldPermissions, companyId),
      companyPlugins: backupPayloadRows(state.companyPlugins, companyId),
      teamMembers: backupPayloadRows(state.teamMembers, companyId),
      memberships: backupPayloadRows(state.memberships, companyId),
      workspaceBuilderDoc: clone(state.workspaceBuilderDocs?.[companyId] || null),
    },
  };
}

function workspaceBackupRecordCounts(payload) {
  return Object.entries(payload?.data || {}).reduce((acc, [key, value]) => {
    if (Array.isArray(value)) acc[key] = value.length;
    return acc;
  }, {});
}

async function createWorkspaceBackup(companyId = activeCompanyId(), kind = 'manual') {
  const payload = buildWorkspaceBackupPayload(companyId);
  const now = new Date().toISOString();
  const profile = activeSession()?.profile || {};
  const backup = normalizeWorkspaceBackup({
    id: `backup-${crypto.randomUUID()}`,
    company_id: companyId,
    label: `${companyName(companyId)} ${titleCase(kind)} backup`,
    kind,
    status: 'active',
    interval_key: backupSettingsForCompany(companyId).interval_key,
    payload,
    size_bytes: new Blob([JSON.stringify(payload)]).size,
    record_counts: workspaceBackupRecordCounts(payload),
    created_by: isUuid(profile.id) ? profile.id : null,
    created_by_label: profile.full_name || profile.email || 'ROM user',
    source: 'settings',
    created_at: now,
    updated_at: now,
  });
  let savedBackup = backup;
  if (isLiveSupabaseSession()) {
    const { ok, data } = await supabaseWrite('workspace_backups', backup);
    if (!ok) return false;
    if (data) savedBackup = normalizeWorkspaceBackup(data);
  }
  state.workspaceBackups = [savedBackup].concat((state.workspaceBackups || []).filter((item) => item.id !== savedBackup.id));
  state.backupSettings = {
    ...(state.backupSettings || {}),
    [companyId]: { ...backupSettingsForCompany(companyId), last_backup_at: now },
  };
  writeJson(WORKSPACE_BACKUP_CACHE_KEY, state.workspaceBackups);
  writeJson(WORKSPACE_BACKUP_SETTINGS_KEY, state.backupSettings);
  if (isLiveSupabaseSession()) await refreshPlatformBackupCopies();
  showToast('Backup snapshot created.', 'saved', 'Backups');
  render();
  return savedBackup;
}

async function downloadBackupZip(backup) {
  const target = backup || workspaceBackupById(state.selectedWorkspaceBackupId);
  if (!target) {
    showToast('Backup not found.', 'local', 'Backups');
    return;
  }
  const JSZip = await loadJsZip();
  const zip = new JSZip();
  zip.file('romio-backup.json', JSON.stringify(target.payload || buildWorkspaceBackupPayload(target.company_id), null, 2));
  const blob = await zip.generateAsync({ type: 'blob' });
  const url = URL.createObjectURL(blob);
  const anchor = document.createElement('a');
  anchor.href = url;
  anchor.download = `${slugify(target.label || 'romio-backup') || 'romio-backup'}.zip`;
  document.body.appendChild(anchor);
  anchor.click();
  anchor.remove();
  URL.revokeObjectURL(url);
}

async function importWorkspaceBackupFile(file) {
  if (!file) return;
  const check = await validateUpload(file, 'backup');
  if (!check.ok) throw new Error(check.reason);
  const JSZip = await loadJsZip();
  const zip = await JSZip.loadAsync(file);
  const entry = zip.file('romio-backup.json');
  if (!entry) throw new Error('This zip does not contain romio-backup.json.');
  const payload = JSON.parse(await entry.async('string'));
  validateWorkspaceBackupPayload(payload);
  const now = new Date().toISOString();
  const profile = activeSession()?.profile || {};
  const backup = normalizeWorkspaceBackup({
    id: `backup-${crypto.randomUUID()}`,
    company_id: payload.company_id,
    label: `${companyName(payload.company_id)} imported backup`,
    kind: 'import',
    status: 'active',
    interval_key: backupSettingsForCompany(payload.company_id).interval_key,
    payload,
    size_bytes: file.size || new Blob([JSON.stringify(payload)]).size,
    record_counts: workspaceBackupRecordCounts(payload),
    created_by: isUuid(profile.id) ? profile.id : null,
    created_by_label: profile.full_name || profile.email || 'ROM user',
    source: 'settings-import',
    created_at: now,
    updated_at: now,
  });
  let savedBackup = backup;
  if (isLiveSupabaseSession()) {
    const { ok, data } = await supabaseWrite('workspace_backups', backup);
    if (!ok) return false;
    if (data) savedBackup = normalizeWorkspaceBackup(data);
  }
  state.workspaceBackups = [savedBackup].concat((state.workspaceBackups || []).filter((item) => item.id !== savedBackup.id));
  writeJson(WORKSPACE_BACKUP_CACHE_KEY, state.workspaceBackups);
  showToast('Backup imported. Restore it when you are ready.', 'saved', 'Backups');
  render();
}

function validateWorkspaceBackupPayload(payload) {
  if (!payload || payload.version !== WORKSPACE_BACKUP_VERSION) throw new Error('This backup version is not supported.');
  if (!payload.company_id || !payload.data || typeof payload.data !== 'object') throw new Error('This backup file is missing workspace data.');
}

function replaceCompanyRows(currentRows, nextRows, companyId, normalizer) {
  const preserved = (currentRows || []).filter((row) => row.company_id !== companyId);
  return preserved.concat((nextRows || []).map(normalizer));
}

function applyWorkspaceBackupPayload(payload) {
  validateWorkspaceBackupPayload(payload);
  const companyId = payload.company_id;
  const data = payload.data || {};
  if (payload.company) state.companies = mergeCompanies(state.companies.concat([normalizeCompany(payload.company)]));
  state.jobs = replaceCompanyRows(state.jobs, data.jobs, companyId, normalizeJob);
  state.pipelineStages = replaceCompanyRows(state.pipelineStages, data.pipelineStages, companyId, (row) => ({ ...row, company_id: canonicalCompanyId(row.company_id || companyId) }));
  applyPipelineStagesForCompany(companyId);
  state.contacts = replaceCompanyRows(state.contacts, data.contacts, companyId, normalizeContact);
  state.accounts = replaceCompanyRows(state.accounts, data.accounts, companyId, normalizeAccount);
  state.deals = replaceCompanyRows(state.deals, data.deals, companyId, normalizeDeal);
  state.sites = replaceCompanyRows(state.sites, data.sites, companyId, normalizeCrmSite);
  state.proposals = replaceCompanyRows(state.proposals, data.proposals, companyId, normalizeProposal);
  state.activities = replaceCompanyRows(state.activities, data.activities, companyId, normalizeActivity);
  state.tasks = replaceCompanyRows(state.tasks, data.tasks, companyId, normalizeTask);
  state.files = replaceCompanyRows(state.files, data.files, companyId, normalizeFile);
  state.driveFolders = replaceCompanyRows(state.driveFolders, data.driveFolders, companyId, normalizeDriveFolder);
  state.forms = replaceCompanyRows(state.forms, data.forms, companyId, normalizeForm);
  state.formResponses = replaceCompanyRows(state.formResponses, data.formResponses, companyId, normalizeFormResponse);
  state.financeInvoices = replaceCompanyRows(state.financeInvoices, data.financeInvoices, companyId, normalizeFinanceInvoice);
  state.financePayments = replaceCompanyRows(state.financePayments, data.financePayments, companyId, normalizeFinancePayment);
  state.financeExpenses = replaceCompanyRows(state.financeExpenses, data.financeExpenses, companyId, normalizeFinanceExpense);
  state.financeVendors = replaceCompanyRows(state.financeVendors, data.financeVendors, companyId, normalizeFinanceVendor);
  state.pricebookVendors = replaceCompanyRows(state.pricebookVendors, data.pricebookVendors, companyId, normalizePricebookVendor);
  state.pricebookMaterials = replaceCompanyRows(state.pricebookMaterials, data.pricebookMaterials, companyId, normalizePricebookMaterial);
  state.pricebookPrices = replaceCompanyRows(state.pricebookPrices, data.pricebookPrices, companyId, normalizePricebookPrice);
  state.clientPortals = replaceCompanyRows(state.clientPortals, data.clientPortals, companyId, normalizeClientPortal);
  state.clientPortalDocuments = replaceCompanyRows(state.clientPortalDocuments, data.clientPortalDocuments, companyId, normalizeClientPortalDocument);
  state.clientPortalAnnotations = replaceCompanyRows(state.clientPortalAnnotations, data.clientPortalAnnotations, companyId, normalizeClientPortalAnnotation);
  state.clientPortalEvents = replaceCompanyRows(state.clientPortalEvents, data.clientPortalEvents, companyId, normalizeClientPortalEvent);
  state.messageConversations = replaceCompanyRows(state.messageConversations, data.messageConversations, companyId, normalizeMessageConversation);
  state.messageAccess = replaceCompanyRows(state.messageAccess, data.messageAccess, companyId, normalizeMessageAccess);
  state.messages = replaceCompanyRows(state.messages, data.messages, companyId, normalizeMessage);
  state.messageReads = replaceCompanyRows(state.messageReads, data.messageReads, companyId, normalizeMessageRead);
  state.messageAttachments = replaceCompanyRows(state.messageAttachments, data.messageAttachments, companyId, normalizeMessageAttachment);
  state.calendarEvents = replaceCompanyRows(state.calendarEvents, data.calendarEvents, companyId, normalizeCalendarEvent);
  state.roles = replaceCompanyRows(state.roles, data.roles, companyId, normalizeRole);
  state.rolePermissions = replaceCompanyRows(state.rolePermissions, data.rolePermissions, companyId, normalizeRolePermission);
  state.roleAssignments = replaceCompanyRows(state.roleAssignments, data.roleAssignments, companyId, normalizeRoleAssignment);
  state.resourceAcl = replaceCompanyRows(state.resourceAcl, data.resourceAcl, companyId, normalizeResourceAcl);
  state.fieldPermissions = replaceCompanyRows(state.fieldPermissions, data.fieldPermissions, companyId, normalizeFieldPermission);
  state.companyPlugins = replaceCompanyRows(state.companyPlugins, data.companyPlugins, companyId, normalizeCompanyPlugin);
  state.teamMembers = replaceCompanyRows(state.teamMembers, data.teamMembers, companyId, normalizeTeamMember);
  state.memberships = replaceCompanyRows(state.memberships, data.memberships, companyId, normalizeMembership);
  if (data.workspaceBuilderDoc) state.workspaceBuilderDocs = { ...(state.workspaceBuilderDocs || {}), [companyId]: normalizeWorkspaceBuilderDoc(data.workspaceBuilderDoc) };
  persistAll();
}

async function restoreWorkspaceBackup(backupId) {
  const backup = workspaceBackupById(backupId);
  if (!backup) throw new Error('Backup not found.');
  applyWorkspaceBackupPayload(backup.payload);
  if (isLiveSupabaseSession()) await persistWorkspaceBackupPayloadToSupabase(backup.payload);
  state.modal = '';
  showToast('Workspace restored from backup.', 'saved', 'Backups');
  render();
}

async function persistWorkspaceBackupPayloadToSupabase(payload) {
  const client = createSupabaseClient();
  if (!client) return;
  const data = payload?.data || {};
  const tableMap = [
    ['jobs', data.jobs, (row) => supabaseRow(row, JOB_COLS), 'id'],
    ['pipeline_stages', data.pipelineStages, (row) => ({
      company_id: row.company_id,
      kind: row.kind,
      name: row.name,
      color: row.color || '#9AA0A8',
      position: number(row.position),
    }), 'company_id,kind,name'],
    ['contacts', data.contacts, (row) => supabaseRow(row, CONTACT_COLS), 'id'],
    ['accounts', data.accounts, (row) => supabaseRow(row, ACCOUNT_COLS), 'id'],
    ['deals', data.deals, (row) => supabaseRow(row, DEAL_COLS), 'id'],
    ['crm_sites', data.sites, (row) => supabaseRow(row, SITE_COLS), 'id'],
    ['proposal_documents', data.proposals, (row) => supabaseRow(row, PROPOSAL_COLS), 'id'],
    ['activities', data.activities, (row) => supabaseRow(row, ACTIVITY_COLS), 'id'],
    ['tasks', data.tasks, taskPayload, 'id'],
    ['forms', data.forms, formPayload, 'id'],
    ['form_responses', data.formResponses, formResponsePayload, 'id'],
    ['finance_invoices', data.financeInvoices, invoicePayload, 'id'],
    ['finance_payments', data.financePayments, paymentPayload, 'id'],
    ['finance_expenses', data.financeExpenses, expensePayload, 'id'],
    ['finance_vendors', data.financeVendors, vendorPayload, 'id'],
    ['pricebook_vendors', data.pricebookVendors, (row) => row, 'id'],
    ['pricebook_materials', data.pricebookMaterials, (row) => row, 'id'],
    ['pricebook_vendor_prices', data.pricebookPrices, (row) => row, 'company_id,vendor_id,material_id'],
    ['client_portals', data.clientPortals, clientPortalPayload, 'id'],
    ['client_portal_documents', data.clientPortalDocuments, (row) => supabaseRow(clientPortalDocumentPayload(row), CLIENT_PORTAL_DOCUMENT_COLS), 'id'],
    ['client_portal_annotations', data.clientPortalAnnotations, (row) => supabaseRow(clientPortalAnnotationPayload(row), CLIENT_PORTAL_ANNOTATION_COLS), 'id'],
    ['message_conversations', data.messageConversations, messageConversationPayload, 'id'],
    ['messages', data.messages, messagePayload, 'id'],
    ['message_attachments', data.messageAttachments, messageAttachmentPayload, 'id'],
    ['message_reads', data.messageReads, messageReadPayload, 'conversation_id,profile_id'],
  ];
  for (const [table, rows, mapper, onConflict] of tableMap) {
    if (!Array.isArray(rows) || !rows.length) continue;
    const cleanRows = rows.map(mapper).filter((row) => row && Object.keys(row).length);
    if (!cleanRows.length) continue;
    const result = await client.from(table).upsert(cleanRows, { onConflict });
    if (result.error) notifySyncFailure(result.error, 'Restore');
  }
  if (data.workspaceBuilderDoc) {
    const result = await client.from('workspace_builder_state').upsert({ company_id: payload.company_id, doc: data.workspaceBuilderDoc, updated_by: isUuid(activeSession()?.profile?.id) ? activeSession().profile.id : null });
    if (result.error) notifySyncFailure(result.error, 'Restore');
  }
}

async function markWorkspaceBackupDeleted(backupId) {
  const now = new Date().toISOString();
  const existing = workspaceBackupById(backupId);
  if (!existing) return false;
  let updated = normalizeWorkspaceBackup({ ...existing, status: 'deleted', deleted_at: now, deleted_by: isUuid(activeSession()?.profile?.id) ? activeSession().profile.id : null, updated_at: now });
  if (isLiveSupabaseSession()) {
    const { ok, data } = await supabaseWrite('workspace_backups', updated);
    if (!ok) return false;
    if (data) updated = normalizeWorkspaceBackup(data);
  }
  state.workspaceBackups = (state.workspaceBackups || []).map((backup) => (backup.id === backupId ? updated : backup));
  writeJson(WORKSPACE_BACKUP_CACHE_KEY, state.workspaceBackups);
  if (isLiveSupabaseSession()) await refreshPlatformBackupCopies();
  render();
  return true;
}

async function refreshPlatformBackupCopies() {
  if (!state.platformAdmin || !isLiveSupabaseSession()) return;
  const client = createSupabaseClient();
  if (!client) return;
  const result = await safeSupabaseQuery(client.rpc('list_platform_backup_copies', { filter_company_id: null, filter_status: null, filter_kind: null }));
  if (!result.error) state.platformBackupCopies = (result.data || []).map(normalizePlatformBackupCopy);
}

async function markPlatformBackupCopyDeleted(copyId) {
  const client = createSupabaseClient();
  if (isLiveSupabaseSession() && client) {
    const result = await safeSupabaseQuery(client.rpc('mark_platform_backup_copy_deleted', { copy_id: copyId }));
    if (result.error) {
      showToast(result.error.message || 'Unable to mark backup deleted.', 'error', 'Master');
      return;
    }
  }
  const now = new Date().toISOString();
  state.platformBackupCopies = (state.platformBackupCopies || []).map((copy) => (copy.id === copyId ? normalizePlatformBackupCopy({ ...copy, status: 'deleted', deleted_at: now, updated_at: now }) : copy));
  render();
}

async function permanentlyDeletePlatformBackupCopy(copyId) {
  const client = createSupabaseClient();
  if (isLiveSupabaseSession() && client) {
    const result = await safeSupabaseQuery(client.rpc('permanently_delete_platform_backup_copy', { copy_id: copyId }));
    if (result.error) {
      showToast(result.error.message || 'Unable to delete backup copy.', 'error', 'Master');
      return;
    }
  }
  state.platformBackupCopies = (state.platformBackupCopies || []).filter((copy) => copy.id !== copyId);
  state.modal = '';
  showToast('Backup copy permanently deleted.', 'saved', 'Master');
  render();
}

// Strip app-only/derived keys before sending a row to Supabase.
function supabaseRow(payload, allowed) {
  const row = {};
  allowed.forEach((key) => { if (payload[key] !== undefined) row[key] = payload[key]; });
  return row;
}

// Tell the user when a write/delete failed to reach the server. Only surfaced
// on a live Supabase session — in local/demo mode, local-only persistence is
// the expected behavior, not a failure. Never describe ephemeral UI state as
// safely stored when the server rejected it.
function notifySyncFailure(error, action = 'Save') {
  if (!isLiveSupabaseSession()) return;
  const detail = error?.message || error?.details || '';
  showToast(detail ? `${detail} — changes were not saved.` : 'Changes could not be saved. Review the current screen and try again.', 'error', `${action} failed`);
}

async function supabaseWrite(table, row, { onConflict = 'id' } = {}) {
  if (!isLiveSupabaseSession()) return { ok: true, data: null, error: null };
  const client = createSupabaseClient();
  if (!client) return { ok: false, data: null, error: null };
  try {
    const result = await client.from(table).upsert(row, { onConflict }).select().single();
    if (!result.error && result.data) return { ok: true, data: result.data, error: null };
    if (result.error) { console.warn(`${table} write rejected:`, result.error.message || result.error, result.error.details || ''); notifySyncFailure(result.error, 'Save'); }
    return { ok: false, data: null, error: result.error };
  } catch (error) {
    console.warn(`${table} save sync failed`, error);
    notifySyncFailure(error, 'Save');
    return { ok: false, data: null, error };
  }
}

async function supabaseDelete(table, id) {
  const client = createSupabaseClient();
  if (!client) return;
  try {
    const result = await client.from(table).delete().eq('id', id);
    if (result?.error) { console.warn(`${table} delete rejected:`, result.error.message || result.error); notifySyncFailure(result.error, 'Delete'); }
  } catch (error) {
    console.warn(`${table} delete sync failed`, error);
    notifySyncFailure(error, 'Delete');
  }
}

const RECYCLE_BIN_COLS = ['id', 'company_id', 'source_type', 'source_table', 'source_id', 'item_label', 'status', 'deleted_by', 'deleted_by_label', 'deleted_at', 'restore_until', 'restored_at', 'restored_by', 'snapshot', 'created_at', 'updated_at'];

function recycleTypeConfig(type) {
  return RECYCLE_BIN_TYPES[String(type || '')] || null;
}

function recycleRecordByConfig(config) {
  const typeConfig = recycleTypeConfig(config?.type);
  if (!typeConfig || !config?.id) return null;
  const id = typeConfig.type === 'calendar_event' ? String(config.id).replace(/^manual:/, '') : String(config.id);
  return (state[typeConfig.stateKey] || []).find((record) => String(record.id) === id) || null;
}

function recycleActorId() {
  const profileId = activeSession()?.profile?.id || '';
  return isUuid(profileId) ? profileId : null;
}

function buildRecycleBinItem(record, config) {
  const typeConfig = recycleTypeConfig(config?.type);
  const now = new Date();
  const restoreUntil = new Date(now.getTime() + RECYCLE_BIN_RETENTION_DAYS * 86400000);
  const snapshot = { ...(record || {}), deleted_at: null, deleted_by: null };
  return normalizeRecycleBinItem({
    id: `recycle-${typeConfig.type}-${record.id}-${now.getTime()}`,
    company_id: record.company_id || activeCompanyId(),
    source_type: typeConfig.type,
    source_table: typeConfig.table,
    source_id: record.id,
    item_label: typeConfig.title(record),
    status: 'active',
    deleted_by: recycleActorId(),
    deleted_by_label: actorName(),
    deleted_at: now.toISOString(),
    restore_until: restoreUntil.toISOString(),
    snapshot,
    created_at: now.toISOString(),
    updated_at: now.toISOString(),
  });
}

function upsertRecycleBinItemLocal(item) {
  const normalized = normalizeRecycleBinItem(item);
  state.recycleBinItems = [normalized].concat((state.recycleBinItems || []).filter((row) => row.id !== normalized.id));
  if (!isLiveSupabaseSession() && !isReadOnlyDemo()) writeJson(RECYCLE_BIN_CACHE_KEY, state.recycleBinItems);
  return normalized;
}

async function insertRecycleBinItem(item) {
  const normalized = upsertRecycleBinItemLocal(item);
  const client = createSupabaseClient();
  if (!isLiveSupabaseSession() || !client) return { ok: true, item: normalized };
  const row = supabaseRow(normalized, RECYCLE_BIN_COLS);
  const result = await client.from('recycle_bin_items').insert(row).select().single();
  if (result.error) {
    state.recycleBinItems = state.recycleBinItems.filter((entry) => entry.id !== normalized.id);
    notifySyncFailure(result.error, 'Recycle bin');
    return { ok: false, item: normalized, error: result.error };
  }
  if (result.data) upsertRecycleBinItemLocal(normalizeRecycleBinItem(result.data));
  return { ok: true, item: result.data ? normalizeRecycleBinItem(result.data) : normalized };
}

function removeRecycleSourceLocal(typeConfig, id) {
  state[typeConfig.stateKey] = (state[typeConfig.stateKey] || []).filter((record) => String(record.id) !== String(id));
  if (typeConfig.type === 'contact' && state.selectedContactId === id) state.selectedContactId = '';
  if (typeConfig.type === 'deal' && state.selectedDealId === id) state.selectedDealId = '';
  if (typeConfig.type === 'job' && state.selectedJobId === id) state.selectedJobId = '';
  if (typeConfig.type === 'task' && state.selectedTaskId === id) state.selectedTaskId = '';
  if (typeConfig.type === 'file' && state.selectedFileId === id) state.selectedFileId = '';
  if (typeConfig.type === 'form' && state.selectedFormId === id) state.selectedFormId = '';
  if (typeConfig.type === 'form_response' && state.selectedFormResponseId === id) state.selectedFormResponseId = '';
  if (typeConfig.type === 'proposal' && state.selectedProposalId === id) state.selectedProposalId = '';
  if (typeConfig.type === 'account' && state.selectedAccountId === id) state.selectedAccountId = '';
  if (typeConfig.type === 'client_portal' && state.selectedClientPortalId === id) state.selectedClientPortalId = '';
  if (typeConfig.type === 'calendar_event' && String(state.selectedCalendarEventId || '').replace(/^manual:/, '') === id) state.selectedCalendarEventId = '';
  if (typeConfig.type === 'pricebook_vendor' && state.pricebookVendorId === id) state.pricebookVendorId = '';
  if (typeConfig.type === 'pricebook_price' && state.pbCostEditId === id) state.pbCostEditId = '';
}

function restoreRecycleSourceLocal(typeConfig, snapshot) {
  const restored = typeConfig.normalize({ ...(snapshot || {}), deleted_at: null, deleted_by: null, updated_at: new Date().toISOString() });
  state[typeConfig.stateKey] = [restored].concat((state[typeConfig.stateKey] || []).filter((record) => String(record.id) !== String(restored.id)));
  return restored;
}

async function softDeleteRecycleSource(typeConfig, record, item) {
  const client = createSupabaseClient();
  if (!isLiveSupabaseSession() || !client) return { ok: true };
  const patch = {
    deleted_at: item.deleted_at,
    deleted_by: item.deleted_by || null,
  };
  if (typeConfig.type !== 'form_response') patch.updated_at = item.deleted_at;
  const result = await client.from(typeConfig.table).update(patch).eq('id', record.id);
  if (result.error) {
    await client.from('recycle_bin_items').delete().eq('id', item.id);
    state.recycleBinItems = state.recycleBinItems.filter((entry) => entry.id !== item.id);
    notifySyncFailure(result.error, 'Delete');
    return { ok: false, error: result.error };
  }
  return { ok: true };
}

async function recycleDeleteRecord(config) {
  const typeConfig = recycleTypeConfig(config?.type);
  const record = recycleRecordByConfig(config);
  if (!typeConfig || !record) return false;
  if (typeConfig.permission && !requirePermission(typeConfig.permission, record.company_id, `Your role cannot delete this ${typeConfig.label.toLowerCase()}.`, typeConfig.label)) return false;
  const item = buildRecycleBinItem(record, config);
  const client = createSupabaseClient();
  if (isLiveSupabaseSession() && client) {
    const row = supabaseRow(item, RECYCLE_BIN_COLS);
    const result = await client.rpc('recycle_move_item', { p_item: row });
    if (result.error) {
      notifySyncFailure(result.error, 'Delete');
      return false;
    }
    upsertRecycleBinItemLocal(normalizeRecycleBinItem(result.data || item));
  } else {
    upsertRecycleBinItemLocal(item);
  }
  removeRecycleSourceLocal(typeConfig, record.id);
  persistAll();
  state.modal = '';
  state.recycleDeleteCtx = null;
  showToast(`${typeConfig.label} moved to Recycle Bin.`, isLiveSupabaseSession() ? 'live' : 'local', 'Recycle Bin');
  const redirect = config.options?.stayOnPage ? '' : typeConfig.redirect?.(record.company_id);
  if (redirect) navigate(redirect, { replace: true });
  else render();
  return true;
}

async function confirmRecycleDelete() {
  if (!state.recycleDeleteCtx) return;
  await recycleDeleteRecord(state.recycleDeleteCtx);
}

function recycleBinItemsForCompany(companyId) {
  return (state.recycleBinItems || [])
    .map(normalizeRecycleBinItem)
    .filter((item) => item.company_id === companyId && item.status === 'active')
    .sort((a, b) => Date.parse(b.deleted_at || 0) - Date.parse(a.deleted_at || 0));
}

function recycleItemById(itemId) {
  return (state.recycleBinItems || []).map(normalizeRecycleBinItem).find((item) => item.id === itemId) || null;
}

function recycleDaysLeft(item) {
  return Math.ceil((Date.parse(item.restore_until || 0) - Date.now()) / 86400000);
}

async function restoreRecycleBinItem(itemId) {
  const item = recycleItemById(itemId);
  const typeConfig = recycleTypeConfig(item?.source_type);
  if (!item || !typeConfig) return;
  if (!requirePermission('settings.manage', item.company_id, 'Your role cannot restore recycle bin items.', 'Recycle Bin')) return;
  const now = new Date().toISOString();
  const client = createSupabaseClient();
  if (isLiveSupabaseSession() && client) {
    const result = await client.rpc('recycle_restore_item', { p_item_id: item.id });
    if (result.error) { notifySyncFailure(result.error, 'Restore'); return false; }
    if (result.data) Object.assign(item, normalizeRecycleBinItem(result.data));
  }
  restoreRecycleSourceLocal(typeConfig, item.snapshot);
  state.recycleBinItems = state.recycleBinItems.map((row) => (row.id === item.id ? normalizeRecycleBinItem({ ...row, status: 'restored', restored_at: now, restored_by: recycleActorId(), updated_at: now }) : row));
  persistAll();
  showToast(`${typeConfig.label} restored.`, isLiveSupabaseSession() ? 'live' : 'local', 'Recycle Bin');
  render();
  return true;
}

async function permanentlyDeleteRecycleBinItem(itemId, options = {}) {
  const item = recycleItemById(itemId);
  const typeConfig = recycleTypeConfig(item?.source_type);
  if (!item || !typeConfig) return;
  if (!requirePermission('settings.manage', item.company_id, 'Your role cannot permanently delete recycle bin items.', 'Recycle Bin')) return;
  const snapshot = item.snapshot || {};
  const client = createSupabaseClient();
  if (isLiveSupabaseSession() && client) {
    if (typeConfig.type === 'file' && snapshot.object_path) {
      const storageResult = await client.storage.from('romio-job-files').remove([snapshot.object_path]);
      if (storageResult.error) { notifySyncFailure(storageResult.error, 'Permanent delete'); return false; }
    }
    const result = await client.rpc('recycle_permanently_delete_item', { p_item_id: item.id });
    if (result.error) { notifySyncFailure(result.error, 'Permanent delete'); return false; }
  }
  state.recycleBinItems = (state.recycleBinItems || []).filter((row) => row.id !== item.id);
  persistAll();
  state.modal = '';
  state.selectedRecycleItemId = '';
  if (!options.silent) showToast(`${typeConfig.label} permanently deleted.`, isLiveSupabaseSession() ? 'live' : 'local', 'Recycle Bin');
  if (options.renderAfter !== false) render();
  return true;
}

const ACCOUNT_COLS = ['id', 'company_id', 'name', 'type', 'industry', 'website', 'phone', 'email', 'address', 'owner_name', 'status', 'notes', 'updated_at'];
const SITE_COLS = ['id', 'company_id', 'contact_id', 'account_id', 'label', 'address', 'roof_system', 'secondary_roof_system', 'has_multiple_roof_systems', 'notes', 'updated_at'];
const DEAL_COLS = ['id', 'company_id', 'account_id', 'primary_contact_id', 'site_id', 'name', 'stage', 'status', 'value', 'probability', 'close_date', 'owner_name', 'source', 'job_id', 'line_items', 'notes', 'updated_at'];
const JOB_COLS = ['id', 'company_id', 'name', 'client_name', 'contact_name', 'site_address', 'job_type', 'stage', 'priority', 'owner_name', 'scope', 'notes', 'estimate_total', 'invoice_total', 'account_id', 'contact_id', 'deal_id', 'site_id', 'updated_at'];
const PROPOSAL_COLS = ['id', 'company_id', 'proposal_no', 'title', 'status', 'related_type', 'related_id', 'contact_id', 'deal_id', 'job_id', 'client', 'draft', 'total', 'public_token', 'accepted_by', 'accepted_email', 'accepted_at', 'declined_at', 'viewed_at', 'sent_at', 'created_by', 'created_by_label', 'created_at', 'updated_at'];
const ACTIVITY_COLS = ['id', 'company_id', 'type', 'subject', 'body', 'related_type', 'related_id', 'account_id', 'contact_id', 'site_id', 'deal_id', 'job_id', 'due_at', 'completed_at', 'owner_name', 'updated_at'];
const CONTACT_COLS = ['id', 'company_id', 'name', 'phone', 'email', 'location', 'stage', 'value', 'owner_name', 'account_id', 'title', 'source', 'temperature', 'pay_type', 'roof_system', 'secondary_roof_system', 'has_multiple_roof_systems', 'last_activity_at', 'notes', 'country_code', 'country', 'province', 'city', 'barangay', 'street', 'block_no', 'zip', 'lat', 'lng', 'updated_at'];
const CLIENT_PORTAL_DOCUMENT_COLS = ['id', 'company_id', 'portal_id', 'version_group_id', 'version_number', 'is_current', 'review_status', 'scale', 'scale_unit', 'bucket_id', 'object_path', 'file_name', 'mime_type', 'size_bytes', 'page_count', 'uploaded_by', 'created_at', 'updated_at'];
const CLIENT_PORTAL_ANNOTATION_COLS = ['id', 'company_id', 'portal_id', 'document_id', 'page_number', 'guest_name', 'author_profile_id', 'annotation_type', 'payload', 'resolved_at', 'created_at', 'updated_at'];

function emptyToNull(row, keys) {
  keys.forEach((key) => { if (row[key] === '') row[key] = null; });
  return row;
}

async function saveAccount(form) {
  const payload = normalizeAccount(Object.fromEntries(new FormData(form).entries()));
  payload.id = payload.id || `account-${crypto.randomUUID()}`;
  payload.updated_at = new Date().toISOString();
  const { ok, data } = await supabaseWrite('accounts', supabaseRow(payload, ACCOUNT_COLS));
  if (!ok) return false;
  const savedAccount = data ? normalizeAccount(data) : payload;
  upsertAccount(savedAccount);
  state.selectedAccountId = savedAccount.id;
  state.modal = '';
  showToast(`${payload.name} saved.`, ok ? 'live' : 'local', 'Accounts');
  render();
  return true;
}

async function deleteAccount(id) {
  if (!id) return;
  await recycleDeleteRecord({ type: 'account', id });
}

async function saveDeal(form) {
  const payload = normalizeDeal(Object.fromEntries(new FormData(form).entries()));
  payload.id = payload.id || `deal-${crypto.randomUUID()}`;
  // Keep status in sync with terminal stage names so KPIs / badges stay correct.
  if (/^won/i.test(payload.stage)) payload.status = 'won';
  else if (/^lost/i.test(payload.stage)) payload.status = 'lost';
  else if (payload.status !== 'open' && !/^won|^lost/i.test(payload.stage)) payload.status = 'open';
  payload.updated_at = new Date().toISOString();
  const previous = dealById(payload.id);
  const row = emptyToNull(supabaseRow(payload, DEAL_COLS), ['account_id', 'primary_contact_id', 'site_id', 'close_date', 'job_id']);
  const { ok, data } = await supabaseWrite('deals', row);
  if (!ok) return false;
  const savedDeal = data ? normalizeDeal(data) : payload;
  upsertDeal(savedDeal);
  if (previous && previous.stage !== payload.stage) {
    await logActivity({ type: 'stage_change', subject: `Stage -> ${payload.stage}`, related_type: 'deal', related_id: payload.id, account_id: payload.account_id });
  }
  state.selectedDealId = savedDeal.id;
  state.modal = '';
  showToast(`${payload.name} saved.`, ok ? 'live' : 'local', 'Quotes');
  render();
  return true;
}

async function persistDeal(deal, label = 'Quote saved.') {
  const payload = normalizeDeal({ ...deal, updated_at: new Date().toISOString() });
  if (/^won/i.test(payload.stage)) payload.status = 'won';
  else if (/^lost/i.test(payload.stage)) payload.status = 'lost';
  else if (payload.status !== 'open' && !/^won|^lost/i.test(payload.stage)) payload.status = 'open';
  const row = emptyToNull(supabaseRow(payload, DEAL_COLS), ['account_id', 'primary_contact_id', 'site_id', 'close_date', 'job_id']);
  const { ok, data } = await supabaseWrite('deals', row);
  if (!ok) return false;
  const savedDeal = data ? normalizeDeal(data) : payload;
  upsertDeal(savedDeal);
  showToast(label, ok ? 'live' : 'local', 'Quotes');
  render();
  return savedDeal;
}

function normalizeDealLineItems(raw) {
  const rows = typeof raw === 'string' ? safeJson(raw, []) : raw;
  return (Array.isArray(rows) ? rows : []).map((item) => {
    const quantity = Math.max(0, number(item.quantity || item.qty || 1));
    const unitCost = Math.max(0, number(item.unit_cost));
    const margin = Math.max(0, number(item.margin_pct ?? item.margin ?? 30));
    const manualSell = item.unit_sell === '' || item.unit_sell === null || item.unit_sell === undefined ? null : Math.max(0, number(item.unit_sell));
    return {
      id: String(item.id || `line-${crypto.randomUUID()}`),
      material_id: String(item.material_id || ''),
      vendor_price_id: String(item.vendor_price_id || ''),
      name: String(item.name || 'Line item').trim() || 'Line item',
      category: String(item.category || '').trim(),
      sku: String(item.sku || '').trim(),
      unit: String(item.unit || 'each').trim() || 'each',
      quantity,
      unit_cost: unitCost,
      margin_pct: margin,
      unit_sell: manualSell,
      source: String(item.source || (item.vendor_price_id ? 'price_book' : 'manual')),
    };
  }).filter((item) => item.name);
}

function dealLineSell(item) {
  if (item.unit_sell !== null && item.unit_sell !== undefined) return number(item.unit_sell);
  return number(item.unit_cost) * (1 + number(item.margin_pct) / 100);
}

function dealLineItemsTotal(deal) {
  const line_items = normalizeDealLineItems(deal?.line_items);
  return line_items.reduce((total, item) => total + number(item.quantity) * dealLineSell(item), 0);
}

function quoteMaterialOptions(companyId) {
  return pbRows(companyId)
    .sort((a, b) => a.material.localeCompare(b.material) || a.cost - b.cost)
    .map((row) => [`${row.id}`, `${row.material} - ${row.vendor} ($${pbMoney(row.cost)}/${row.unit})`]);
}

function pricebookLineItemFromPrice(priceId, quantity, marginPct) {
  const row = pbRows(activeCompanyId()).find((item) => item.id === priceId);
  if (!row) return null;
  return {
    id: `line-${crypto.randomUUID()}`,
    material_id: row.materialId,
    vendor_price_id: row.id,
    name: row.material,
    category: row.category,
    sku: row.sku === '-' ? '' : row.sku,
    unit: row.unit,
    quantity,
    unit_cost: row.cost,
    margin_pct: marginPct,
    unit_sell: null,
    source: 'price_book',
  };
}

function renderDealLineItems(deal, companyId) {
  const lineItems = normalizeDealLineItems(deal.line_items);
  const materialOptions = quoteMaterialOptions(companyId);
  const total = dealLineItemsTotal(deal);
  return `
    <div class="sf-card quote-line-items">
      <div class="sf-card-head"><i class="ti ti-receipt-2"></i>Quote line items <span>${money(total)}</span></div>
      <div class="quote-line-table">
        <div class="quote-line-head"><span>Item</span><span>Qty</span><span>Cost</span><span>Sell</span><span>Total</span><span></span></div>
        ${lineItems.map((item) => `
          <div class="quote-line-row">
            <span><strong>${h(item.name)}</strong><small>${h([item.category, item.sku, item.source === 'price_book' ? 'Price Book' : 'Manual'].filter(Boolean).join(' / '))}</small></span>
            <span>${h(String(item.quantity))} ${h(item.unit)}</span>
            <span>${money(item.unit_cost)}</span>
            <span>${money(dealLineSell(item))}</span>
            <span>${money(number(item.quantity) * dealLineSell(item))}</span>
            <button type="button" data-action="remove-quote-line-item" data-deal-id="${h(deal.id)}" data-line-id="${h(item.id)}" aria-label="Remove line item"><i class="ti ti-trash"></i></button>
          </div>
        `).join('') || '<div class="quote-line-empty">No line items yet. Add Price Book or manual items below.</div>'}
      </div>
      <form class="quote-line-add" data-quote-line-item-form>
        <input type="hidden" name="deal_id" value="${h(deal.id)}" />
        <select name="vendor_price_id">
          <option value="">Manual line item</option>
          ${materialOptions.map(([value, label]) => `<option value="${h(value)}">${h(label)}</option>`).join('')}
        </select>
        <input name="name" placeholder="Manual item name" />
        <input name="quantity" type="number" min="0" step="0.01" value="1" aria-label="Quantity" />
        <input name="unit" placeholder="unit" value="each" aria-label="Unit" />
        <input name="unit_cost" type="number" min="0" step="0.01" placeholder="Cost" aria-label="Unit cost" />
        <input name="margin_pct" type="number" min="0" step="1" value="30" aria-label="Margin percent" />
        <button class="btn btn-primary" type="submit"><i class="ti ti-plus"></i>Add</button>
      </form>
    </div>
  `;
}

async function addQuoteLineItem(form) {
  const data = Object.fromEntries(new FormData(form).entries());
  const deal = dealById(data.deal_id);
  if (!deal) return;
  const quantity = Math.max(0, number(data.quantity || 1));
  const marginPct = Math.max(0, number(data.margin_pct || 30));
  let nextItem = data.vendor_price_id ? pricebookLineItemFromPrice(String(data.vendor_price_id), quantity, marginPct) : null;
  if (!nextItem) {
    const name = String(data.name || '').trim();
    if (!name) return showToast('Enter a line item name or choose a Price Book item.', 'local', 'Quotes');
    nextItem = {
      id: `line-${crypto.randomUUID()}`,
      material_id: '',
      vendor_price_id: '',
      name,
      category: 'Manual',
      sku: '',
      unit: String(data.unit || 'each').trim() || 'each',
      quantity,
      unit_cost: Math.max(0, number(data.unit_cost)),
      margin_pct: marginPct,
      unit_sell: null,
      source: 'manual',
    };
  }
  const line_items = normalizeDealLineItems(deal.line_items).concat(nextItem);
  await persistDeal({ ...deal, line_items, value: dealLineItemsTotal({ line_items }) }, 'Quote line item added.');
}

async function removeQuoteLineItem(dealId, lineId) {
  const deal = dealById(dealId);
  if (!deal) return;
  const line_items = normalizeDealLineItems(deal.line_items).filter((item) => item.id !== lineId);
  await persistDeal({ ...deal, line_items, value: dealLineItemsTotal({ line_items }) }, 'Quote line item removed.');
}

async function persistProposal(proposal, label = 'Proposal saved.') {
  const payload = normalizeProposal({ ...proposal, updated_at: new Date().toISOString() });
  const row = emptyToNull(supabaseRow(payload, PROPOSAL_COLS), ['contact_id', 'deal_id', 'job_id', 'accepted_at', 'declined_at', 'viewed_at', 'sent_at']);
  const { ok, data } = await supabaseWrite('proposal_documents', row);
  if (!ok) return false;
  const savedProposal = data ? normalizeProposal(data) : payload;
  upsertProposal(savedProposal);
  showToast(label, ok ? 'live' : 'local', 'Proposals');
  return savedProposal;
}

async function setDealStage(dealId, stage) {
  const deal = dealById(dealId);
  if (!deal || !stage || deal.stage === stage) return;
  if (!await persistDeal({ ...deal, stage }, 'Quote stage saved.')) return false;
  await logActivity({ type: 'stage_change', subject: `Stage -> ${stage}`, related_type: 'deal', related_id: dealId, account_id: deal.account_id });
  return true;
}

function markDealNextStage(dealId) {
  const deal = dealById(dealId);
  const names = dealStageNames();
  const idx = deal ? names.indexOf(deal.stage) : -1;
  if (!deal || idx < 0 || idx >= names.length - 1) return;
  setDealStage(deal.id, names[idx + 1]);
}

function patchDealField(dealId, key, raw) {
  const deal = dealById(dealId);
  if (!deal) return;
  let value;
  if (key === 'value' || key === 'probability') value = Number(String(raw).replace(/[^0-9.]/g, '')) || 0;
  else value = String(raw).trim();
  if (deal[key] === value) { render(); return; }
  persistDeal({ ...deal, [key]: value }, 'Quote field saved.');
}

function beginDealInlineEdit(span) {
  const key = span.dataset.dealEdit;
  const dealId = span.dataset.dealId;
  const deal = dealById(dealId);
  if (!deal) return;
  const input = document.createElement('input');
  input.className = 'sf-edit-input';
  input.value = (key === 'value' || key === 'probability') ? (deal[key] || 0) : (deal[key] || '');
  span.replaceWith(input);
  input.focus();
  input.select();
  let done = false;
  const commit = () => { if (done) return; done = true; patchDealField(dealId, key, input.value); };
  input.addEventListener('blur', commit);
  input.addEventListener('keydown', (ev) => {
    if (ev.key === 'Enter') { ev.preventDefault(); commit(); }
    if (ev.key === 'Escape') { done = true; render(); }
  });
}

async function createDealTask(dealId, title) {
  const deal = dealById(dealId);
  const clean = String(title || '').trim();
  if (!deal || !clean) return;
  if (!requirePermission('tasks.manage', deal.company_id, 'Your role cannot create tasks.', 'Tasks')) return false;
  const creatorId = activeTaskCreatorId(deal.company_id);
  if (!creatorId) {
    showToast('Your signed-in profile is missing a task creator ID.', 'error', 'Tasks');
    return false;
  }
  const payload = normalizeTask({
    id: `task-${crypto.randomUUID()}`,
    company_id: deal.company_id,
    title: clean,
    contact_id: deal.primary_contact_id,
    creator_id: creatorId,
    status: 'todo',
    due: isoDate(1),
  });
  const client = createSupabaseClient();
  let savedTask = payload;
  if (client && isLiveSupabaseSession()) {
    const result = await safeSupabaseQuery(client.from('tasks').insert(taskPayload(payload)).select().single());
    if (result.error) {
      notifySyncFailure(result.error, 'Task create');
      return false;
    }
    if (!result.data) {
      notifySyncFailure(new Error('Task insert returned no record.'), 'Task create');
      return false;
    }
    savedTask = normalizeTask(result.data);
  }
  upsertTask(savedTask);
  render();
  return savedTask;
}

async function logDealActivity(dealId, type, subject, body = '') {
  const deal = dealById(dealId);
  if (!deal) return;
  const activity = await logActivity({ type, subject, body, related_type: 'deal', related_id: dealId, account_id: deal.account_id });
  render();
  return activity;
}

async function createDealProposal(dealId) {
  const deal = dealById(dealId);
  if (!deal) return;
  const estimateStage = dealStageNames().find((stage) => /estimate|proposal/i.test(stage)) || 'Estimate Sent';
  if (estimateStage && resolvePipelineStage('deals', deal.stage, deal.company_id) !== estimateStage) {
    await setDealStage(deal.id, estimateStage);
  }
  await logDealActivity(deal.id, 'email', 'Proposal prepared', 'Proposal/estimate work started from Quick Create.');
  openDockedActivityComposer('deal', deal.id, 'Email');
}

function dealQuickCreate(dealId, kind) {
  if (kind === 'Task' || kind === 'New Task') return openDockedActivityComposer('deal', dealId, 'New Task');
  if (kind === 'Note') return openDockedActivityComposer('deal', dealId, 'Note');
  if (kind === 'Call Log' || kind === 'Log a Call') return openDockedActivityComposer('deal', dealId, 'Log a Call');
  if (kind === 'Meeting' || kind === 'New Event') return openDockedActivityComposer('deal', dealId, 'New Event');
  if (kind === 'Estimate' || kind === 'New Estimate') return openEstimateBuilder('deal', dealId);
  if (kind === 'Proposal') return openProposalBuilder('deal', dealId);
  if (kind === 'Follow') return showToast('Following this quote.', 'local', 'Quotes');
  return showToast(`${kind} isn't set up yet.`, 'local', 'Quotes');
}

async function postDealNote(form) {
  const data = Object.fromEntries(new FormData(form).entries());
  const text = String(data.body || '').trim();
  const dealId = String(data.deal_id || '');
  if (!text) return;
  const tab = state.dealActivityTab || 'Email';
  if (tab === 'New Task') return createDealTask(dealId, text);
  const typeMap = { Email: 'email', 'Log a Call': 'call', 'New Event': 'meeting' };
  await logDealActivity(dealId, typeMap[tab] || 'note', '', text);
}

async function deleteDeal(id) {
  if (!id) return;
  await recycleDeleteRecord({ type: 'deal', id });
}

async function logActivity(input) {
  // Resolve a real account_id: explicit, valid, or derived from the related record.
  let accountId = accountById(input.account_id) ? input.account_id : '';
  let contactId = input.contact_id ? String(input.contact_id) : '';
  let siteId = input.site_id ? String(input.site_id) : '';
  let dealId = input.deal_id ? String(input.deal_id) : '';
  let jobId = input.job_id ? String(input.job_id) : '';
  if (!accountId) {
    if (input.related_type === 'account') accountId = input.related_id;
    else if (input.related_type === 'deal') accountId = dealById(input.related_id)?.account_id || '';
    else if (input.related_type === 'contact') accountId = contactById(input.related_id)?.account_id || '';
    else if (input.related_type === 'job') accountId = jobById(input.related_id)?.account_id || '';
  }
  if (input.related_type === 'contact') contactId ||= String(input.related_id || '');
  if (input.related_type === 'deal') dealId ||= String(input.related_id || '');
  if (input.related_type === 'job') jobId ||= String(input.related_id || '');
  const relatedJob = jobById(jobId);
  const relatedDeal = dealById(dealId || relatedJob?.deal_id);
  if (relatedDeal) dealId ||= relatedDeal.id;
  contactId ||= relatedJob?.contact_id || relatedDeal?.primary_contact_id || '';
  siteId ||= relatedJob?.site_id || relatedDeal?.site_id || (contactId ? crmSitesForContact(contactId)[0]?.id : '') || '';
  accountId ||= relatedJob?.account_id || relatedDeal?.account_id || contactById(contactId)?.account_id || '';
  if (!accountById(accountId)) accountId = '';
  const payload = normalizeActivity({
    ...input,
    id: input.id || `activity-${crypto.randomUUID()}`,
    company_id: activeCompanyId(),
    account_id: accountId,
    contact_id: contactId,
    site_id: siteId,
    deal_id: dealId,
    job_id: jobId,
    owner_name: input.owner_name || activeSession().profile.full_name || '',
    completed_at: input.completed_at || (input.type === 'note' || input.type === 'stage_change' ? new Date().toISOString() : input.completed_at),
  });
  payload.updated_at = new Date().toISOString();
  const row = emptyToNull(supabaseRow(payload, ACTIVITY_COLS), ['account_id', 'contact_id', 'site_id', 'deal_id', 'job_id', 'due_at', 'completed_at']);
  const { ok, data } = await supabaseWrite('activities', row);
  if (!ok) return false;
  const savedActivity = data ? normalizeActivity(data) : payload;
  upsertActivity(savedActivity);
  // Stamp last_activity_at on a related contact.
  if (contactId) {
    const contact = contactById(contactId);
    if (contact) {
      const updated = { ...contact, last_activity_at: payload.completed_at || payload.created_at, updated_at: new Date().toISOString() };
      const contactResult = await supabaseWrite('contacts', emptyToNull(supabaseRow(updated, CONTACT_COLS), ['account_id']));
      if (contactResult.ok) upsertContact(contactResult.data ? normalizeContact(contactResult.data) : updated);
    }
  }
  return savedActivity;
}

async function saveActivityForm(form) {
  const formData = Object.fromEntries(new FormData(form).entries());
  const activity = await logActivity({
    type: formData.type,
    subject: formData.subject,
    body: formData.body,
    related_type: formData.related_type,
    related_id: formData.related_id,
    account_id: formData.account_id,
  });
  if (!activity) return false;
  state.modal = '';
  showToast('Activity logged.', isLiveSupabaseSession() ? 'live' : 'local', 'CRM');
  render();
  return true;
}

async function deleteActivity(id) {
  if (!id) return;
  await recycleDeleteRecord({ type: 'activity', id, options: { stayOnPage: true } });
}

// Convert a won deal into a production Job (interconnect CRM -> Jobs).
async function convertDealToJob(dealId) {
  const deal = dealById(dealId);
  if (!deal) return;
  const companyId = deal.company_id;
  if (!requirePermission('jobs.manage', companyId, 'Your role cannot create jobs.', 'Jobs')) return;
  if (!requirePermission('crm.view', companyId, 'Your role cannot update this quote.', 'Quotes')) return;
  const account = accountById(deal.account_id);
  const contact = contactById(deal.primary_contact_id);
  const site = crmSiteById(deal.site_id);
  const job = normalizeJob({
    id: '',
    company_id: companyId,
    name: deal.name,
    client_name: account?.name || '',
    contact_name: contact?.name || '',
    site_address: site?.address || account?.address || contact?.location || '',
    owner_name: deal.owner_name,
    estimate_total: deal.value,
    stage: pipelineStages('jobs', companyId)[0]?.name || jobStageNames()[0],
    account_id: deal.account_id,
    contact_id: deal.primary_contact_id,
    deal_id: deal.id,
    site_id: deal.site_id,
    scope: deal.notes,
  });
  job.id = crypto.randomUUID();
  job.updated_at = new Date().toISOString();
  const wonStage = dealStageNames().find((name) => /win|won/i.test(name)) || deal.stage;
  const updatedDeal = normalizeDeal({ ...deal, status: 'won', stage: wonStage, job_id: job.id, updated_at: new Date().toISOString() });
  let savedJob = job;
  let savedDeal = updatedDeal;
  let conversionCreated = true;
  const client = createSupabaseClient();
  if (isLiveSupabaseSession()) {
    if (!client) {
      notifySyncFailure(new Error('Supabase client is unavailable.'), 'Quote conversion');
      return false;
    }
    const result = await safeSupabaseQuery(client.rpc('convert_deal_to_job', {
      p_job: jobSupabaseRow(job),
      p_deal: emptyToNull(supabaseRow(updatedDeal, DEAL_COLS), ['account_id', 'primary_contact_id', 'site_id', 'close_date', 'job_id']),
    }));
    if (result.error) {
      notifySyncFailure(result.error, 'Quote conversion');
      return false;
    }
    if (!result.data?.job || !result.data?.deal) {
      notifySyncFailure(new Error('Quote conversion returned an incomplete result.'), 'Quote conversion');
      return false;
    }
    savedJob = normalizeJob(result.data?.job);
    savedDeal = normalizeDeal(result.data?.deal);
    conversionCreated = result.data?.created !== false;
  }
  upsertJob(savedJob);
  upsertDeal(savedDeal);
  if (conversionCreated) await logActivity({ type: 'system', subject: 'Quote converted -> Job created', body: deal.name, related_type: 'deal', related_id: deal.id, account_id: deal.account_id });
  state.selectedJobId = savedJob.id;
  state.modal = '';
  showToast('Quote converted to job.', isLiveSupabaseSession() ? 'live' : 'local', 'Quotes');
  navigate(companyPath('jobs', { tab: 'profile', job_id: savedJob.id }, companyId));
  return true;
}

function crmAccounts(companyId = activeCompanyId()) {
  const groups = new Map();
  companyJobs(companyId).forEach((job) => {
    const accountName = String(job.client_name || '').trim() || 'Unassigned customer';
    const key = `account-${slugify(accountName.toLowerCase()) || 'unassigned'}`;
    if (!groups.has(key)) {
      groups.set(key, {
        key,
        name: accountName,
        jobs: [],
      });
    }
    groups.get(key).jobs.push(job);
  });

  return Array.from(groups.values()).map((account) => {
    const jobs = account.jobs
      .slice()
      .sort((a, b) => Date.parse(b.updated_at || b.created_at || 0) - Date.parse(a.updated_at || a.created_at || 0));
    const latestJob = jobs[0] || null;
    const jobIds = jobs.map((job) => job.id);
    const tasks = companyTasks(companyId).filter((task) => jobIds.includes(task.project_id));
    const forms = companyForms(companyId).filter((form) => jobIds.includes(form.linked_job_id));
    const files = companyFiles(companyId).filter((file) => jobIds.includes(file.job_id));
    const contacts = compactUnique(jobs.map((job) => job.contact_name));
    const owners = compactUnique(jobs.map((job) => job.owner_name));
    const addresses = compactUnique(jobs.map((job) => job.site_address));
    const priority = jobs
      .map((job) => job.priority || 'Medium')
      .sort((a, b) => priorityRank(b) - priorityRank(a))[0] || 'Medium';

    return {
      ...account,
      jobs,
      tasks,
      latestJob,
      contacts,
      owners,
      addresses,
      forms,
      files,
      primaryContact: contacts[0] || 'No contact',
      owner: owners[0] || 'Unassigned',
      stage: latestJob?.stage || 'Lead',
      priority,
      estimateTotal: sum(jobs, 'estimate_total'),
      fileCount: files.length,
      formCount: forms.length,
      updatedAt: latestJob?.updated_at || latestJob?.created_at || new Date().toISOString(),
      subtitle: addresses[0] || `${jobs.length} linked job${jobs.length === 1 ? '' : 's'}`,
    };
  }).sort((a, b) => Date.parse(b.updatedAt || 0) - Date.parse(a.updatedAt || 0));
}

function filteredCrmAccounts(companyId = activeCompanyId()) {
  const query = state.crmQuery.trim().toLowerCase();
  return crmAccounts(companyId).filter((account) => {
    if (state.crmStageFilter !== 'all' && !account.jobs.some((job) => job.stage === state.crmStageFilter)) return false;
    if (state.crmOwnerFilter !== 'all' && !account.owners.includes(state.crmOwnerFilter)) return false;
    if (!query) return true;
    return [
      account.name,
      account.primaryContact,
      account.owner,
      account.stage,
      ...account.addresses,
      ...account.contacts,
      ...account.jobs.map((job) => job.name),
    ].some((value) => String(value || '').toLowerCase().includes(query));
  });
}

function crmAccountByKey(companyId, key) {
  return crmAccounts(companyId).find((account) => account.key === key) || null;
}

function crmOwnerOptions(companyId = activeCompanyId()) {
  return compactUnique(companyJobs(companyId).map((job) => job.owner_name)).sort((a, b) => a.localeCompare(b));
}

function timeSummary(companyId = activeCompanyId()) {
  const memberId = activeSession().profile.member_id || '';
  const tasks = companyTasks(companyId).slice().sort(taskSortForOperations);
  const open = tasks.filter(isOpenTask);
  const dueToday = open.filter((task) => task.due === isoDate(0));
  const overdue = open.filter((task) => daysUntil(task.due) < 0);
  const thisWeek = open.filter((task) => {
    const days = daysUntil(task.due);
    return days >= 0 && days <= 7;
  });
  const assignedToMe = open.filter((task) => task.assignee_id === memberId);
  const review = open.filter((task) => ['review', 'pending'].includes(task.status));
  const done = tasks.filter((task) => task.status === 'done');
  const focus = compactUnique(overdue.concat(dueToday, assignedToMe, review, thisWeek).map((task) => task.id))
    .map((id) => tasks.find((task) => task.id === id))
    .filter(Boolean)
    .sort(taskSortForOperations);
  return { tasks, open, dueToday, overdue, thisWeek, assignedToMe, review, done, focus };
}

function approvalItems(companyId = activeCompanyId()) {
  const formApprovals = companyForms(companyId)
    .filter((form) => (form.require_approval || form.type === 'Client approval') && !['Archived', 'Closed', 'Approved'].includes(form.status))
    .map((form) => ({
      id: `form:${form.id}`,
      title: form.title,
      meta: jobById(form.linked_job_id)?.name || form.description || 'Company form',
      type: 'Form approval',
      owner: memberName(form.creator_id),
      status: form.status,
      updatedAt: form.updated_at || form.created_at,
      href: companyPath('forms', { form_id: form.id }, companyId),
    }));
  const taskApprovals = companyTasks(companyId)
    .filter((task) => ['review', 'pending'].includes(task.status))
    .map((task) => ({
      id: `task:${task.id}`,
      title: task.title,
      meta: jobById(task.project_id)?.name || task.description || 'Company task',
      type: 'Task review',
      owner: memberName(task.assignee_id),
      status: statusLabel(task.status),
      updatedAt: task.updated_at || task.due,
      href: companyPath('tasks', { ...(task.project_id ? { job_id: task.project_id } : {}), task_id: task.id }, companyId),
    }));
  const accessApprovals = state.memberships
    .filter((membership) => membership.company_id === companyId && membership.status !== 'active')
    .map((membership) => ({
      id: `access:${membership.profile_id || membership.member_id}`,
      title: memberName(membership.member_id || membership.profile_id),
      meta: `${titleCase(membership.role)} access request`,
      type: 'Access request',
      owner: 'ROM admin',
      status: titleCase(membership.status),
      updatedAt: new Date().toISOString(),
      href: companyPath('settings', { tab: 'access' }, companyId),
    }));
  return formApprovals.concat(taskApprovals, accessApprovals)
    .sort((a, b) => Date.parse(b.updatedAt || 0) - Date.parse(a.updatedAt || 0));
}

function activeTimerForCompany(companyId = activeCompanyId()) {
  const timer = state.activeTimer;
  if (!timer || timer.company_id !== companyId) return null;
  return timer;
}

function timeEntriesForCompany(companyId = activeCompanyId()) {
  return state.timeEntries
    .filter((entry) => entry.company_id === companyId)
    .sort((a, b) => Date.parse(b.started_at || 0) - Date.parse(a.started_at || 0));
}

function totalTimeForCompany(companyId = activeCompanyId(), sinceMs = 0) {
  return timeEntriesForCompany(companyId)
    .filter((entry) => Date.parse(entry.started_at || 0) >= sinceMs)
    .reduce((total, entry) => total + number(entry.duration_ms), 0);
}

function startClock(companyId = activeCompanyId(), taskId = '') {
  if (!requirePermission('time.track', companyId, 'Your role cannot track time in this workspace.', 'Time')) return;
  if (state.activeTimer) stopClock(false);
  const task = taskId ? taskById(taskId) : null;
  state.activeTimer = {
    id: `timer-${crypto.randomUUID()}`,
    company_id: companyId,
    user_id: activeSession().profile.member_id || activeSession().profile.id,
    task_id: task?.company_id === companyId ? task.id : '',
    task_title: task?.company_id === companyId ? task.title : '',
    started_at: new Date().toISOString(),
  };
  persistTimeState();
  state.sync = { label: 'Clock started locally', mode: 'local' };
  render();
}

function stopClock(shouldRender = true) {
  const timer = state.activeTimer;
  if (!timer) return;
  const endedAt = new Date().toISOString();
  const durationMs = Math.max(0, Date.parse(endedAt) - Date.parse(timer.started_at || endedAt));
  state.timeEntries.unshift({
    id: `time-${crypto.randomUUID()}`,
    company_id: timer.company_id,
    user_id: timer.user_id,
    task_id: timer.task_id || '',
    task_title: timer.task_title || '',
    started_at: timer.started_at,
    ended_at: endedAt,
    duration_ms: durationMs,
    notes: timer.task_title ? 'Task timer' : 'General shift',
  });
  state.activeTimer = null;
  persistTimeState();
  state.sync = { label: 'Clock stopped locally', mode: 'local' };
  if (shouldRender) render();
}

function isOpenTask(task) {
  return task.status !== 'done';
}

function taskSortForOperations(a, b) {
  const dateDiff = Date.parse(a.due || 0) - Date.parse(b.due || 0);
  if (dateDiff) return dateDiff;
  return priorityRank(b.priority) - priorityRank(a.priority);
}

function companyFinanceInvoices(companyId = activeCompanyId()) {
  return state.financeInvoices
    .filter((invoice) => invoice.company_id === companyId)
    .sort(dateDesc('updated_at'));
}

function companyFinancePayments(companyId = activeCompanyId()) {
  return state.financePayments.filter((payment) => payment.company_id === companyId);
}

function companyFinanceExpenses(companyId = activeCompanyId()) {
  return state.financeExpenses
    .filter((expense) => expense.company_id === companyId)
    .sort(dateDesc('updated_at'));
}

function companyFinanceVendors(companyId = activeCompanyId()) {
  return state.financeVendors.filter((vendor) => vendor.company_id === companyId);
}

function financeInvoiceById(id) {
  return state.financeInvoices.find((invoice) => invoice.id === id) || null;
}

function financeExpenseById(id) {
  return state.financeExpenses.find((expense) => expense.id === id) || null;
}

function financeVendorById(id) {
  return state.financeVendors.find((vendor) => vendor.id === id) || null;
}

function financeVendorName(id) {
  return financeVendorById(id)?.name || 'No vendor';
}

function paymentsForInvoice(invoiceId) {
  return state.financePayments.filter((payment) => payment.invoice_id === invoiceId).sort(dateDesc('received_at'));
}

function invoicePaid(invoiceId) {
  return sum(paymentsForInvoice(invoiceId), 'amount');
}

function invoiceBalance(invoiceId) {
  const invoice = financeInvoiceById(invoiceId);
  return Math.max(0, number(invoice?.total) - invoicePaid(invoiceId));
}

function invoiceStatus(invoice) {
  const balance = invoiceBalance(invoice.id);
  if (balance <= 0 && number(invoice.total) > 0) return 'Paid';
  if (balance < number(invoice.total)) return 'Partially paid';
  if (invoice.status === 'Sent' && daysPastDue(invoice.due_date) > 0) return 'Overdue';
  return invoice.status;
}

function financeSummary(companyId = activeCompanyId()) {
  const invoices = companyFinanceInvoices(companyId);
  const payments = companyFinancePayments(companyId);
  const expenses = companyFinanceExpenses(companyId).filter((expense) => ['Approved', 'Paid'].includes(expense.status));
  const aging = { current: 0, thirty: 0, sixty: 0, overSixty: 0 };
  invoices.forEach((invoice) => {
    const balance = invoiceBalance(invoice.id);
    if (!balance) return;
    const days = daysPastDue(invoice.due_date);
    if (days <= 0) aging.current += balance;
    else if (days <= 30) aging.thirty += balance;
    else if (days <= 60) aging.sixty += balance;
    else aging.overSixty += balance;
  });
  const collected = sum(payments, 'amount');
  const expenseTotal = sum(expenses, 'amount');
  return {
    pipeline: sum(companyJobs(companyId), 'estimate_total'),
    invoiced: sum(invoices, 'total'),
    collected,
    outstanding: invoices.reduce((total, invoice) => total + invoiceBalance(invoice.id), 0),
    expenses: expenseTotal,
    net: collected - expenseTotal,
    aging,
  };
}

function filteredTasks(companyId = activeCompanyId(), jobId = '') {
  const q = state.query.trim().toLowerCase();
  return companyTasks(companyId).filter((task) => {
    if (jobId && task.project_id !== jobId) return false;
    if (state.taskStatusFilter !== 'all' && task.status !== state.taskStatusFilter) return false;
    if (state.taskPriorityFilter !== 'all' && task.priority !== state.taskPriorityFilter) return false;
    if (!q) return true;
    return [task.title, task.description, taskTypeLabel(task.type), memberName(task.assignee_id), jobById(task.project_id)?.name]
      .some((value) => String(value || '').toLowerCase().includes(q));
  });
}

function allowedCompanies() {
  const ids = allowedCompanyIds();
  return state.companies.filter((company) => ids.includes(company.id));
}

function can(permission, companyId = activeCompanyId()) {
  if (!permission) return true;
  // ROM embed: the workspace ROLE decides everything, not the module's internal
  // role model. viewWorkspace gates every "view" action; any create/edit/interact
  // action needs write access (post/editTiles/manage). This makes Viewer truly
  // view-only and Editor/Owner able to create — matching the ROM role matrix.
  const romP = window.__ROM_WS_PERMS__;
  if (romP) {
    const p = String(permission);
    if (p.endsWith('.view')) return !!romP.viewWorkspace;
    // Interacting with tiles (calendar/checklist/polls) is its own capability.
    if (p === 'tiles.interact') return !!(romP.interactTiles || romP.editTiles || romP.post || romP.manage);
    // Every other action (posts, apps, tiles, items, calendar, checklist, …) is a write.
    return !!(romP.post || romP.editTiles || romP.manage);
  }
  if (!permissionAvailableForCompany(permission, companyId)) return false;
  const previewRole = rolePreviewForCompany(companyId);
  if (previewRole) return roleAllowsPermission(previewRole, permission);
  const variants = permissionVariants(permission);
  const profile = activeSession().profile;
  if (state.session?.auth === 'supabase') {
    const membership = membershipForProfile(companyId, profile.id);
    const trustedProfileCompany = (profile.company_ids || []).map(canonicalCompanyId).includes(canonicalCompanyId(companyId));
    if (!membership && trustedProfileCompany && ['owner', 'admin', 'developer'].includes(String(profile.role || '').toLowerCase())) return true;
    if (!membership || membership.status !== 'active') return false;
    if (['owner', 'developer'].includes(String(membership.role).toLowerCase())) return true;
    const assignedRoleIds = state.roleAssignments
      .filter((item) => item.company_id === companyId && item.profile_id === profile.id)
      .map((item) => item.role_id);
    const permissions = state.rolePermissions.filter((item) => assignedRoleIds.includes(item.role_id));
    if (permissions.some((item) => (variants.includes(item.permission_key) || item.permission_key === '*') && item.effect === 'deny')) return false;
    if (permissions.some((item) => (variants.includes(item.permission_key) || item.permission_key === '*') && item.effect === 'allow')) return true;
  }
  const role = String(membershipForProfile(companyId, profile.id)?.role || profile.role || 'member').toLowerCase();
  const permissions = ROLE_PERMISSIONS[role] || ROLE_PERMISSIONS.member;
  return permissions.includes('*') || variants.some((variant) => permissions.includes(variant));
}

function requirePermission(permission, companyId = activeCompanyId(), message = 'Your role cannot perform that action.', title = 'Access') {
  if (can(permission, companyId)) return true;
  showToast(message, 'local', title);
  return false;
}

function isReadOnlyDemo() {
  return state.session?.auth === 'demo-readonly' && CONFIG.demoReadonly;
}

function isLiveSupabaseSession() {
  return state.session?.auth === 'supabase' && !isReadOnlyDemo();
}

function requireMutableWorkspace(message = 'Demo is read-only. Create a workspace to save changes.', title = 'Read-only demo') {
  if (!isReadOnlyDemo()) return true;
  showToast(message, 'local', title);
  return false;
}

