    'pipeline-open',
    'pipeline-stage',
    'open-notification',
    'verify-email',
    'start-demo-mode',
    'open-auth-modal',
    'close-auth-modal',
    'set-auth-mode',
    'open-profile',
    'open-settings',
    'toggle-contact-select',
    'toggle-contact-select-all',
    'contacts-clear-selection',
    'contacts-email',
    'toggle-file-select',
    'files-clear-selection',
    'files-select-all',
    'files-copy',
    'files-move',
    'view-as-role',
    'exit-role-preview',
    'message-details',
    'message-search-results',
    'set-message-filter',
    'set-calendar-scope',
    'set-calendar-view',
    'calendar-prev',
    'calendar-next',
    'calendar-today',
