function blankCalendarEvent(companyId = activeCompanyId(), prefillDate = '') {
  let start;
  if (prefillDate) {
    // Clicked a calendar date: default to a 9–10am slot on that day.
    start = new Date(`${prefillDate}T09:00:00`);
    if (Number.isNaN(start.getTime())) { start = new Date(); start.setHours(start.getHours() + 1, 0, 0, 0); }
  } else {
    start = new Date();
    start.setHours(start.getHours() + 1, 0, 0, 0);
  }
  const end = new Date(start);
  end.setHours(start.getHours() + 1);
  return normalizeCalendarEvent({
    id: '',
    company_id: companyId,
    title: '',
    description: '',
    event_type: 'Company event',
    starts_at: start.toISOString(),
    ends_at: end.toISOString(),
    all_day: false,
    visibility: 'company',
    linked_type: '',
    linked_id: '',
    assigned_profile_id: activeSession().profile.member_id || activeSession().profile.id,
    created_by: activeSession().profile.id,
  });
}

