// The ROM host injects the signed-in user's real identity via window globals.
// These ALWAYS win over any locally-persisted/synced profile so a stale draft
// (e.g. an old "ROM Basic Mode" persona) can never shadow the real user.
function romIdentityOverride() {
  const o = {};
  if (window.__ROM_USER_NAME__) o.full_name = window.__ROM_USER_NAME__;
  if (window.__ROM_USER_EMAIL__) o.email = window.__ROM_USER_EMAIL__;
  return o;
}

function activeSession() {
  if (state.session) {
    if (state.session.auth === 'supabase') return state.session;
    return {
      ...state.session,
      profile: {
        ...buildLocalSession().profile,
        ...(state.session.profile || {}),
        ...(state.profileDraft || {}),
        ...romIdentityOverride(),
      },
    };
  }
  return buildLocalSession();
}

function buildSupabaseSession(session, profile) {
  const emailVerified = !!(session.user.email_confirmed_at || session.user.confirmed_at);
  return {
    auth: 'supabase',
    access_token: session.access_token,
    refresh_token: session.refresh_token,
    user: {
      id: session.user.id,
      email: session.user.email || '',
      email_confirmed_at: session.user.email_confirmed_at || session.user.confirmed_at || '',
      email_verified: emailVerified,
    },
    profile: normalizeProfile(profile || {}, {
      id: session.user.id,
      email: session.user.email || '',
      full_name: session.user.user_metadata?.full_name || session.user.email || 'ROM user',
      role: 'member',
      role_label: 'Member',
      member_id: '',
      company_ids: [],
      avatar_url: '',
      approved: false,
      email_verified: emailVerified,
    }),
  };
}

function buildLocalSession() {
  const profile = {
    id: 'basic-user',
    email: window.__ROM_USER_EMAIL__ || 'local-demo@romio.local',
    full_name: window.__ROM_USER_NAME__ || 'You',
    role: 'developer',
    role_label: 'Member',
    member_id: 'abraham',
    company_ids: ['roofing', 'drafting', 'lumen'],
    avatar_url: '',
    email_verified: true,
    ...(state.profileDraft || {}),
    ...romIdentityOverride(),
  };
  return {
    auth: 'local-basic',
    user: { id: profile.id, username: CONFIG.localUsername, email: profile.email },
    profile,
  };
}

function buildDemoSession() {
  const profile = {
    id: 'demo-readonly-user',
    email: 'demo@romio.local',
    full_name: 'Demo Visitor',
    role: 'owner',
    role_label: 'Demo',
    member_id: 'demo-visitor',
    company_ids: ['roofing'],
    avatar_url: '',
    email_verified: true,
  };
  return {
    auth: 'demo-readonly',
    user: { id: profile.id, username: 'demo', email: profile.email },
    profile,
  };
}

function normalizeProfile(input, fallback = {}) {
  const role = String(input.role || fallback.role || 'member').toLowerCase();
  const emailVerified = typeof input.email_verified === 'boolean' ? input.email_verified : fallback.email_verified === true;
  return {
    id: String(input.id || fallback.id || ''),
    email: String(input.email || fallback.email || ''),
    full_name: String(input.full_name || fallback.full_name || input.email || fallback.email || 'ROM user'),
    role,
    role_label: titleCase(role),
    member_id: String(input.member_id || fallback.member_id || ''),
    company_ids: Array.isArray(input.company_ids) ? compactUnique(input.company_ids.map(canonicalCompanyId)) : (fallback.company_ids || []),
    avatar_url: String(input.avatar_url || fallback.avatar_url || ''),
    approved: input.approved !== false,
    email_verified: emailVerified,
    supervisor_id: String(input.supervisor_id || fallback.supervisor_id || ''),
  };
}

function normalizeNotification(input) {
  const legacyBody = stripHtmlText(input.html || input.meta || '');
  const readAt = input.read_at || (input.read === true ? input.created_at || new Date().toISOString() : '');
  return {
    id: String(input.id || `notification-${crypto.randomUUID()}`),
    company_id: canonicalCompanyId(input.company_id || ''),
    recipient_profile_id: String(input.recipient_profile_id || input.profile_id || input.member_id || 'basic-user'),
    type: String(input.type || (input.task_id ? 'task.notification' : 'general')),
    title: String(input.title || input.meta || 'Notification'),
    body: String(input.body || legacyBody || ''),
    href: String(input.href || ''),
    source_type: String(input.source_type || (input.task_id ? 'task' : '')),
    source_id: String(input.source_id || input.task_id || ''),
    read_at: String(readAt || ''),
    created_at: String(input.created_at || new Date().toISOString()),
  };
}

function stripHtmlText(value) {
  return String(value || '').replace(/<[^>]*>/g, ' ').replace(/\s+/g, ' ').trim();
}

function isSessionEmailVerified(session = activeSession()) {
  if (session.auth !== 'supabase') return true;
  return session.user?.email_verified === true || !!session.user?.email_confirmed_at || session.profile?.email_verified === true;
}

function isNoticeWorkspaceHeader(title, summary) {
  return [
    'Access denied',
    'Company access denied',
    'Subscription required',
    'Workspace awaiting approval',
  ].includes(title) || String(summary || '').startsWith('This module will use');
}

function workspaceHeader(title, summary, actions = '') {
  if (!isNoticeWorkspaceHeader(title, summary)) {
    return actions ? `
      <section class="workspace-head workspace-head-actions-only">
        <div class="head-actions">${actions}</div>
      </section>
    ` : '';
  }
  const symbol = moduleSymbol();
  return `
    <section class="workspace-head">
      <div class="head-copy">
        <span class="head-symbol">${svgIcon(symbol)}</span>
        <div>
          <div class="context-line"><span>${h(companyName(activeCompanyId()))}</span><b>${h(roleForCompany(activeCompanyId()))}</b></div>
          <h1>${h(title)}</h1>
          <p>${h(summary)}</p>
        </div>
      </div>
      ${actions ? `<div class="head-actions">${actions}</div>` : ''}
    </section>
  `;
}

function metricGrid(items) {
  return `<section class="metric-grid">${items.map(([label, value]) => `<article class="metric">${svgIcon(metricSymbol(label), 'metric-symbol')}<span>${h(label)}</span><strong>${h(value)}</strong></article>`).join('')}</section>`;
}

function jobQueueRow(job) {
  return `
    <button class="queue-row" type="button" data-select-job="${h(job.id)}">
      <span><strong>${h(job.name)}</strong><small>${h(job.client_name || companyName(job.company_id))}</small></span>
      ${priorityPill(job.priority)}
      <b>${h(job.stage)}</b>
    </button>
  `;
}

function taskQueueRow(task) {
  return `
    <button class="queue-row" type="button" data-select-task="${h(task.id)}">
      <span><strong>${h(task.title)}</strong><small>${h(jobById(task.project_id)?.name || companyName(task.company_id))}</small></span>
      ${taskPriorityPill(task.priority)}
      <b>${h(statusLabel(task.status))}</b>
    </button>
  `;
}

function jobCard(job) {
  return `
    <button class="job-card priority-${h(job.priority.toLowerCase())} ${job.id === state.selectedJobId ? 'active' : ''}" type="button" draggable="true" data-drag-kind="job" data-drag-id="${h(job.id)}" data-select-job="${h(job.id)}">
      <strong>${h(job.name)}</strong>
      <span>${h(job.client_name || 'No client')}</span>
      <small>${h(companyName(job.company_id))} - ${h(job.owner_name || 'Unassigned')}</small>
      <em>${h(taskCountForJob(job.id))} tasks</em>
    </button>
  `;
}

function miniLink(path, icon, title, text) {
  return `
    <a class="mini-link" href="${appHref(path)}" data-router>
      <i class="ti ${h(icon)}"></i>
      <span><strong>${h(title)}</strong><small>${h(text)}</small></span>
    </a>
  `;
}

function contractRows(rows) {
  return `<div class="contract-rows">${rows.map(([label, value]) => `<div><span>${h(label)}</span><strong>${h(value)}</strong></div>`).join('')}</div>`;
}

function field(label, name, value = '', required = false, type = 'text', className = '', attrs = '') {
  return `<label class="${h(className)}"><span>${h(label)}</span><input name="${h(name)}" type="${h(type)}" value="${h(value)}" ${required ? 'required' : ''} ${attrs} /></label>`;
}

function renderJobTypeCombobox(label, name, value, companyId) {
  const options = contactJobTypeOptions(companyId);
  return `
    <label class="job-type-field">
      <span>${h(label)}</span>
      <div class="job-type-combobox">
        <input name="${h(name)}" type="text" value="${h(value || '')}" data-job-type-input data-job-type-options="${h(JSON.stringify(options))}" autocomplete="off" placeholder="Type or choose job type" />
        <button class="job-type-toggle" type="button" data-job-type-toggle aria-label="Show job type suggestions"><i class="ti ti-chevron-down"></i></button>
        <div class="job-type-suggestions-menu" data-job-type-menu hidden></div>
      </div>
    </label>
  `;
}

function textareaField(label, name, value = '', className = '') {
  return `<label class="${h(className)}"><span>${h(label)}</span><textarea name="${h(name)}" rows="4">${h(value)}</textarea></label>`;
}

function selectField(label, name, value, options) {
  return `
    <label><span>${h(label)}</span><select name="${h(name)}">
      ${options.map(([id, text]) => `<option value="${h(id)}" ${String(id) === String(value) ? 'selected' : ''}>${h(text)}</option>`).join('')}
    </select></label>
  `;
}

function priorityPill(priority) {
  return `<span class="priority ${h(String(priority).toLowerCase())}">${h(priority)}</span>`;
}

function taskPriorityPill(priority) {
  return `<span class="priority ${h(priority)}">${h(titleCase(priority))}</span>`;
}

function taskStatusPill(status) {
  return `<span class="status-pill ${h(status)}">${h(statusLabel(status))}</span>`;
}

function financeStatusPill(status) {
  return `<span class="finance-status ${h(slugify(status))}">${h(status)}</span>`;
}

function renderAvatar(profile, className, attrs = {}) {
  const attrText = Object.entries(attrs)
    .filter(([, value]) => value !== undefined && value !== null && value !== '')
    .map(([key, value]) => `${h(key)}="${h(String(value))}"`)
    .join(' ');
  if (profile.avatar_url) return `<span class="${h(`${className} has-image`)}" ${attrText}><img src="${h(profile.avatar_url)}" alt="" /></span>`;
  const initials = String(profile.full_name || profile.email || 'QB').trim().split(/\s+/).map((part) => part[0]).join('').slice(0, 2).toUpperCase() || 'QB';
  return `<span class="${h(className)}" ${attrText}>${h(initials)}</span>`;
}

// The current workspace's icon/image, shown in the topbar (in place of the user's
// avatar). Falls back to a coloured glyph, then to the ROMIO mark. Fed by the ROM
// host bridge (window.__ROM_WS_IMAGE__ / __ROM_WS_ICON__ / __ROM_WS_COLOR__).
function renderWorkspaceBadge() {
  const img = window.__ROM_WS_IMAGE__ || '';
  const color = window.__ROM_WS_COLOR__ || '#e0552d';
  const wico = window.__ROM_WS_ICON__ || 'layout-grid-add';
  const name = window.__ROM_WS_NAME__ || 'Workspace';
  if (img) return `<span class="avatar wb-ws-badge has-image" title="${h(name)}"><img src="${h(img)}" alt="" /></span>`;
  return `<span class="avatar wb-ws-badge" title="${h(name)}" style="background:${h(color)};color:#fff"><i class="ti ti-${h(wico)}"></i></span>`;
}

function calendarAssigneeOptions(companyId = activeCompanyId()) {
  const rows = companyAccessUsers(companyId)
    .filter((user) => user.status === 'active')
    .map((user) => [user.profile_id || user.member_id, user.name || user.email || user.member_id]);
  return [['', 'Unassigned']].concat(rows);
}

function dateTimeLocalValue(value) {
  const date = new Date(value || Date.now());
  if (Number.isNaN(date.getTime())) return '';
  const y = date.getFullYear();
  const m = String(date.getMonth() + 1).padStart(2, '0');
  const d = String(date.getDate()).padStart(2, '0');
  const hh = String(date.getHours()).padStart(2, '0');
  const mm = String(date.getMinutes()).padStart(2, '0');
  return `${y}-${m}-${d}T${hh}:${mm}`;
}

function localDateTimeToIso(value) {
  const date = new Date(value || Date.now());
  if (Number.isNaN(date.getTime())) return new Date().toISOString();
  return date.toISOString();
}

function emptyState(text) {
  return `<div class="empty-state">${svgIcon('q-empty', 'empty-symbol')}<span>${h(text)}</span></div>`;
}

function randomPortalToken(bytes = 24) {
  const values = new Uint8Array(bytes);
  crypto.getRandomValues(values);
  return btoa(String.fromCharCode(...values)).replace(/\+/g, '-').replace(/\//g, '_').replace(/=+$/, '');
}

async function digestHex(value) {
  const data = new TextEncoder().encode(String(value || ''));
  const hash = await crypto.subtle.digest('SHA-256', data);
  return [...new Uint8Array(hash)].map((byte) => byte.toString(16).padStart(2, '0')).join('');
}

async function pbkdf2Hex(password, salt) {
  const key = await crypto.subtle.importKey('raw', new TextEncoder().encode(String(password || '')), 'PBKDF2', false, ['deriveBits']);
  const bits = await crypto.subtle.deriveBits({ name: 'PBKDF2', salt: new TextEncoder().encode(String(salt || '')), iterations: 120000, hash: 'SHA-256' }, key, 256);
  return [...new Uint8Array(bits)].map((byte) => byte.toString(16).padStart(2, '0')).join('');
}

function clientPortalPayload(portal) {
  return {
    id: portal.id,
    company_id: portal.company_id,
    job_id: portal.job_id || null,
    title: portal.title,
    client_name: portal.client_name || null,
    client_email: portal.client_email || null,
    token_hash: portal.token_hash,
    password_hash: portal.password_hash || null,
    password_salt: portal.password_salt || null,
    status: portal.status,
    created_by: portal.created_by || activeSession().profile.id,
  };
}

function clientPortalDocumentPayload(doc) {
  return {
    id: doc.id,
    company_id: doc.company_id,
    portal_id: doc.portal_id,
    version_group_id: doc.version_group_id || doc.id,
    version_number: doc.version_number || 1,
    is_current: doc.is_current !== false,
    review_status: doc.review_status || 'pending',
    scale: Number(doc.scale) > 0 ? Number(doc.scale) : null,
    scale_unit: ['ft', 'in', 'cm'].includes(doc.scale_unit) ? doc.scale_unit : null,
    bucket_id: doc.bucket_id,
    object_path: doc.object_path,
    file_name: doc.file_name,
    mime_type: doc.mime_type,
    size_bytes: doc.size_bytes,
    page_count: doc.page_count,
    uploaded_by: doc.uploaded_by || activeSession().profile.id,
  };
}

function clientPortalAnnotationPayload(annotation) {
  return emptyToNull(supabaseRow({
    ...normalizeClientPortalAnnotation(annotation),
    updated_at: annotation.updated_at || new Date().toISOString(),
  }, CLIENT_PORTAL_ANNOTATION_COLS), ['document_id', 'guest_name', 'author_profile_id']);
}

function upsertClientPortal(portal) {
  state.clientPortals = [portal].concat(state.clientPortals.filter((item) => item.id !== portal.id));
  persistAll();
}

function upsertClientPortalDocument(doc) {
  state.clientPortalDocuments = [doc].concat(state.clientPortalDocuments.filter((item) => item.id !== doc.id));
  persistAll();
}

function upsertClientPortalAnnotationLocal(annotation) {
  const normalized = normalizeClientPortalAnnotation(annotation);
  state.clientPortalAnnotations = [normalized].concat(state.clientPortalAnnotations.filter((item) => item.id !== normalized.id));
  if (state.clientPortalPublic?.local && state.clientPortalPublic.portal?.id === normalized.portal_id) {
    state.clientPortalPublic.annotations = [normalized].concat((state.clientPortalPublic.annotations || []).filter((item) => item.id !== normalized.id));
    writeJson(CLIENT_PORTAL_SESSION_KEY, state.clientPortalPublic);
  }
  persistClientPortalCaches();
}

async function persistClientPortalAnnotation(annotation) {
  const normalized = normalizeClientPortalAnnotation({ ...annotation, updated_at: new Date().toISOString() });
  upsertClientPortalAnnotationLocal(normalized);
  const client = createSupabaseClient();
  if (!isLiveSupabaseSession() || !client) return;
  const { data, error } = await client.from('client_portal_annotations').upsert(clientPortalAnnotationPayload(normalized), { onConflict: 'id' }).select().single();
  if (error) {
    notifySyncFailure(error, 'Markup save');
    return;
  }
  if (data) upsertClientPortalAnnotationLocal(normalizeClientPortalAnnotation(data));
}

async function deleteClientPortalAnnotationRow(id) {
  state.clientPortalAnnotations = state.clientPortalAnnotations.filter((item) => item.id !== id);
  if (state.clientPortalPublic?.local) {
    state.clientPortalPublic.annotations = (state.clientPortalPublic.annotations || []).filter((item) => item.id !== id);
    writeJson(CLIENT_PORTAL_SESSION_KEY, state.clientPortalPublic);
  }
  persistClientPortalCaches();
  const client = createSupabaseClient();
  if (!isLiveSupabaseSession() || !client) return;
  const { error } = await client.from('client_portal_annotations').delete().eq('id', id);
  if (error) notifySyncFailure(error, 'Markup delete');
}

async function persistClientPortalDocument(doc) {
  const normalized = normalizeClientPortalDocument({ ...doc, updated_at: new Date().toISOString() });
  upsertClientPortalDocument(normalized);
  const client = createSupabaseClient();
  if (!isLiveSupabaseSession() || !client) return;
  const payload = emptyToNull(supabaseRow(clientPortalDocumentPayload(normalized), CLIENT_PORTAL_DOCUMENT_COLS), ['scale', 'scale_unit', 'page_count', 'uploaded_by']);
  const { data, error } = await client.from('client_portal_documents').update(payload).eq('id', normalized.id).select().single();
  if (error) {
    notifySyncFailure(error, 'Document save');
    return;
  }
  if (data) upsertClientPortalDocument(normalizeClientPortalDocument(data));
}

function copyParams(params, keys) {
  const next = {};
  keys.forEach((key) => {
    const value = params.get(key);
    if (value) next[key] = value;
  });
  return next;
}

