function blankForm(companyId = activeCompanyId()) {
  return normalizeForm({
    id: `form-${crypto.randomUUID()}`,
    company_id: companyId,
    title: 'Untitled form',
    description: '',
    type: 'Internal',
    status: 'Draft',
    audience: 'Internal',
    linked_job_id: state.route?.jobId || '',
    theme_color: companyColor(companyId),
    background: 'clean',
    submit_label: 'Submit',
    collect_email: true,
    require_approval: false,
    questions: [blankQuestion('short', 'First question')],
  });
}

function blankQuestion(type = 'short', label = 'Untitled question', options = []) {
  return normalizeQuestion({
    id: `q-${crypto.randomUUID()}`,
    type,
    label,
    required: false,
    options,
  });
}

async function persistFormRecord(form) {
  if (!isLiveSupabaseSession()) return form;
  const client = createSupabaseClient();
  if (!client) throw new Error('Supabase is unavailable.');
  if (!can('forms.manage', form.company_id)) throw new Error('Your role cannot manage forms.');
  const result = await client.from('forms').upsert(formPayload(form), { onConflict: 'id' }).select().single();
  if (result.error) throw new Error(result.error.message || 'Form save failed.');
  return normalizeForm(result.data);
}

async function deleteFormRecord(form) {
  if (!isLiveSupabaseSession()) return true;
  const client = createSupabaseClient();
  if (!client) throw new Error('Supabase is unavailable.');
  if (!can('forms.manage', form.company_id)) throw new Error('Your role cannot delete forms.');
  const result = await client.from('forms').delete().eq('id', form.id).eq('company_id', form.company_id);
  if (result.error) throw new Error(result.error.message || 'Form delete failed.');
  return true;
}

async function persistFormResponseRecord(response) {
  if (!isLiveSupabaseSession()) return response;
  const client = createSupabaseClient();
  if (!client) throw new Error('Supabase is unavailable.');
  const form = formById(response.form_id);
  if (!form || !can('forms.view', response.company_id)) throw new Error('Your role cannot submit this form.');
  const result = await client.from('form_responses').insert(formResponsePayload(response)).select().single();
  if (result.error) throw new Error(result.error.message || 'Form response save failed.');
  return normalizeFormResponse(result.data);
}

async function deleteFormResponseRecord(response) {
  if (!isLiveSupabaseSession()) return true;
  const client = createSupabaseClient();
  if (!client) throw new Error('Supabase is unavailable.');
  if (!can('forms.manage', response.company_id)) throw new Error('Your role cannot delete form responses.');
  const result = await client.from('form_responses').delete().eq('id', response.id).eq('company_id', response.company_id);
  if (result.error) throw new Error(result.error.message || 'Form response delete failed.');
  return true;
}

async function createForm(companyId, overrides = {}) {
  if (!requirePermission('forms.manage', companyId, 'Your role cannot create forms.', 'Forms')) return null;
  const base = blankForm(companyId);
  const form = normalizeForm({
    ...base,
    ...overrides,
    id: overrides.id || `form-${crypto.randomUUID()}`,
    company_id: companyId,
    questions: (overrides.questions || base.questions).map((question) => normalizeQuestion(question)),
    created_at: overrides.created_at || new Date().toISOString(),
    updated_at: new Date().toISOString(),
  });
  state.forms.unshift(form);
  state.selectedFormId = form.id;
  state.selectedQuestionId = form.questions[0]?.id || '';
  state.formsTab = 'builder';
  state.formEditorTab = 'questions';
  state.modal = '';
  state.formStartTemplateId = '';
  state.formStartTab = 'blank';
  saveFormsState('New form created');
  render();
  return form;
}

async function createFormFromModal(formEl) {
  if (!requirePermission('forms.manage', activeCompanyId(), 'Your role cannot create forms.', 'Forms')) return;
  const data = Object.fromEntries(new FormData(formEl).entries());
  const template = data.template_id ? formTemplates().find((item) => item.id === data.template_id) : null;
  const validation = validateNewFormModal(formEl, template);
  if (!validation.ok) return;
  const title = validation.title;
  const description = String(data.description || template?.description || '').trim();
  const questions = template
    ? template.questions.map((question) => ({ ...clone(question), id: `q-${crypto.randomUUID()}` }))
    : [blankQuestion('short', 'First question')];
  await createForm(activeCompanyId(), {
    title,
    description,
    type: FORM_TYPES.includes(data.type) ? data.type : template?.type || 'Internal',
    audience: String(data.audience || 'Internal').trim() || 'Internal',
    creator_id: activeSession().profile.member_id || activeSession().profile.id || 'basic-user',
    linked_job_id: String(data.linked_job_id || ''),
    theme_color: companyColor(activeCompanyId()),
    background: 'clean',
    submit_label: String(data.submit_label || 'Submit').trim() || 'Submit',
    collect_email: data.collect_email === 'on',
    require_approval: data.require_approval === 'on',
    questions,
  });
}

function validateNewFormModal(formEl, template) {
  const data = Object.fromEntries(new FormData(formEl).entries());
  const titleInput = formEl.querySelector('[name="title"]');
  const title = String(data.title || template?.title || '').trim();
  if (!title) {
    titleInput?.setCustomValidity('Form title is required.');
    titleInput?.reportValidity();
    showToast('Form title is required.', 'local', 'Forms');
    return { ok: false };
  }
  titleInput?.setCustomValidity('');
  return { ok: true, data, title };
}

function selectForm(id, shouldRender = true) {
  const form = formById(id);
  if (!form) return;
  state.selectedFormId = form.id;
  state.selectedQuestionId = form.questions[0]?.id || '';
  state.selectedFormResponseId = responsesForForm(form.id)[0]?.id || '';
  if (shouldRender) render();
}

function selectFormResponse(id) {
  const response = state.formResponses.find((item) => item.id === id);
  if (!response) return;
  state.selectedFormResponseId = response.id;
  state.selectedFormId = response.form_id || state.selectedFormId;
  render();
}

function shouldIgnoreCardToggle(target) {
  return Boolean(target?.closest?.('button, a, input, textarea, select, label, [data-action]:not([data-card-action])'));
}

function saveFormsState(label = 'Forms saved', options = {}) {
  const manual = Boolean(options.manual);
  const form = selectedFormMutable();
  if (form) form.updated_at = new Date().toISOString();
  writeJson(FORM_CACHE_KEY, state.forms);
  writeJson(FORM_RESPONSE_CACHE_KEY, state.formResponses);
  if (!isLiveSupabaseSession() || !form) {
    state.sync = { label: `${label} locally`, mode: 'local' };
    if (manual) showToast(`${label} locally.`, 'local', 'Forms');
    if (manual) render();
    return Promise.resolve(form);
  }
  state.sync = { label: 'Saving form to Supabase...', mode: 'loading' };
  if (manual) render();
  return persistFormRecord(form)
    .then((saved) => {
      if (saved) state.forms = [saved].concat(state.forms.filter((item) => item.id !== saved.id));
      state.sync = { label: `${label} in Supabase`, mode: 'live' };
      if (manual) showToast(`${label} in Supabase.`, 'live', 'Forms');
      render();
      return saved;
    })
    .catch((error) => {
      state.sync = { label: error.message || 'Form save failed', mode: 'local' };
      showToast(error.message || 'Form save failed.', 'local', 'Forms');
      render();
      return null;
    });
}

function setFormStatus(id, status) {
  const form = formById(id || state.selectedFormId);
  if (!form) return;
  if (!requirePermission('forms.manage', form.company_id, 'Your role cannot update forms.', 'Forms')) return;
  form.status = FORM_STATUSES.includes(status) ? status : 'Draft';
  state.selectedFormId = form.id;
  saveFormsState(form.status);
  render();
}

function duplicateForm(id) {
  const form = formById(id || state.selectedFormId);
  if (!form) return;
  if (!requirePermission('forms.manage', form.company_id, 'Your role cannot duplicate forms.', 'Forms')) return;
  const copy = normalizeForm({
    ...clone(form),
    id: `form-${crypto.randomUUID()}`,
    title: `${form.title} Copy`,
    status: 'Draft',
    questions: form.questions.map((question) => ({ ...clone(question), id: `q-${crypto.randomUUID()}` })),
    created_at: new Date().toISOString(),
    updated_at: new Date().toISOString(),
  });
  state.forms.unshift(copy);
  state.selectedFormId = copy.id;
  state.selectedQuestionId = copy.questions[0]?.id || '';
  saveFormsState('Form duplicated');
  render();
}

async function deleteForm(id) {
  const formId = id || state.selectedFormId;
  if (!formId) return;
  const form = formById(formId);
  if (form && !requirePermission('forms.manage', form.company_id, 'Your role cannot delete forms.', 'Forms')) return;
  await recycleDeleteRecord({ type: 'form', id: formId });
}

async function deleteFormResponse(responseId) {
  const response = responseById(responseId);
  if (!response) return;
  if (!requirePermission('forms.manage', response.company_id, 'Your role cannot delete form responses.', 'Forms')) return;
  await recycleDeleteRecord({ type: 'form_response', id: response.id });
}

async function copyFormLink(id) {
  return copyFormPublicLink(id);
}

function formPublicLink(form) {
  const formId = typeof form === 'string' ? form : form?.id;
  return `${window.location.origin}${appHref(`/form/${encodeURIComponent(formId)}`)}`;
}

async function copyFormPublicLink(id) {
  const formId = id || state.selectedFormId;
  const url = formPublicLink(formId);
  try {
    await navigator.clipboard.writeText(url);
    state.sync = { label: 'Public form link copied', mode: 'live' };
  } catch {
    state.sync = { label: 'Copy failed', mode: 'local' };
  }
  render();
}

function exportForms(companyId) {
  const payload = JSON.stringify({ company_id: companyId, forms: companyForms(companyId), responses: companyFormResponses(companyId) }, null, 2);
  downloadText(`${companyId}-forms-export.json`, payload, 'application/json');
}

function updateFormField(target) {
  const form = selectedFormMutable();
  if (!form) return;
  if (!can('forms.manage', form.company_id)) return;
  const key = target.dataset.formField;
  if (!key) return;
  form[key] = target.type === 'checkbox' ? target.checked : target.value;
  form.updated_at = new Date().toISOString();
  writeJson(FORM_CACHE_KEY, state.forms);
}

function updateQuestionField(target) {
  const form = selectedFormMutable();
  const card = target.closest('[data-question-id]');
  const question = form?.questions.find((item) => item.id === card?.dataset.questionId);
  if (!form || !question) return;
  if (!can('forms.manage', form.company_id)) return;
  state.selectedQuestionId = question.id;
  if (target.matches('[data-question-option]')) {
    const index = Number(target.dataset.questionOption);
    question.options[index] = target.value;
  } else {
    const key = target.dataset.questionField;
    if (key === 'required') question.required = target.checked;
    else if (key === 'type') {
      question.type = target.value;
      if (questionHasOptions(question) && !question.options.length) question.options = ['Option 1', 'Option 2'];
      if (!questionHasOptions(question)) question.options = [];
      saveFormsState('Question updated');
      render();
      return;
    } else if (key) {
      question[key] = target.value;
    }
  }
  form.updated_at = new Date().toISOString();
  writeJson(FORM_CACHE_KEY, state.forms);
}

function addQuestion(type = 'multiple') {
  const form = selectedFormMutable();
  if (!form) return;
  if (!requirePermission('forms.manage', form.company_id, 'Your role cannot edit forms.', 'Forms')) return;
  const question = blankQuestion(type, QUESTION_TYPES.find(([id]) => id === type)?.[1] || 'New question');
  form.questions.push(question);
  state.selectedQuestionId = question.id;
  saveFormsState('Question added');
  render();
}

function duplicateQuestion(id) {
  const form = selectedFormMutable();
  const question = form?.questions.find((item) => item.id === id);
  if (!form || !question) return;
  if (!requirePermission('forms.manage', form.company_id, 'Your role cannot edit forms.', 'Forms')) return;
  const index = form.questions.findIndex((item) => item.id === id);
  const copy = normalizeQuestion({ ...clone(question), id: `q-${crypto.randomUUID()}`, label: `${question.label} Copy` });
  form.questions.splice(index + 1, 0, copy);
  state.selectedQuestionId = copy.id;
  saveFormsState('Question duplicated');
  render();
}

function deleteQuestion(id) {
  const form = selectedFormMutable();
  if (!form) return;
  if (!requirePermission('forms.manage', form.company_id, 'Your role cannot edit forms.', 'Forms')) return;
  form.questions = form.questions.filter((question) => question.id !== id);
  state.selectedQuestionId = form.questions[0]?.id || '';
  saveFormsState('Question deleted');
  render();
}

function moveQuestion(id, direction) {
  const form = selectedFormMutable();
  if (!form || !direction) return;
  if (!requirePermission('forms.manage', form.company_id, 'Your role cannot edit forms.', 'Forms')) return;
  const index = form.questions.findIndex((question) => question.id === id);
  const next = index + direction;
  if (index < 0 || next < 0 || next >= form.questions.length) return;
  const [question] = form.questions.splice(index, 1);
  form.questions.splice(next, 0, question);
  state.selectedQuestionId = id;
  saveFormsState('Question moved');
  render();
}

function addQuestionOption(id) {
  const form = selectedFormMutable();
  const question = form?.questions.find((item) => item.id === id);
  if (!question) return;
  if (!requirePermission('forms.manage', form.company_id, 'Your role cannot edit forms.', 'Forms')) return;
  question.options = question.options || [];
  question.options.push(`Option ${question.options.length + 1}`);
  saveFormsState('Option added');
  render();
}

function removeQuestionOption(id, index) {
  const form = selectedFormMutable();
  const question = form?.questions.find((item) => item.id === id);
  if (!question || index < 0) return;
  if (!requirePermission('forms.manage', form.company_id, 'Your role cannot edit forms.', 'Forms')) return;
  question.options.splice(index, 1);
  if (!question.options.length) question.options.push('Option 1');
  saveFormsState('Option removed');
  render();
}

async function saveFormResponse(formEl) {
  const form = formById(formEl.dataset.formId);
  if (!form) return;
  const data = new FormData(formEl);
  const answers = await collectFormAnswers(form, data);
  const response = normalizeFormResponse({
    company_id: form.company_id,
    form_id: form.id,
    submitter_email: String(data.get('submitter_email') || ''),
    submitted_by: String(data.get('submitter_email') || activeSession().profile.full_name || 'Preview submitter'),
    answers,
    created_at: new Date().toISOString(),
  });
  const savedResponse = await persistFormResponseRecord(response);
  state.formResponses = [savedResponse].concat(state.formResponses.filter((item) => item.id !== savedResponse.id));
  state.formsTab = 'responses';
  state.modal = '';
  writeJson(FORM_RESPONSE_CACHE_KEY, state.formResponses);
  state.sync = { label: isLiveSupabaseSession() ? 'Response saved in Supabase' : 'Preview response saved locally', mode: isLiveSupabaseSession() ? 'live' : 'local' };
  notifyLocalEvent(
    form.require_approval ? 'approval.form' : 'form.response',
    form.require_approval ? 'Form approval ready' : 'Form response saved',
    `${actorName()} saved a response for ${form.title}.`,
    companyPath('forms', { form_id: form.id, tab: 'responses' }, form.company_id),
    'form_response',
    form.id,
    form.company_id,
  );
  render();
}

async function uploadPublicFormFile(form, question, file) {
  const check = await validateUpload(file, 'formfile');
  if (!check.ok) throw new Error(check.reason);
  const response = await fetch('/api/public-form-file-upload', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({
      form_id: form.id,
      question_id: question.id,
      file_name: file.name,
      file_type: contentTypeFor(file),
      file_size: file.size,
    }),
  });
  const payload = await response.json().catch(() => ({}));
  if (!response.ok) throw new Error(payload.error || 'Could not prepare file upload.');
  const client = createSupabaseClient();
  if (!client) throw new Error('File upload is not available in this session.');
  const upload = await client
    .storage
    .from(payload.bucket_id)
    .uploadToSignedUrl(payload.object_path, payload.token, file, {
      contentType: contentTypeFor(file),
    });
  if (upload.error) throw upload.error;
  return formFileAnswerMeta(file, '', {
    bucket_id: payload.bucket_id,
    object_path: payload.object_path,
    uploaded_at: new Date().toISOString(),
  });
}

async function collectFormAnswers(form, data) {
  const options = arguments.length > 2 && arguments[2] && typeof arguments[2] === 'object' ? arguments[2] : {};
  const answers = {};
  for (const question of form.questions) {
    const key = `answer:${question.id}`;
    const values = data.getAll(key).filter((value) => value instanceof File ? value.name : String(value || '').trim());
    const normalized = [];
    for (const value of values) {
      if (value instanceof File) {
        normalized.push(options.publicUpload ? await uploadPublicFormFile(form, question, value) : formFileAnswerMeta(value, value.size <= 2 * 1024 * 1024 ? await fileToDataUrl(value) : ''));
      }
      else normalized.push(String(value || '').trim());
    }
    answers[question.id] = normalized.length > 1 ? normalized : (normalized[0] || '');
  }
  return answers;
}

function responseById(id) {
  return state.formResponses.find((response) => response.id === id) || null;
}

function responseAnswerText(response, patterns) {
  const form = formById(response.form_id);
  const matchers = patterns.map((pattern) => pattern instanceof RegExp ? pattern : new RegExp(pattern, 'i'));
  for (const [questionId, value] of Object.entries(response.answers || {})) {
    const question = form?.questions.find((item) => item.id === questionId);
    const label = question?.label || questionId;
    if (!matchers.some((pattern) => pattern.test(label))) continue;
    const flattened = Array.isArray(value) ? value : [value];
    const text = flattened
      .filter((item) => !(item && typeof item === 'object' && item.kind === 'file'))
      .map((item) => String(item || '').trim())
      .filter(Boolean)
      .join(', ');
    if (text) return text;
  }
  return '';
}

function responseSummary(response) {
  const form = formById(response.form_id);
  const firstAnswer = Object.values(response.answers || {}).flat?.().find((value) => String(value || '').trim()) || '';
  return {
    form,
    name: responseAnswerText(response, [/name|client|customer|contact/i]) || response.submitted_by || response.submitter_email || 'Form respondent',
    email: response.submitter_email || responseAnswerText(response, [/email/i]),
    phone: responseAnswerText(response, [/phone|mobile|cell/i]),
    location: responseAnswerText(response, [/address|location|site/i]),
    jobType: responseAnswerText(response, [/job type|service|request|work/i]) || form?.type || 'Form request',
    title: responseAnswerText(response, [/title|request|subject|project/i]) || form?.title || 'Form response',
    notes: responseAnswerText(response, [/detail|note|scope|description|message/i]) || String(firstAnswer || ''),
  };
}

async function createContactFromFormResponse(responseId) {
  const response = responseById(responseId);
  if (!response) return showToast('Response not found.', 'local', 'Forms');
  if (!requirePermission('crm.view', response.company_id, 'Your role cannot create CRM records.', 'Forms')) return;
  const summary = responseSummary(response);
  const contact = normalizeContact({
    id: `contact-${crypto.randomUUID()}`,
    company_id: response.company_id,
    name: summary.name,
    email: summary.email,
    phone: summary.phone,
    location: summary.location,
    job_type: summary.jobType,
    stage: contactStageNames()[0],
    owner_name: actorName(),
    source: 'Form',
    notes: `Created from ${summary.form?.title || 'form'} response.\n${summary.notes}`.trim(),
    value: 0,
  });
  if (!await persistContact(contact)) return false;
  await logActivity({ type: 'form', subject: `Form response converted to contact`, body: summary.notes, related_type: 'contact', related_id: contact.id, contact_id: contact.id, company_id: response.company_id });
  navigate(companyPath('contacts', { contact_id: contact.id }, response.company_id));
}

async function createJobFromFormResponse(responseId) {
  const response = responseById(responseId);
  if (!response) return showToast('Response not found.', 'local', 'Forms');
  if (!requirePermission('jobs.manage', response.company_id, 'Your role cannot create jobs.', 'Forms')) return;
  const summary = responseSummary(response);
  const job = normalizeJob({
    ...blankJob(response.company_id),
    id: crypto.randomUUID(),
    company_id: response.company_id,
    name: summary.title,
    client_name: summary.name,
    client_email: summary.email,
    client_phone: summary.phone,
    site_address: summary.location,
    job_type: summary.jobType,
    scope: summary.notes,
    stage: jobStageNames()[0],
    priority: 'Medium',
    owner_name: actorName(),
    updated_at: new Date().toISOString(),
  });
  if (!await persistJob(job, 'Job created from form')) return false;
  await logActivity({ type: 'form', subject: `Form response converted to job`, body: summary.notes, related_type: 'job', related_id: job.id, job_id: job.id, company_id: response.company_id });
  navigate(companyPath('jobs', { tab: 'profile', job_id: job.id }, response.company_id));
}

async function createTaskFromFormResponse(responseId) {
  const response = responseById(responseId);
  if (!response) return showToast('Response not found.', 'local', 'Forms');
  if (!requirePermission('tasks.manage', response.company_id, 'Your role cannot create tasks.', 'Forms')) return;
  const creatorId = activeTaskCreatorId(response.company_id);
  if (!creatorId) {
    showToast('Your signed-in profile is missing a task creator ID.', 'error', 'Tasks');
    return false;
  }
  const summary = responseSummary(response);
  const task = normalizeTask({
    ...blankTask(response.company_id),
    id: `task-${crypto.randomUUID()}`,
    company_id: response.company_id,
    title: `Review form: ${summary.form?.title || summary.title}`,
    description: `${summary.name}${summary.email ? ` / ${summary.email}` : ''}\n${summary.notes}`.trim(),
    due: isoDate(1),
    priority: 'medium',
    type: 'admin',
    status: 'todo',
    creator_id: creatorId,
    assignee_id: creatorId,
  });
  const client = createSupabaseClient();
  let savedTask = task;
  if (client && isLiveSupabaseSession()) {
    const result = await safeSupabaseQuery(client.from('tasks').insert(taskPayload(task)).select().single());
    if (result.error) {
      notifySyncFailure(result.error, 'Task create');
      return false;
    }
    if (!result.data) {
      notifySyncFailure(new Error('Task insert returned no record.'), 'Task create');
      return false;
    }
    savedTask = normalizeTask(result.data);
  }
  upsertTask(savedTask);
  showToast('Task created from form response.', 'saved', 'Forms');
  navigate(companyPath('tasks', { task_id: savedTask.id }, response.company_id));
  return savedTask;
}

function downloadText(filename, text, type = 'text/plain') {
  const blob = new Blob([text], { type });
  const url = URL.createObjectURL(blob);
  const link = document.createElement('a');
  link.href = url;
  link.download = filename;
  link.click();
  URL.revokeObjectURL(url);
}

function clone(value) {
  return JSON.parse(JSON.stringify(value));
}

function compactUnique(values) {
  return Array.from(new Set(values.map((value) => String(value || '').trim()).filter(Boolean)));
}

function statusLabel(status) {
  return {
    todo: 'To do',
    pending: 'Pending',
    hold: 'On hold',
    review: 'Review',
    done: 'Done',
  }[status] || titleCase(status);
}

function taskTypeLabel(type) {
  return {
    lead: 'Lead',
    bid: 'Bid',
    admin: 'Admin',
    invoicing: 'Invoicing',
    ar: 'AR',
    meeting: 'Meeting',
    web_dev: 'Web dev',
  }[type] || titleCase(type);
}

function folderLabel(id) {
  return DRIVE_FOLDERS.find(([folderId]) => folderId === id)?.[1]
    || state.driveFolders.find((folder) => folder.id === id)?.name
    || titleCase(id || 'Shared');
}

function driveFolderOptions(companyId = activeCompanyId()) {
  return DRIVE_FOLDERS.map(([id, label]) => [id, label])
    .concat(companyDriveFolders(companyId).map((folder) => [folder.id, folder.name]));
}

function folderIdFromCategory(category) {
  const lower = String(category || '').toLowerCase();
  if (lower.includes('photo')) return 'photos';
  if (lower.includes('permit')) return 'permits';
  if (lower.includes('contract')) return 'contracts';
  if (lower.includes('form')) return 'forms';
  if (lower.includes('archive')) return 'archive';
  return 'shared';
}

function folderIconAsset(folder, label = 'Folder') {
  return iconAsset('default_folder.svg', label || 'Folder');
}

function fileIconAsset(file, label = 'File') {
  return iconAsset(fileIconAssetName(file), label || fileTypeLabel(file));
}

function iconAsset(asset, label) {
  return `<img class="asset-icon" src="${h(FILE_ICON_ASSET_BASE + asset)}" alt="${h(label)}" loading="lazy" draggable="false" referrerpolicy="no-referrer" />`;
}

function fileIconAssetName(file) {
  const ext = fileExtension(file);
  const exact = {
    pdf: 'file_type_pdf.svg',
    doc: 'file_type_word.svg',
    docx: 'file_type_word.svg',
    odt: 'file_type_word.svg',
    rtf: 'file_type_word.svg',
    xls: 'file_type_excel.svg',
    xlsx: 'file_type_excel.svg',
    xlsm: 'file_type_excel.svg',
    ods: 'file_type_excel.svg',
    csv: 'file_type_excel.svg',
    ppt: 'file_type_powerpoint.svg',
    pptx: 'file_type_powerpoint.svg',
    pps: 'file_type_powerpoint.svg',
    odp: 'file_type_powerpoint.svg',
    zip: 'file_type_zip.svg',
    rar: 'file_type_zip.svg',
    '7z': 'file_type_zip.svg',
    tar: 'file_type_zip.svg',
    gz: 'file_type_zip.svg',
    tgz: 'file_type_zip.svg',
    txt: 'file_type_text.svg',
    log: 'file_type_text.svg',
    md: 'file_type_markdown.svg',
    json: 'file_type_json.svg',
    html: 'file_type_html.svg',
    htm: 'file_type_html.svg',
    css: 'file_type_css.svg',
    scss: 'file_type_css.svg',
    js: 'file_type_js.svg',
    jsx: 'file_type_js.svg',
    ts: 'file_type_js.svg',
    tsx: 'file_type_js.svg',
    xml: 'file_type_xml.svg',
    yml: 'file_type_yaml.svg',
    yaml: 'file_type_yaml.svg',
    svg: 'file_type_svg.svg',
    ai: 'file_type_ai.svg',
    psd: 'file_type_photoshop.svg',
  };
  if (exact[ext]) return exact[ext];
  const kind = fileTypeKind(file);
  if (kind === 'image') return 'file_type_image.svg';
  if (kind === 'video') return 'file_type_video.svg';
  if (kind === 'audio') return 'file_type_audio.svg';
  if (kind === 'text') return 'file_type_text.svg';
  if (kind === 'code') return 'file_type_js.svg';
  if (kind === 'archive') return 'file_type_zip.svg';
  return 'default_file.svg';
}

function titleCase(value) {
  return String(value || '')
    .replace(/[_-]+/g, ' ')
    .replace(/\b\w/g, (char) => char.toUpperCase());
}

function isoDate(offsetDays = 0) {
  const date = new Date(Date.now() + offsetDays * 86400000);
  return date.toISOString().slice(0, 10);
}

// Current local date (or date + time) as an <input>-ready string, for auto-stamp
// Date fields. `YYYY-MM-DD` or `YYYY-MM-DDTHH:mm`.
function nowStampValue(withTime) {
  const d = new Date();
  const p = (n) => String(n).padStart(2, '0');
  const date = `${d.getFullYear()}-${p(d.getMonth() + 1)}-${p(d.getDate())}`;
  return withTime ? `${date}T${p(d.getHours())}:${p(d.getMinutes())}` : date;
}

function formatDate(value) {
  if (!value) return 'No date';
  const date = new Date(value);
  if (Number.isNaN(date.getTime())) return String(value);
  return new Intl.DateTimeFormat('en-US', { month: 'short', day: 'numeric' }).format(date);
}

function formatDateTime(value) {
  if (!value) return 'No time';
  const date = new Date(value);
  if (Number.isNaN(date.getTime())) return String(value);
  return new Intl.DateTimeFormat('en-US', { month: 'short', day: 'numeric', hour: 'numeric', minute: '2-digit' }).format(date);
}

function formatTime(value) {
  const clean = String(value || '').trim();
  const match = clean.match(/^(\d{1,2}):(\d{2})/);
  if (!match) return clean;
  const date = new Date();
  date.setHours(Number(match[1]), Number(match[2]), 0, 0);
  return new Intl.DateTimeFormat('en-US', { hour: 'numeric', minute: '2-digit' }).format(date);
}

function timeAgo(value) {
  const date = new Date(value);
  if (!value || Number.isNaN(date.getTime())) return 'just now';
  const seconds = Math.max(0, Math.floor((Date.now() - date.getTime()) / 1000));
  if (seconds < 45) return 'just now';
  const minutes = Math.floor(seconds / 60);
  if (minutes < 60) return `${minutes}m ago`;
  const hours = Math.floor(minutes / 60);
  if (hours < 24) return `${hours}h ago`;
  const days = Math.floor(hours / 24);
  if (days < 7) return `${days}d ago`;
  return formatDate(value);
}

function formatDuration(value) {
  const totalSeconds = Math.max(0, Math.floor(number(value) / 1000));
  const hours = Math.floor(totalSeconds / 3600);
  const minutes = Math.floor((totalSeconds % 3600) / 60);
  if (hours) return `${hours}h ${String(minutes).padStart(2, '0')}m`;
  return `${minutes}m`;
}

function formatBytes(value) {
  const bytes = number(value);
  if (!bytes) return '0 B';
  const units = ['B', 'KB', 'MB', 'GB'];
  const index = Math.min(Math.floor(Math.log(bytes) / Math.log(1024)), units.length - 1);
  return `${(bytes / 1024 ** index).toFixed(index ? 1 : 0)} ${units[index]}`;
}

function dateDesc(field) {
  return (a, b) => Date.parse(b[field] || b.updated_at || b.created_at || 0) - Date.parse(a[field] || a.updated_at || a.created_at || 0);
}

function daysPastDue(value) {
  if (!value) return 0;
  const due = new Date(`${String(value).slice(0, 10)}T00:00:00`);
  if (Number.isNaN(due.getTime())) return 0;
  return Math.floor((startOfToday().getTime() - due.getTime()) / 86400000);
}

function daysUntil(value) {
  if (!value) return 999;
  const target = new Date(`${String(value).slice(0, 10)}T00:00:00`);
  if (Number.isNaN(target.getTime())) return 999;
  return Math.floor((target.getTime() - startOfToday().getTime()) / 86400000);
}

function nextInvoiceNumber(companyId = activeCompanyId()) {
  const prefix = (companyLabel(companyById(companyId) || { short_name: companyId }) || companyId || 'QH')
    .replace(/[^a-z]/gi, '')
    .slice(0, 2)
    .toUpperCase() || 'QH';
  const count = companyFinanceInvoices(companyId).length + 1;
  return `${prefix}-${String(1000 + count)}`;
}

function startOfToday() {
  const date = new Date();
  date.setHours(0, 0, 0, 0);
  return date;
}

function percent(value, total) {
  return `${percentNumber(value, total)}%`;
}

function percentNumber(value, total) {
  const denominator = number(total);
  if (!denominator) return 0;
  return Math.max(0, Math.min(100, Math.round((number(value) / denominator) * 100)));
}

function priorityRank(priority) {
  return {
    critical: 5,
    urgent: 4,
    high: 3,
    medium: 2,
    low: 1,
  }[String(priority || '').toLowerCase()] || 0;
}

function slugify(value) {
  return String(value || 'file').toLowerCase().replace(/[^a-z0-9.]+/g, '-').replace(/^-+|-+$/g, '') || 'file';
}

function sum(items, field) {
  return items.reduce((total, item) => total + number(item[field]), 0);
}

function number(value) {
  const parsed = Number(value);
  return Number.isFinite(parsed) ? parsed : 0;
}

function isUuid(value) {
  return /^[0-9a-f]{8}-[0-9a-f]{4}-[1-5][0-9a-f]{3}-[89ab][0-9a-f]{3}-[0-9a-f]{12}$/i.test(String(value || ''));
}

function isOpaqueUserId(value) {
  const text = String(value || '').trim();
  return isUuid(text) || /^[0-9a-f]{8,}$/i.test(text) || /^user[_-]?[0-9a-f-]{8,}$/i.test(text);
}

function shortUserId(value) {
  const text = String(value || '').trim();
  return text ? text.slice(0, 8) : '';
}

function money(value) {
  return new Intl.NumberFormat('en-US', { style: 'currency', currency: 'USD', maximumFractionDigits: 0 }).format(number(value));
}

function readJson(key, fallback) {
  try {
    const raw = localStorage.getItem(key);
    return raw ? JSON.parse(raw) : fallback;
  } catch {
    return fallback;
  }
}

function safeJson(raw, fallback) {
  try {
    return JSON.parse(raw);
  } catch {
    return fallback;
  }
}

function readSeededList(key, fallback) {
  const value = readJson(key, fallback);
  return Array.isArray(value) && value.length ? value : fallback;
}

function writeJson(key, value) {
  if (isReadOnlyDemo() && key !== SESSION_KEY) return;
  try {
    localStorage.setItem(key, JSON.stringify(value));
  } catch {
    /* local persistence is best effort */
  }
}

function h(value) {
  return String(value ?? '')
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
    .replace(/'/g, '&#039;');
}

// Bootstrap the app once every top-level declaration is initialized.
init();
